#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryDashboard {
    pub total_boundaries: usize,
    pub continue_boundaries: usize,
    pub observe_boundaries: usize,
    pub repair_boundaries: usize,
    pub dispatch_allowed_boundaries: usize,
    pub memory_note_allowed_boundaries: usize,
    pub adaptive_state_allowed_boundaries: usize,
    pub repair_first_boundaries: usize,
    pub blocked_gates: usize,
    pub total_reasons: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_rust_validation_command_count: usize,
    pub service_execution_rust_validation_command_closes: usize,
    pub service_execution_tool_build_command_reason_count: usize,
    pub latest_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub continue_rate: f32,
    pub observe_rate: f32,
    pub repair_rate: f32,
    pub dispatch_allowed_rate: f32,
    pub memory_note_allowed_rate: f32,
    pub adaptive_state_allowed_rate: f32,
    pub repair_first_rate: f32,
}

impl AgentCollaborationSideEffectBoundaryDashboard {
    pub fn from_history(history: &AgentCollaborationSideEffectBoundaryHistory) -> Self {
        let total_boundaries = history.len();
        let continue_boundaries = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Continue)
            .count();
        let observe_boundaries = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Observe)
            .count();
        let repair_boundaries = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Repair)
            .count();
        let dispatch_allowed_boundaries = history
            .summaries()
            .iter()
            .filter(|summary| summary.dispatch_allowed)
            .count();
        let memory_note_allowed_boundaries = history
            .summaries()
            .iter()
            .filter(|summary| summary.memory_note_allowed)
            .count();
        let adaptive_state_allowed_boundaries = history
            .summaries()
            .iter()
            .filter(|summary| summary.adaptive_state_allowed)
            .count();
        let repair_first_boundaries = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let blocked_gates = history
            .summaries()
            .iter()
            .map(|summary| summary.blocked_gates)
            .sum();
        let total_reasons = history
            .summaries()
            .iter()
            .map(|summary| summary.reasons)
            .sum();
        let service_execution_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_closes)
            .sum();
        let service_execution_rust_validation_command_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_count)
            .sum();
        let service_execution_rust_validation_command_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_closes)
            .sum();
        let service_execution_tool_build_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_tool_build_command_reason_count)
            .sum();
        let latest = history.summaries().last();

        Self {
            total_boundaries,
            continue_boundaries,
            observe_boundaries,
            repair_boundaries,
            dispatch_allowed_boundaries,
            memory_note_allowed_boundaries,
            adaptive_state_allowed_boundaries,
            repair_first_boundaries,
            blocked_gates,
            total_reasons,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_rust_validation_command_count,
            service_execution_rust_validation_command_closes,
            service_execution_tool_build_command_reason_count,
            latest_mode: latest.map(|summary| summary.mode),
            latest_health_status: latest.map(|summary| summary.health_status),
            continue_rate: rate(continue_boundaries, total_boundaries),
            observe_rate: rate(observe_boundaries, total_boundaries),
            repair_rate: rate(repair_boundaries, total_boundaries),
            dispatch_allowed_rate: rate(dispatch_allowed_boundaries, total_boundaries),
            memory_note_allowed_rate: rate(memory_note_allowed_boundaries, total_boundaries),
            adaptive_state_allowed_rate: rate(adaptive_state_allowed_boundaries, total_boundaries),
            repair_first_rate: rate(repair_first_boundaries, total_boundaries),
        }
    }

    pub fn health(
        &self,
        policy: AgentCollaborationSideEffectBoundaryHealthPolicy,
    ) -> AgentCollaborationSideEffectBoundaryHealth {
        AgentCollaborationSideEffectBoundaryHealth::from_dashboard(self, policy)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryHealthPolicy {
    pub minimum_dispatch_allowed_rate: f32,
    pub minimum_memory_note_allowed_rate: f32,
    pub maximum_repair_rate: f32,
    pub maximum_repair_first_rate: f32,
}

impl Default for AgentCollaborationSideEffectBoundaryHealthPolicy {
    fn default() -> Self {
        Self {
            minimum_dispatch_allowed_rate: 0.25,
            minimum_memory_note_allowed_rate: 0.25,
            maximum_repair_rate: 0.0,
            maximum_repair_first_rate: 0.0,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSideEffectBoundaryHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationSideEffectBoundaryDashboard,
        policy: AgentCollaborationSideEffectBoundaryHealthPolicy,
    ) -> Self {
        if dashboard.total_boundaries == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec!["collaboration_side_effect_boundary_history_empty".to_owned()],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "collaboration_side_effect_boundary_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "collaboration_side_effect_boundary_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.dispatch_allowed_rate < policy.minimum_dispatch_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_side_effect_boundary_dispatch_allowed_rate={:.3}<{:.3}",
                dashboard.dispatch_allowed_rate, policy.minimum_dispatch_allowed_rate
            ));
        }
        if dashboard.memory_note_allowed_rate < policy.minimum_memory_note_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_side_effect_boundary_memory_note_allowed_rate={:.3}<{:.3}",
                dashboard.memory_note_allowed_rate, policy.minimum_memory_note_allowed_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }

    pub fn is_stable(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn allows_service_advance(&self) -> bool {
        self.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

