#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationSideEffectBoundaryGate;

impl AgentCollaborationSideEffectBoundaryGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        boundary: &AgentCollaborationSideEffectBoundary,
        history_record: &AgentCollaborationSideEffectBoundaryHistoryRecord,
    ) -> AgentCollaborationSideEffectBoundaryGateDecision {
        let requested_mode = boundary.mode;
        let boundary_health = history_record.health.clone();
        let effective_mode = side_effect_boundary_gate_mode(requested_mode, boundary_health.status);
        let requires_repair_first =
            boundary.requires_repair_first || effective_mode == AgentClosedLoopNextTurnMode::Repair;
        let can_dispatch_service_commands = effective_mode.can_schedule()
            && boundary.can_dispatch_service_commands
            && !requires_repair_first;
        let can_promote_memory_note = effective_mode == AgentClosedLoopNextTurnMode::Continue
            && boundary_health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && boundary.can_promote_memory_note;
        let can_admit_adaptive_evolution = can_promote_memory_note
            && boundary_health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && boundary.can_admit_adaptive_evolution;
        let reasons = side_effect_boundary_gate_reasons(boundary, &boundary_health, effective_mode);
        let gates = vec![
            side_effect_boundary_gate(
                SideEffectKind::ExternalCall,
                can_dispatch_service_commands,
                "service_command_dispatch",
                &reasons,
            ),
            side_effect_boundary_gate(
                SideEffectKind::MemoryNote,
                can_promote_memory_note,
                "memory_note_promotion",
                &reasons,
            ),
            side_effect_boundary_gate(
                SideEffectKind::AdaptiveStateWrite,
                can_admit_adaptive_evolution,
                "adaptive_evolution_admission",
                &reasons,
            ),
        ];
        let telemetry = side_effect_boundary_gate_telemetry(
            requested_mode,
            effective_mode,
            &boundary_health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            reasons.len(),
            history_record
                .dashboard
                .service_execution_tool_build_command_reason_count,
        );

        AgentCollaborationSideEffectBoundaryGateDecision {
            requested_mode,
            effective_mode,
            boundary_health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            gates,
            reasons,
            service_execution_command_reason_count: history_record
                .dashboard
                .service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count: history_record
                .dashboard
                .service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes: history_record
                .dashboard
                .service_execution_memory_promotion_command_reason_closes,
            service_execution_tool_build_command_reason_count: history_record
                .dashboard
                .service_execution_tool_build_command_reason_count,
            telemetry,
        }
    }
}

