#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryHandoffMonitorHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSideEffectBoundaryHandoffMonitorHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationSideEffectBoundaryHandoffMonitorDashboard,
        policy: AgentCollaborationSideEffectBoundaryHandoffMonitorHealthPolicy,
    ) -> Self {
        if dashboard.total_records == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec![
                    "collaboration_side_effect_boundary_handoff_monitor_history_empty".to_owned(),
                ],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.boundary_repair_rate > policy.maximum_boundary_repair_rate {
            repair_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_boundary_repair_rate={:.3}>{:.3}",
                dashboard.boundary_repair_rate, policy.maximum_boundary_repair_rate
            ));
        }
        if dashboard.handoff_repair_rate > policy.maximum_handoff_repair_rate {
            repair_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_handoff_repair_rate={:.3}>{:.3}",
                dashboard.handoff_repair_rate, policy.maximum_handoff_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.dispatch_allowed_rate < policy.minimum_dispatch_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_dispatch_allowed_rate={:.3}<{:.3}",
                dashboard.dispatch_allowed_rate, policy.minimum_dispatch_allowed_rate
            ));
        }
        if dashboard.memory_note_allowed_rate < policy.minimum_memory_note_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_memory_note_allowed_rate={:.3}<{:.3}",
                dashboard.memory_note_allowed_rate, policy.minimum_memory_note_allowed_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }
}

