#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffSummary {
    pub effective_mode: AgentClosedLoopNextTurnMode,
    pub monitor_health_status: AgentClosedLoopExecutionHealthStatus,
    pub dispatch_allowed: bool,
    pub memory_note_allowed: bool,
    pub adaptive_state_allowed: bool,
    pub requires_repair_first: bool,
    pub records: usize,
    pub gates: usize,
    pub blocked_gates: usize,
    pub reasons: usize,
    pub monitor_history_health_reasons: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_tool_build_command_reason_count: usize,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffSummary {
    pub fn from_handoff(
        record: &AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffRecord,
    ) -> Self {
        let blocked_gates = record
            .gate_decision
            .gates
            .iter()
            .filter(|gate| !gate.allowed)
            .count();
        let telemetry =
            side_effect_boundary_handoff_monitor_handoff_summary_telemetry(record, blocked_gates);

        Self {
            effective_mode: record.effective_mode(),
            monitor_health_status: record.monitor_health_status(),
            dispatch_allowed: record
                .service_dispatch_gate()
                .is_some_and(|gate| gate.allowed),
            memory_note_allowed: record.memory_note_gate().is_some_and(|gate| gate.allowed),
            adaptive_state_allowed: record
                .adaptive_state_gate()
                .is_some_and(|gate| gate.allowed),
            requires_repair_first: record.requires_repair_first(),
            records: record.records(),
            gates: record.gate_decision.gates.len(),
            blocked_gates,
            reasons: record.gate_decision.reasons.len(),
            monitor_history_health_reasons: record.history_record.health.reasons.len(),
            service_execution_command_reason_count: record
                .gate_decision
                .service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count: record
                .gate_decision
                .service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes: record
                .gate_decision
                .service_execution_memory_promotion_command_reason_closes,
            service_execution_tool_build_command_reason_count: record
                .gate_decision
                .service_execution_tool_build_command_reason_count,
            telemetry,
        }
    }
}

