#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffDashboard {
    pub total_handoffs: usize,
    pub continue_handoffs: usize,
    pub observe_handoffs: usize,
    pub repair_handoffs: usize,
    pub dispatch_allowed_handoffs: usize,
    pub memory_note_allowed_handoffs: usize,
    pub adaptive_state_allowed_handoffs: usize,
    pub repair_first_handoffs: usize,
    pub blocked_gates: usize,
    pub total_reasons: usize,
    pub monitor_history_health_reasons: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_tool_build_command_reason_count: usize,
    pub latest_effective_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_monitor_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub continue_rate: f32,
    pub observe_rate: f32,
    pub repair_rate: f32,
    pub dispatch_allowed_rate: f32,
    pub memory_note_allowed_rate: f32,
    pub adaptive_state_allowed_rate: f32,
    pub repair_first_rate: f32,
}

impl AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffDashboard {
    pub fn from_history(
        history: &AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHistory,
    ) -> Self {
        let total_handoffs = history.len();
        let continue_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Continue)
            .count();
        let observe_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Observe)
            .count();
        let repair_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Repair)
            .count();
        let dispatch_allowed_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.dispatch_allowed)
            .count();
        let memory_note_allowed_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.memory_note_allowed)
            .count();
        let adaptive_state_allowed_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.adaptive_state_allowed)
            .count();
        let repair_first_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let blocked_gates = history
            .summaries()
            .iter()
            .map(|summary| summary.blocked_gates)
            .sum();
        let total_reasons = history
            .summaries()
            .iter()
            .map(|summary| summary.reasons)
            .sum();
        let monitor_history_health_reasons = history
            .summaries()
            .iter()
            .map(|summary| summary.monitor_history_health_reasons)
            .sum();
        let service_execution_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_closes)
            .sum();
        let service_execution_tool_build_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_tool_build_command_reason_count)
            .sum();
        let latest = history.summaries().last();

        Self {
            total_handoffs,
            continue_handoffs,
            observe_handoffs,
            repair_handoffs,
            dispatch_allowed_handoffs,
            memory_note_allowed_handoffs,
            adaptive_state_allowed_handoffs,
            repair_first_handoffs,
            blocked_gates,
            total_reasons,
            monitor_history_health_reasons,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_tool_build_command_reason_count,
            latest_effective_mode: latest.map(|summary| summary.effective_mode),
            latest_monitor_health_status: latest.map(|summary| summary.monitor_health_status),
            continue_rate: rate(continue_handoffs, total_handoffs),
            observe_rate: rate(observe_handoffs, total_handoffs),
            repair_rate: rate(repair_handoffs, total_handoffs),
            dispatch_allowed_rate: rate(dispatch_allowed_handoffs, total_handoffs),
            memory_note_allowed_rate: rate(memory_note_allowed_handoffs, total_handoffs),
            adaptive_state_allowed_rate: rate(adaptive_state_allowed_handoffs, total_handoffs),
            repair_first_rate: rate(repair_first_handoffs, total_handoffs),
        }
    }

    pub fn health(
        &self,
        policy: AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealthPolicy,
    ) -> AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealth {
        AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealth::from_dashboard(
            self, policy,
        )
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealthPolicy {
    pub minimum_dispatch_allowed_rate: f32,
    pub minimum_memory_note_allowed_rate: f32,
    pub maximum_repair_rate: f32,
    pub maximum_repair_first_rate: f32,
}

impl Default for AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealthPolicy {
    fn default() -> Self {
        Self {
            minimum_dispatch_allowed_rate: 0.25,
            minimum_memory_note_allowed_rate: 0.25,
            maximum_repair_rate: 0.0,
            maximum_repair_first_rate: 0.0,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffDashboard,
        policy: AgentCollaborationSideEffectBoundaryHandoffMonitorHandoffHealthPolicy,
    ) -> Self {
        if dashboard.total_handoffs == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec![
                    "collaboration_side_effect_boundary_handoff_monitor_handoff_history_empty"
                        .to_owned(),
                ],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_handoff_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_handoff_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.dispatch_allowed_rate < policy.minimum_dispatch_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_handoff_dispatch_allowed_rate={:.3}<{:.3}",
                dashboard.dispatch_allowed_rate, policy.minimum_dispatch_allowed_rate
            ));
        }
        if dashboard.memory_note_allowed_rate < policy.minimum_memory_note_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_side_effect_boundary_handoff_monitor_handoff_memory_note_allowed_rate={:.3}<{:.3}",
                dashboard.memory_note_allowed_rate, policy.minimum_memory_note_allowed_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }
}

