#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationAdapterSideEffectAdmissionDashboard {
    pub total_admissions: usize,
    pub continue_admissions: usize,
    pub observe_admissions: usize,
    pub repair_admissions: usize,
    pub dispatch_allowed_admissions: usize,
    pub memory_note_allowed_admissions: usize,
    pub adaptive_state_allowed_admissions: usize,
    pub repair_first_admissions: usize,
    pub blocked_gates: usize,
    pub total_reasons: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_tool_build_command_reason_count: usize,
    pub latest_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub continue_rate: f32,
    pub observe_rate: f32,
    pub repair_rate: f32,
    pub dispatch_allowed_rate: f32,
    pub memory_note_allowed_rate: f32,
    pub adaptive_state_allowed_rate: f32,
    pub repair_first_rate: f32,
}

impl AgentCollaborationAdapterSideEffectAdmissionDashboard {
    pub fn from_history(history: &AgentCollaborationAdapterSideEffectAdmissionHistory) -> Self {
        let total_admissions = history.len();
        let continue_admissions = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Continue)
            .count();
        let observe_admissions = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Observe)
            .count();
        let repair_admissions = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Repair)
            .count();
        let dispatch_allowed_admissions = history
            .summaries()
            .iter()
            .filter(|summary| summary.dispatch_allowed)
            .count();
        let memory_note_allowed_admissions = history
            .summaries()
            .iter()
            .filter(|summary| summary.memory_note_allowed)
            .count();
        let adaptive_state_allowed_admissions = history
            .summaries()
            .iter()
            .filter(|summary| summary.adaptive_state_allowed)
            .count();
        let repair_first_admissions = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let blocked_gates = history
            .summaries()
            .iter()
            .map(|summary| summary.blocked_gates)
            .sum();
        let total_reasons = history
            .summaries()
            .iter()
            .map(|summary| summary.reasons)
            .sum();
        let service_execution_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_closes)
            .sum();
        let service_execution_tool_build_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_tool_build_command_reason_count)
            .sum();
        let latest = history.summaries().last();

        Self {
            total_admissions,
            continue_admissions,
            observe_admissions,
            repair_admissions,
            dispatch_allowed_admissions,
            memory_note_allowed_admissions,
            adaptive_state_allowed_admissions,
            repair_first_admissions,
            blocked_gates,
            total_reasons,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_tool_build_command_reason_count,
            latest_mode: latest.map(|summary| summary.mode),
            latest_health_status: latest.map(|summary| summary.health_status),
            continue_rate: rate(continue_admissions, total_admissions),
            observe_rate: rate(observe_admissions, total_admissions),
            repair_rate: rate(repair_admissions, total_admissions),
            dispatch_allowed_rate: rate(dispatch_allowed_admissions, total_admissions),
            memory_note_allowed_rate: rate(memory_note_allowed_admissions, total_admissions),
            adaptive_state_allowed_rate: rate(adaptive_state_allowed_admissions, total_admissions),
            repair_first_rate: rate(repair_first_admissions, total_admissions),
        }
    }

    pub fn health(
        &self,
        policy: AgentCollaborationAdapterSideEffectAdmissionHealthPolicy,
    ) -> AgentCollaborationAdapterSideEffectAdmissionHealth {
        AgentCollaborationAdapterSideEffectAdmissionHealth::from_dashboard(self, policy)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationAdapterSideEffectAdmissionHealthPolicy {
    pub minimum_dispatch_allowed_rate: f32,
    pub minimum_memory_note_allowed_rate: f32,
    pub maximum_repair_rate: f32,
    pub maximum_repair_first_rate: f32,
}

impl Default for AgentCollaborationAdapterSideEffectAdmissionHealthPolicy {
    fn default() -> Self {
        Self {
            minimum_dispatch_allowed_rate: 0.25,
            minimum_memory_note_allowed_rate: 0.25,
            maximum_repair_rate: 0.0,
            maximum_repair_first_rate: 0.0,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationAdapterSideEffectAdmissionHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationAdapterSideEffectAdmissionHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationAdapterSideEffectAdmissionDashboard,
        policy: AgentCollaborationAdapterSideEffectAdmissionHealthPolicy,
    ) -> Self {
        if dashboard.total_admissions == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec![
                    "collaboration_adapter_side_effect_admission_history_empty".to_owned(),
                ],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "collaboration_adapter_side_effect_admission_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "collaboration_adapter_side_effect_admission_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.dispatch_allowed_rate < policy.minimum_dispatch_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_adapter_side_effect_admission_dispatch_allowed_rate={:.3}<{:.3}",
                dashboard.dispatch_allowed_rate, policy.minimum_dispatch_allowed_rate
            ));
        }
        if dashboard.memory_note_allowed_rate < policy.minimum_memory_note_allowed_rate {
            watch_reasons.push(format!(
                "collaboration_adapter_side_effect_admission_memory_note_allowed_rate={:.3}<{:.3}",
                dashboard.memory_note_allowed_rate, policy.minimum_memory_note_allowed_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationAdapterSideEffectAdmissionHistoryRecord {
    pub history: AgentCollaborationAdapterSideEffectAdmissionHistory,
    pub appended_summary: AgentCollaborationAdapterSideEffectAdmissionSummary,
    pub dashboard: AgentCollaborationAdapterSideEffectAdmissionDashboard,
    pub health: AgentCollaborationAdapterSideEffectAdmissionHealth,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationAdapterSideEffectAdmissionHistoryRecord {
    pub fn records(&self) -> usize {
        self.history.len()
    }

    pub fn allows_service_advance(&self) -> bool {
        self.health.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.health.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationAdapterSideEffectAdmissionHistoryRecorder;

impl AgentCollaborationAdapterSideEffectAdmissionHistoryRecorder {
    pub fn new() -> Self {
        Self
    }

    pub fn record_summary(
        &self,
        mut history: AgentCollaborationAdapterSideEffectAdmissionHistory,
        summary: AgentCollaborationAdapterSideEffectAdmissionSummary,
        policy: AgentCollaborationAdapterSideEffectAdmissionHealthPolicy,
    ) -> AgentCollaborationAdapterSideEffectAdmissionHistoryRecord {
        history.push(summary.clone());
        let dashboard = history.dashboard();
        let health = dashboard.health(policy);
        let telemetry =
            adapter_side_effect_admission_history_record_telemetry(&summary, &dashboard, &health);

        AgentCollaborationAdapterSideEffectAdmissionHistoryRecord {
            history,
            appended_summary: summary,
            dashboard,
            health,
            telemetry,
        }
    }

    pub fn record_admission(
        &self,
        history: AgentCollaborationAdapterSideEffectAdmissionHistory,
        admission: &AgentCollaborationAdapterSideEffectAdmission,
        policy: AgentCollaborationAdapterSideEffectAdmissionHealthPolicy,
    ) -> AgentCollaborationAdapterSideEffectAdmissionHistoryRecord {
        self.record_summary(
            history,
            AgentCollaborationAdapterSideEffectAdmissionSummary::from_admission(admission),
            policy,
        )
    }
}

