#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffGateDecision {
    pub requested_mode: AgentClosedLoopNextTurnMode,
    pub effective_mode: AgentClosedLoopNextTurnMode,
    pub handoff_health: AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffHealth,
    pub can_dispatch_service_commands: bool,
    pub can_promote_memory_note: bool,
    pub can_admit_adaptive_evolution: bool,
    pub requires_repair_first: bool,
    pub gates: Vec<SideEffectGate>,
    pub reasons: Vec<String>,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_tool_build_command_reason_count: usize,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffGateDecision {
    pub fn gate(&self, kind: SideEffectKind) -> Option<&SideEffectGate> {
        self.gates.iter().find(|gate| gate.kind == kind)
    }

    pub fn memory_note_gate(&self) -> Option<&SideEffectGate> {
        self.gate(SideEffectKind::MemoryNote)
    }

    pub fn adaptive_state_gate(&self) -> Option<&SideEffectGate> {
        self.gate(SideEffectKind::AdaptiveStateWrite)
    }

    pub fn service_dispatch_gate(&self) -> Option<&SideEffectGate> {
        self.gate(SideEffectKind::ExternalCall)
    }
}

#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffGate;

impl AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        handoff: &AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffRecord,
        history_record: &AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffHistoryRecord,
    ) -> AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffGateDecision {
        let requested_mode = handoff.effective_mode();
        let handoff_health = history_record.health.clone();
        let effective_mode = side_effect_boundary_gate_mode(requested_mode, handoff_health.status);
        let requires_repair_first = handoff.requires_repair_first()
            || effective_mode == AgentClosedLoopNextTurnMode::Repair;
        let can_dispatch_service_commands = effective_mode.can_schedule()
            && handoff.can_dispatch_service_commands()
            && !requires_repair_first;
        let can_promote_memory_note = effective_mode == AgentClosedLoopNextTurnMode::Continue
            && handoff_health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && handoff.can_promote_memory_note();
        let can_admit_adaptive_evolution = can_promote_memory_note
            && handoff_health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && handoff.can_admit_adaptive_evolution();
        let reasons = adapter_side_effect_admission_monitor_handoff_gate_reasons(
            handoff,
            &handoff_health,
            effective_mode,
        );
        let gates = vec![
            side_effect_boundary_gate(
                SideEffectKind::ExternalCall,
                can_dispatch_service_commands,
                "service_command_dispatch",
                &reasons,
            ),
            side_effect_boundary_gate(
                SideEffectKind::MemoryNote,
                can_promote_memory_note,
                "memory_note_promotion",
                &reasons,
            ),
            side_effect_boundary_gate(
                SideEffectKind::AdaptiveStateWrite,
                can_admit_adaptive_evolution,
                "adaptive_evolution_admission",
                &reasons,
            ),
        ];
        let telemetry = adapter_side_effect_admission_monitor_handoff_gate_telemetry(
            requested_mode,
            effective_mode,
            &handoff_health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            reasons.len(),
            history_record
                .dashboard
                .service_execution_tool_build_command_reason_count,
        );

        AgentCollaborationAdapterSideEffectAdmissionMonitorHandoffGateDecision {
            requested_mode,
            effective_mode,
            handoff_health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            gates,
            reasons,
            service_execution_command_reason_count: history_record
                .dashboard
                .service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count: history_record
                .dashboard
                .service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes: history_record
                .dashboard
                .service_execution_memory_promotion_command_reason_closes,
            service_execution_tool_build_command_reason_count: history_record
                .dashboard
                .service_execution_tool_build_command_reason_count,
            telemetry,
        }
    }
}

