impl AgentCollaborationPlanSummaryHistoryRecorder {
    pub fn new() -> Self {
        Self
    }

    pub fn record_summary_with_health(
        &self,
        mut history: AgentCollaborationPlanSummaryHistory,
        summary: AgentCollaborationPlanSummary,
        policy: AgentCollaborationPlanHealthPolicy,
    ) -> AgentCollaborationPlanSummaryHistoryRecord {
        history.push(summary.clone());
        let dashboard = history.dashboard();
        let health = dashboard.health(policy);
        let telemetry = collaboration_plan_history_record_telemetry(&dashboard, &health);

        AgentCollaborationPlanSummaryHistoryRecord {
            history,
            appended_summary: summary,
            dashboard,
            health,
            telemetry,
        }
    }

    pub fn record_plan_with_health(
        &self,
        history: AgentCollaborationPlanSummaryHistory,
        plan: &AgentCollaborationPlan,
        gate_policy: AgentCollaborationPlanGatePolicy,
        health_policy: AgentCollaborationPlanHealthPolicy,
    ) -> AgentCollaborationPlanSummaryHistoryRecord {
        self.record_summary_with_health(history, plan.summary(gate_policy), health_policy)
    }

    pub fn record_plan_with_health_gate(
        &self,
        history: AgentCollaborationPlanSummaryHistory,
        plan: &AgentCollaborationPlan,
        gate_policy: AgentCollaborationPlanGatePolicy,
        health_policy: AgentCollaborationPlanHealthPolicy,
    ) -> AgentCollaborationPlanHistoryGateRecord {
        let health_record = self.record_plan_with_health(history, plan, gate_policy, health_policy);
        let gate_decision =
            AgentCollaborationPlanHistoryGate::new().gate(plan, gate_policy, &health_record);
        let telemetry =
            collaboration_plan_history_gate_record_telemetry(&health_record, &gate_decision);

        AgentCollaborationPlanHistoryGateRecord {
            health_record,
            gate_decision,
            telemetry,
        }
    }
}

