#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationPlanHistoryGate;

impl AgentCollaborationPlanHistoryGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        plan: &AgentCollaborationPlan,
        gate_policy: AgentCollaborationPlanGatePolicy,
        history_record: &AgentCollaborationPlanSummaryHistoryRecord,
    ) -> AgentCollaborationPlanHistoryGateDecision {
        let plan_gate = plan.gate(gate_policy);
        let plan_health = history_record.health.clone();
        let mut reasons = plan_gate.reasons.clone();
        extend_ordered_unique(
            &mut reasons,
            plan_health
                .reasons
                .iter()
                .map(|reason| format!("collaboration_plan_history:{reason}"))
                .collect::<Vec<_>>(),
        );
        let requires_repair_first = plan_gate.status
            == AgentClosedLoopExecutionHealthStatus::Repair
            || plan_health.requires_repair_first();
        let can_dispatch_queue = plan_gate.can_dispatch_queue
            && plan_health.allows_service_advance()
            && !requires_repair_first;
        let can_open_side_effect_boundary = plan_gate.can_open_side_effect_boundary
            && plan_health.allows_service_advance()
            && !requires_repair_first;
        let repair_tasks =
            collaboration_plan_history_gate_repair_tasks(requires_repair_first, &reasons);
        let repair_queue = AgentTaskQueue::from_tasks(repair_tasks.clone());
        let telemetry = collaboration_plan_history_gate_telemetry(
            plan_health.status,
            can_dispatch_queue,
            can_open_side_effect_boundary,
            requires_repair_first,
            repair_tasks.len(),
            repair_queue.len(),
            reasons.len(),
            &plan_gate.summary,
        );

        AgentCollaborationPlanHistoryGateDecision {
            plan_gate,
            plan_health,
            can_dispatch_queue,
            can_open_side_effect_boundary,
            requires_repair_first,
            repair_tasks,
            repair_queue,
            reasons,
            telemetry,
        }
    }
}

