#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AgentWindowContextCleanRoomReassignmentReport {
    pub report_only: bool,
    pub pure_data_only: bool,
    pub side_effects_allowed: bool,
    pub starts_thread: bool,
    pub sends_message: bool,
    pub reads_old_window_payload: bool,
    pub carries_old_thread_body: bool,
    pub assigns_original_window_follow_up: bool,
    pub total_workers: usize,
    pub old_windows_deactivated: Vec<String>,
    pub clean_room_replacement_worker_ids: Vec<String>,
    pub completed_worker_ids: Vec<String>,
    pub sanitized_candidate_task_ids: Vec<String>,
    pub rejected_candidate_tasks: usize,
    pub clean_room_replacement_task_ids: Vec<String>,
    pub inherited_evidence_result_ids: Vec<String>,
    pub discarded_payload_refs: Vec<String>,
    pub reason_codes: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentWindowContextCleanRoomReassignmentReport {
    pub fn from_workers(
        workers: &[AgentWindowContextReassignmentWorker],
        sanitized_candidate_task_ids: impl IntoIterator<Item = impl Into<String>>,
    ) -> Self {
        let raw_candidate_task_ids = dedup_stable(
            sanitized_candidate_task_ids
                .into_iter()
                .map(Into::into)
                .collect(),
        );
        let sanitized_candidate_task_ids = raw_candidate_task_ids
            .iter()
            .filter(|task_id| is_clean_room_candidate_task_id(task_id))
            .cloned()
            .collect::<Vec<_>>();
        let rejected_candidate_tasks = raw_candidate_task_ids
            .len()
            .saturating_sub(sanitized_candidate_task_ids.len());
        let mut old_windows_deactivated = Vec::new();
        let mut clean_room_replacement_worker_ids = Vec::new();
        let mut completed_worker_ids = Vec::new();
        let mut replacement_source_task_ids = Vec::new();
        let mut inherited_evidence_result_ids = Vec::new();
        let mut discarded_payload_refs = Vec::new();
        let mut reason_codes = Vec::new();

        for worker in workers {
            reason_codes.push(worker.status.reason_code().to_owned());
            reason_codes.extend(worker.reason_codes.clone());
            inherited_evidence_result_ids.extend(worker.evidence_result_ids.clone());
            discarded_payload_refs.extend(worker.discarded_payload_refs.clone());

            if worker.status.requires_old_window_deactivation() {
                old_windows_deactivated.push(worker.worker_id.clone());
            }
            if worker.status.requires_clean_room_replacement() {
                clean_room_replacement_worker_ids.push(worker.worker_id.clone());
                replacement_source_task_ids.extend(worker.task_ids.clone());
            }
            if worker.status == AgentWindowContextReassignmentWorkerStatus::Completed {
                completed_worker_ids.push(worker.worker_id.clone());
            }
        }

        let replacement_source_task_ids = dedup_stable(replacement_source_task_ids);
        let clean_room_replacement_task_ids = clean_room_reassignment_replacement_task_ids(
            &sanitized_candidate_task_ids,
            &replacement_source_task_ids,
            !clean_room_replacement_worker_ids.is_empty(),
        );
        if !clean_room_replacement_worker_ids.is_empty() {
            reason_codes.push("clean_room_replacement_required".to_owned());
        }
        if rejected_candidate_tasks > 0 {
            reason_codes.push("candidate_clean_room_task_payload_discarded".to_owned());
            discarded_payload_refs.push("candidate_clean_room_task_payload".to_owned());
        }
        if clean_room_replacement_task_ids.is_empty()
            && !clean_room_replacement_worker_ids.is_empty()
        {
            reason_codes.push("clean_room_replacement_task_ids_empty".to_owned());
        }
        if !completed_worker_ids.is_empty() {
            reason_codes.push("completed_worker_evidence_inherited".to_owned());
        }

        let old_windows_deactivated = dedup_stable(old_windows_deactivated);
        let clean_room_replacement_worker_ids = dedup_stable(clean_room_replacement_worker_ids);
        let completed_worker_ids = dedup_stable(completed_worker_ids);
        let inherited_evidence_result_ids = dedup_stable(inherited_evidence_result_ids);
        let discarded_payload_refs = dedup_stable(discarded_payload_refs);
        let reason_codes = dedup_stable(reason_codes);
        let telemetry = collaboration_window_context_clean_room_reassignment_report_telemetry(
            workers.len(),
            old_windows_deactivated.len(),
            clean_room_replacement_worker_ids.len(),
            completed_worker_ids.len(),
            sanitized_candidate_task_ids.len(),
            rejected_candidate_tasks,
            clean_room_replacement_task_ids.len(),
            inherited_evidence_result_ids.len(),
            discarded_payload_refs.len(),
            reason_codes.len(),
        );

        Self {
            report_only: true,
            pure_data_only: true,
            side_effects_allowed: false,
            starts_thread: false,
            sends_message: false,
            reads_old_window_payload: false,
            carries_old_thread_body: false,
            assigns_original_window_follow_up: false,
            total_workers: workers.len(),
            old_windows_deactivated,
            clean_room_replacement_worker_ids,
            completed_worker_ids,
            sanitized_candidate_task_ids,
            rejected_candidate_tasks,
            clean_room_replacement_task_ids,
            inherited_evidence_result_ids,
            discarded_payload_refs,
            reason_codes,
            telemetry,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum AgentHelperRole {
    Summary,
    Router,
    Review,
    Index,
    TestGate,
}

impl AgentHelperRole {
    pub fn all() -> [Self; 5] {
        [
            Self::Summary,
            Self::Router,
            Self::Review,
            Self::Index,
            Self::TestGate,
        ]
    }

    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Summary => "summary",
            Self::Router => "router",
            Self::Review => "review",
            Self::Index => "index",
            Self::TestGate => "test-gate",
        }
    }

    pub fn reason_code_prefix(&self) -> &'static str {
        match self {
            Self::Summary => "summary",
            Self::Router => "router",
            Self::Review => "review",
            Self::Index => "index",
            Self::TestGate => "test_gate",
        }
    }

    pub fn agent_role(&self) -> AgentRole {
        match self {
            Self::Summary => AgentRole::Aggregator,
            Self::Router => AgentRole::Planner,
            Self::Review => AgentRole::Reviewer,
            Self::Index => AgentRole::MemoryCurator,
            Self::TestGate => AgentRole::Tester,
        }
    }

    pub fn repair_lane(&self) -> &'static str {
        match self {
            Self::Summary => "summary-repair",
            Self::Router => "router-repair",
            Self::Review => "review-repair",
            Self::Index => "index-repair",
            Self::TestGate => "test-gate-repair",
        }
    }

    pub fn from_label(label: impl AsRef<str>) -> Option<Self> {
        let normalized = label.as_ref().trim().to_ascii_lowercase().replace('_', "-");
        match normalized.as_str() {
            "summary" | "summarizer" | "aggregation" | "aggregator" => Some(Self::Summary),
            "router" | "route" | "routing" | "planner" => Some(Self::Router),
            "review" | "reviewer" => Some(Self::Review),
            "index" | "indexer" | "memory-index" | "memory-curator" => Some(Self::Index),
            "test-gate" | "testgate" | "tester" | "test" => Some(Self::TestGate),
            _ => None,
        }
    }
}

