#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AgentHelperRoleRepairRoutingReport {
    pub report_only: bool,
    pub pure_data_only: bool,
    pub side_effect_dispatch_allowed: bool,
    pub starts_thread: bool,
    pub sends_message: bool,
    pub reads_old_window_payload: bool,
    pub carries_raw_payload: bool,
    pub decision: AgentHelperRoleRepairRoutingDecision,
    pub total_evidence: usize,
    pub complete_helper_evidence: usize,
    pub incomplete_helper_evidence: usize,
    pub requires_repair_first: bool,
    pub clean_matching_role_repair_tasks: bool,
    pub routed_helper_roles: Vec<AgentHelperRole>,
    pub role_counts: Vec<AgentHelperRoleRepairRoutingCount>,
    pub repair_tasks: Vec<AgentTask>,
    pub inherited_evidence_result_ids: Vec<String>,
    pub discarded_payload_refs: Vec<String>,
    pub reason_codes: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentHelperRoleRepairRoutingReport {
    pub fn from_evidence(evidence: &[AgentHelperRoleEvidence]) -> Self {
        Self::from_evidence_with_task_prefix(evidence, "helper-role-repair")
    }

    pub fn from_review_evidence(evidence: &[AgentReviewHelperEvidence]) -> Self {
        let evidence = evidence
            .iter()
            .map(AgentHelperRoleEvidence::from)
            .collect::<Vec<_>>();
        Self::from_evidence(&evidence)
    }

    pub fn from_evidence_with_task_prefix(
        evidence: &[AgentHelperRoleEvidence],
        task_prefix: impl AsRef<str>,
    ) -> Self {
        let total_evidence = evidence.len();
        let mut complete_helper_evidence = 0;
        let mut incomplete_helper_evidence = 0;
        let mut role_counts = AgentHelperRole::all()
            .into_iter()
            .map(AgentHelperRoleRepairRoutingCount::new)
            .collect::<Vec<_>>();
        let mut repair_tasks = Vec::new();
        let mut inherited_evidence_result_ids = Vec::new();
        let mut discarded_payload_refs = Vec::new();
        let mut reason_codes = Vec::new();

        let task_prefix = helper_role_clean_task_prefix(task_prefix.as_ref(), &mut reason_codes);

        for item in evidence {
            let evidence_id = helper_role_clean_ref(
                &item.evidence_id,
                "helper_role_evidence_id",
                &mut discarded_payload_refs,
                &mut reason_codes,
            );
            let helper_id = helper_role_clean_ref(
                &item.helper_id,
                "helper_role_helper_id",
                &mut discarded_payload_refs,
                &mut reason_codes,
            );
            reason_codes.extend(item.reason_codes.clone());
            discarded_payload_refs.extend(item.discarded_payload_refs.clone());
            helper_role_increment_counts(&mut role_counts, &item.helper_role, item.is_complete());

            if item.is_complete() {
                complete_helper_evidence += 1;
                reason_codes.push(format!(
                    "{}_helper_evidence_complete",
                    item.helper_role.reason_code_prefix()
                ));
                reason_codes.push(format!(
                    "{}_completed_evidence_not_promoted",
                    item.helper_role.reason_code_prefix()
                ));
                continue;
            }

            incomplete_helper_evidence += 1;
            if let Some(evidence_id) = evidence_id.clone() {
                inherited_evidence_result_ids.push(evidence_id);
            }
            let missing_reason_codes = helper_role_missing_reason_codes(item);
            reason_codes.extend(missing_reason_codes.clone());
            let repair_task_id = format!(
                "{task_prefix}-{}-{}",
                item.helper_role.as_str(),
                repair_tasks.len()
            );
            let objective = helper_role_repair_objective(
                &item.helper_role,
                evidence_id.as_deref(),
                helper_id.as_deref(),
                &missing_reason_codes,
            );
            repair_tasks.push(
                AgentTask::new(
                    repair_task_id,
                    item.helper_role.agent_role(),
                    objective,
                    AgentBudget::new(16, 1, 1),
                )
                .with_lane(item.helper_role.repair_lane())
                .with_priority(1),
            );
            helper_role_increment_repair_tasks(&mut role_counts, &item.helper_role);
        }

        let inherited_evidence_result_ids = dedup_stable(inherited_evidence_result_ids);
        let discarded_payload_refs = dedup_stable(discarded_payload_refs);
        let reason_codes = dedup_stable(reason_codes);
        let routed_helper_roles = helper_role_routed_roles(&repair_tasks);
        let requires_repair_first = !repair_tasks.is_empty();
        let clean_matching_role_repair_tasks = repair_tasks.iter().all(|task| {
            AgentHelperRole::all()
                .iter()
                .any(|role| task.role == role.agent_role() && task.lane == role.repair_lane())
                && !self_improve_task_has_old_window_payload(task)
        });
        let decision = if requires_repair_first {
            AgentHelperRoleRepairRoutingDecision::Repair
        } else {
            AgentHelperRoleRepairRoutingDecision::Observe
        };
        let telemetry = helper_role_repair_routing_report_telemetry(
            decision,
            total_evidence,
            complete_helper_evidence,
            incomplete_helper_evidence,
            requires_repair_first,
            clean_matching_role_repair_tasks,
            routed_helper_roles.len(),
            repair_tasks.len(),
            inherited_evidence_result_ids.len(),
            discarded_payload_refs.len(),
            reason_codes.len(),
            &role_counts,
        );

        Self {
            report_only: true,
            pure_data_only: true,
            side_effect_dispatch_allowed: false,
            starts_thread: false,
            sends_message: false,
            reads_old_window_payload: false,
            carries_raw_payload: false,
            decision,
            total_evidence,
            complete_helper_evidence,
            incomplete_helper_evidence,
            requires_repair_first,
            clean_matching_role_repair_tasks,
            routed_helper_roles,
            role_counts,
            repair_tasks,
            inherited_evidence_result_ids,
            discarded_payload_refs,
            reason_codes,
            telemetry,
        }
    }

    pub fn repair_task_ids(&self) -> Vec<String> {
        self.repair_tasks
            .iter()
            .map(|task| task.id.clone())
            .collect()
    }

    pub fn allows_side_effect_dispatch(&self) -> bool {
        self.side_effect_dispatch_allowed && !self.requires_repair_first
    }
}

