impl From<&AgentReviewHelperEvidence> for AgentHelperRoleEvidence {
    fn from(evidence: &AgentReviewHelperEvidence) -> Self {
        let helper_role = if evidence.helper_role == AgentRole::Reviewer {
            AgentHelperRole::Review
        } else {
            AgentHelperRole::from_label(evidence.helper_role.as_str())
                .unwrap_or(AgentHelperRole::Review)
        };
        Self {
            evidence_id: evidence.evidence_id.clone(),
            helper_id: evidence.helper_id.clone(),
            helper_role,
            helper_stage_contract_complete: evidence.helper_stage_contract_complete,
            helper_result_complete: evidence.review_result_complete,
            report_gate_passed: evidence.report_gate_passed,
            reason_codes: evidence.reason_codes.clone(),
            discarded_payload_refs: evidence.discarded_payload_refs.clone(),
        }
    }
}

