#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AgentReviewHelperRepairRoutingReport {
    pub report_only: bool,
    pub pure_data_only: bool,
    pub side_effect_dispatch_allowed: bool,
    pub starts_thread: bool,
    pub sends_message: bool,
    pub reads_old_window_payload: bool,
    pub carries_raw_payload: bool,
    pub decision: AgentReviewHelperRepairRoutingDecision,
    pub required_role: AgentRole,
    pub total_evidence: usize,
    pub review_helper_evidence: usize,
    pub complete_review_helper_evidence: usize,
    pub incomplete_review_helper_evidence: usize,
    pub non_review_helper_evidence: usize,
    pub requires_repair_first: bool,
    pub clean_review_role_repair_task: bool,
    pub repair_tasks: Vec<AgentTask>,
    pub inherited_evidence_result_ids: Vec<String>,
    pub discarded_payload_refs: Vec<String>,
    pub reason_codes: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentReviewHelperRepairRoutingReport {
    pub fn from_evidence(evidence: &[AgentReviewHelperEvidence]) -> Self {
        Self::from_evidence_with_task_prefix(evidence, "review-helper-repair")
    }

    pub fn from_evidence_with_task_prefix(
        evidence: &[AgentReviewHelperEvidence],
        task_prefix: impl AsRef<str>,
    ) -> Self {
        let total_evidence = evidence.len();
        let mut review_helper_evidence = 0;
        let mut complete_review_helper_evidence = 0;
        let mut incomplete_review_helper_evidence = 0;
        let mut non_review_helper_evidence = 0;
        let mut repair_tasks = Vec::new();
        let mut inherited_evidence_result_ids = Vec::new();
        let mut discarded_payload_refs = Vec::new();
        let mut reason_codes = Vec::new();

        let task_prefix = review_helper_clean_task_prefix(task_prefix.as_ref(), &mut reason_codes);

        for item in evidence {
            let evidence_id = review_helper_clean_ref(
                &item.evidence_id,
                "review_helper_evidence_id",
                &mut discarded_payload_refs,
                &mut reason_codes,
            );
            let helper_id = review_helper_clean_ref(
                &item.helper_id,
                "review_helper_id",
                &mut discarded_payload_refs,
                &mut reason_codes,
            );
            if let Some(evidence_id) = evidence_id.clone() {
                inherited_evidence_result_ids.push(evidence_id);
            }
            reason_codes.extend(item.reason_codes.clone());
            discarded_payload_refs.extend(item.discarded_payload_refs.clone());

            if !item.is_review_helper() {
                non_review_helper_evidence += 1;
                reason_codes.push(format!(
                    "review_helper_role_not_reviewer={}",
                    item.helper_role.as_str()
                ));
                continue;
            }

            review_helper_evidence += 1;
            if item.is_complete() {
                complete_review_helper_evidence += 1;
                reason_codes.push("review_helper_evidence_complete".to_owned());
                continue;
            }

            incomplete_review_helper_evidence += 1;
            let missing_reason_codes = review_helper_missing_reason_codes(item);
            reason_codes.extend(missing_reason_codes.clone());
            let repair_task_id = format!("{task_prefix}-{}", repair_tasks.len());
            let objective = review_helper_repair_objective(
                evidence_id.as_deref(),
                helper_id.as_deref(),
                &missing_reason_codes,
            );
            repair_tasks.push(
                AgentTask::new(
                    repair_task_id,
                    AgentRole::Reviewer,
                    objective,
                    AgentBudget::new(16, 1, 1),
                )
                .with_lane("review-repair")
                .with_priority(1),
            );
        }

        let inherited_evidence_result_ids = dedup_stable(inherited_evidence_result_ids);
        let discarded_payload_refs = dedup_stable(discarded_payload_refs);
        let reason_codes = dedup_stable(reason_codes);
        let requires_repair_first = !repair_tasks.is_empty();
        let clean_review_role_repair_task = requires_repair_first
            && repair_tasks.iter().all(|task| {
                task.role == AgentRole::Reviewer
                    && task.lane == "review-repair"
                    && !self_improve_task_has_old_window_payload(task)
            });
        let decision = if requires_repair_first {
            AgentReviewHelperRepairRoutingDecision::Repair
        } else {
            AgentReviewHelperRepairRoutingDecision::Observe
        };
        let telemetry = review_helper_repair_routing_report_telemetry(
            decision,
            total_evidence,
            review_helper_evidence,
            complete_review_helper_evidence,
            incomplete_review_helper_evidence,
            non_review_helper_evidence,
            requires_repair_first,
            clean_review_role_repair_task,
            repair_tasks.len(),
            inherited_evidence_result_ids.len(),
            discarded_payload_refs.len(),
            reason_codes.len(),
        );

        Self {
            report_only: true,
            pure_data_only: true,
            side_effect_dispatch_allowed: false,
            starts_thread: false,
            sends_message: false,
            reads_old_window_payload: false,
            carries_raw_payload: false,
            decision,
            required_role: AgentRole::Reviewer,
            total_evidence,
            review_helper_evidence,
            complete_review_helper_evidence,
            incomplete_review_helper_evidence,
            non_review_helper_evidence,
            requires_repair_first,
            clean_review_role_repair_task,
            repair_tasks,
            inherited_evidence_result_ids,
            discarded_payload_refs,
            reason_codes,
            telemetry,
        }
    }

    pub fn repair_task_ids(&self) -> Vec<String> {
        self.repair_tasks
            .iter()
            .map(|task| task.id.clone())
            .collect()
    }

    pub fn allows_side_effect_dispatch(&self) -> bool {
        self.side_effect_dispatch_allowed && !self.requires_repair_first
    }
}

