#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AgentSelfImproveProposalCleanRoomAssignmentState {
    pub assignment_allowed: bool,
    pub side_effects_allowed: bool,
    pub starts_thread: bool,
    pub sends_message: bool,
    pub reads_old_window_payload: bool,
    pub assigns_original_window_follow_up: bool,
    pub evidence_result_ids: Vec<String>,
    pub reason_codes: Vec<String>,
}

impl AgentSelfImproveProposalCleanRoomAssignmentState {
    pub fn from_assignment_report(report: &AgentWindowContextCleanRoomAssignmentReport) -> Self {
        Self {
            assignment_allowed: report.assignment_allowed,
            side_effects_allowed: report.side_effects_allowed,
            starts_thread: report.starts_thread,
            sends_message: report.sends_message,
            reads_old_window_payload: report.reads_old_window_payload,
            assigns_original_window_follow_up: report.assigns_original_window_follow_up,
            evidence_result_ids: report.evidence_result_ids.clone(),
            reason_codes: report.reason_codes.clone(),
        }
    }

    fn preserves_side_effect_boundary(&self) -> bool {
        !self.side_effects_allowed
            && !self.starts_thread
            && !self.sends_message
            && !self.reads_old_window_payload
            && !self.assigns_original_window_follow_up
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AgentSelfImproveProposalPromotionDecision {
    Promote,
    Observe,
    Repair,
}

impl AgentSelfImproveProposalPromotionDecision {
    pub fn as_str(self) -> &'static str {
        match self {
            Self::Promote => "promote",
            Self::Observe => "observe",
            Self::Repair => "repair",
        }
    }

    pub fn can_promote_to_task_queue(self) -> bool {
        self == Self::Promote
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AgentSelfImproveProposalPromotionGate {
    pub report_only: bool,
    pub pure_data_only: bool,
    pub starts_thread: bool,
    pub sends_message: bool,
    pub reads_old_window_payload: bool,
    pub carries_raw_payload: bool,
    pub proposal_id: String,
    pub decision: AgentSelfImproveProposalPromotionDecision,
    pub can_promote_to_task_queue: bool,
    pub required_role: AgentRole,
    pub candidate_queue: AgentTaskQueue,
    pub inherited_evidence_result_ids: Vec<String>,
    pub forbidden_raw_payload_refs: Vec<String>,
    pub side_effect_dispatch_allowed: bool,
    pub reason_codes: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentSelfImproveProposalPromotionGate {
    pub fn decide(
        artifact: &AgentSelfImproveProposalArtifact,
        candidate_task: &AgentTask,
        validation_evidence: &[AgentSelfImproveProposalValidationEvidence],
        assignment_state: &AgentSelfImproveProposalCleanRoomAssignmentState,
    ) -> Self {
        let validation_passed = !validation_evidence.is_empty()
            && validation_evidence.iter().all(|item| item.is_passed());
        let candidate_task_clean = self_improve_candidate_task_is_clean(candidate_task);
        let assignment_side_effect_boundary_preserved =
            assignment_state.preserves_side_effect_boundary();
        let clean_room_assignment_allowed =
            assignment_state.assignment_allowed && assignment_side_effect_boundary_preserved;
        let carries_old_window_payload = artifact.carries_old_window_payload
            || self_improve_task_has_old_window_payload(candidate_task);

        let mut inherited_evidence_result_ids = artifact.evidence_result_ids.clone();
        inherited_evidence_result_ids.extend(
            validation_evidence
                .iter()
                .map(|evidence| evidence.evidence_id.clone()),
        );
        inherited_evidence_result_ids.extend(assignment_state.evidence_result_ids.clone());
        let inherited_evidence_result_ids = dedup_stable(inherited_evidence_result_ids);

        let mut forbidden_raw_payload_refs = artifact.forbidden_raw_payload_refs.clone();
        if self_improve_task_has_old_window_payload(candidate_task) {
            forbidden_raw_payload_refs.push("candidate_task_payload".to_owned());
        }
        let forbidden_raw_payload_refs = dedup_stable(forbidden_raw_payload_refs);

        let mut reason_codes = artifact.reason_codes.clone();
        reason_codes.extend(assignment_state.reason_codes.clone());
        if validation_evidence.is_empty() {
            reason_codes.push("proposal_validation_evidence_missing".to_owned());
        }
        if !validation_evidence.is_empty() && !validation_passed {
            reason_codes.push("proposal_validation_failed".to_owned());
        }
        if !candidate_task_clean {
            reason_codes.push("proposal_candidate_task_not_sanitized".to_owned());
        }
        if carries_old_window_payload {
            reason_codes.push("proposal_old_window_payload_blocked".to_owned());
        }
        if !assignment_state.assignment_allowed {
            reason_codes.push("proposal_clean_room_assignment_not_allowed".to_owned());
        }
        if !assignment_side_effect_boundary_preserved {
            reason_codes
                .push("proposal_clean_room_assignment_side_effect_boundary_open".to_owned());
        }

        let can_promote_to_task_queue = validation_passed
            && candidate_task_clean
            && !carries_old_window_payload
            && clean_room_assignment_allowed;
        let decision = if can_promote_to_task_queue {
            AgentSelfImproveProposalPromotionDecision::Promote
        } else if !validation_passed || carries_old_window_payload || !candidate_task_clean {
            AgentSelfImproveProposalPromotionDecision::Repair
        } else {
            AgentSelfImproveProposalPromotionDecision::Observe
        };
        if can_promote_to_task_queue {
            reason_codes.push("proposal_promotion_allowed".to_owned());
        } else {
            reason_codes.push("proposal_promotion_blocked".to_owned());
        }
        if decision == AgentSelfImproveProposalPromotionDecision::Repair {
            reason_codes.push("proposal_repair_required".to_owned());
        }
        if decision == AgentSelfImproveProposalPromotionDecision::Observe {
            reason_codes.push("proposal_observe_only".to_owned());
        }
        let reason_codes = dedup_stable(reason_codes);

        let required_role = match decision {
            AgentSelfImproveProposalPromotionDecision::Promote => candidate_task.role.clone(),
            AgentSelfImproveProposalPromotionDecision::Repair => AgentRole::Reviewer,
            AgentSelfImproveProposalPromotionDecision::Observe => AgentRole::Reflector,
        };
        let candidate_queue = if can_promote_to_task_queue {
            AgentTaskQueue::from_tasks(vec![candidate_task.clone()])
        } else {
            AgentTaskQueue::new()
        };
        let side_effect_dispatch_allowed = can_promote_to_task_queue;
        let carries_raw_payload = !forbidden_raw_payload_refs.is_empty();
        let telemetry = self_improve_proposal_promotion_gate_telemetry(
            decision,
            can_promote_to_task_queue,
            &required_role,
            validation_evidence.len(),
            validation_passed,
            clean_room_assignment_allowed,
            assignment_side_effect_boundary_preserved,
            candidate_task_clean,
            carries_old_window_payload,
            carries_raw_payload,
            candidate_queue.len(),
            inherited_evidence_result_ids.len(),
            forbidden_raw_payload_refs.len(),
            side_effect_dispatch_allowed,
            reason_codes.len(),
        );

        Self {
            report_only: true,
            pure_data_only: true,
            starts_thread: false,
            sends_message: false,
            reads_old_window_payload: false,
            carries_raw_payload,
            proposal_id: artifact.proposal_id.clone(),
            decision,
            can_promote_to_task_queue,
            required_role,
            candidate_queue,
            inherited_evidence_result_ids,
            forbidden_raw_payload_refs,
            side_effect_dispatch_allowed,
            reason_codes,
            telemetry,
        }
    }
}

