impl AgentCollaborationDispatchPreflightDashboard {
    pub fn from_summaries(summaries: &[AgentCollaborationDispatchPreflightSummary]) -> Self {
        let total_records = summaries.len();
        let dispatchable_records = summaries
            .iter()
            .filter(|summary| summary.can_dispatch_queue && !summary.requires_repair_first)
            .count();
        let side_effect_open_records = summaries
            .iter()
            .filter(|summary| {
                summary.can_open_side_effect_boundary && !summary.requires_repair_first
            })
            .count();
        let repair_first_records = summaries
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let plan_repair_records = summaries
            .iter()
            .filter(|summary| summary.plan_repair_tasks > 0)
            .count();
        let budget_repair_records = summaries
            .iter()
            .filter(|summary| summary.budget_repair_tasks > 0)
            .count();
        let schedule_repair_records = summaries
            .iter()
            .filter(|summary| summary.schedule_repair_tasks > 0)
            .count();
        let total_repair_queue_tasks = summaries
            .iter()
            .map(|summary| summary.repair_queue_tasks)
            .sum::<usize>();
        let total_reasons = summaries
            .iter()
            .map(|summary| summary.reasons)
            .sum::<usize>();
        let total_schedule_waves = summaries
            .iter()
            .map(|summary| summary.schedule_waves)
            .sum::<usize>();
        let dispatch_rate = rate(dispatchable_records, total_records);
        let side_effect_open_rate = rate(side_effect_open_records, total_records);
        let repair_first_rate = rate(repair_first_records, total_records);
        let telemetry = collaboration_dispatch_preflight_dashboard_telemetry(
            total_records,
            dispatchable_records,
            side_effect_open_records,
            repair_first_records,
            plan_repair_records,
            budget_repair_records,
            schedule_repair_records,
            total_repair_queue_tasks,
            total_reasons,
            total_schedule_waves,
            dispatch_rate,
            side_effect_open_rate,
            repair_first_rate,
        );

        Self {
            total_records,
            dispatchable_records,
            side_effect_open_records,
            repair_first_records,
            plan_repair_records,
            budget_repair_records,
            schedule_repair_records,
            total_repair_queue_tasks,
            total_reasons,
            total_schedule_waves,
            dispatch_rate,
            side_effect_open_rate,
            repair_first_rate,
            telemetry,
        }
    }

    pub fn is_empty(&self) -> bool {
        self.total_records == 0
    }

    pub fn health(
        &self,
        policy: AgentCollaborationDispatchPreflightHealthPolicy,
    ) -> AgentCollaborationDispatchPreflightHealth {
        AgentCollaborationDispatchPreflightHealth::from_dashboard(self.clone(), policy)
    }
}

impl AgentCollaborationDispatchPreflightHealth {
    pub fn from_dashboard(
        dashboard: AgentCollaborationDispatchPreflightDashboard,
        policy: AgentCollaborationDispatchPreflightHealthPolicy,
    ) -> Self {
        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();

        if dashboard.is_empty() {
            watch_reasons.push("collaboration_dispatch_preflight_history_empty".to_owned());
        } else {
            if dashboard.dispatch_rate < policy.minimum_dispatch_rate {
                watch_reasons.push(format!(
                    "collaboration_dispatch_preflight_dispatch_rate={:.3}<{}",
                    dashboard.dispatch_rate, policy.minimum_dispatch_rate
                ));
            }
            if dashboard.side_effect_open_rate < policy.minimum_side_effect_open_rate {
                watch_reasons.push(format!(
                    "collaboration_dispatch_preflight_side_effect_open_rate={:.3}<{}",
                    dashboard.side_effect_open_rate, policy.minimum_side_effect_open_rate
                ));
            }
        }

        if dashboard.repair_first_records > policy.maximum_repair_first_records {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_repair_first_records={}>{}",
                dashboard.repair_first_records, policy.maximum_repair_first_records
            ));
        }

        if dashboard.plan_repair_records > policy.maximum_plan_repair_records {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_plan_repair_records={}>{}",
                dashboard.plan_repair_records, policy.maximum_plan_repair_records
            ));
        }

        if dashboard.budget_repair_records > policy.maximum_budget_repair_records {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_budget_repair_records={}>{}",
                dashboard.budget_repair_records, policy.maximum_budget_repair_records
            ));
        }

        if dashboard.schedule_repair_records > policy.maximum_schedule_repair_records {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_schedule_repair_records={}>{}",
                dashboard.schedule_repair_records, policy.maximum_schedule_repair_records
            ));
        }

        if dashboard.total_repair_queue_tasks > policy.maximum_repair_queue_tasks {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_repair_queue_tasks={}>{}",
                dashboard.total_repair_queue_tasks, policy.maximum_repair_queue_tasks
            ));
        }

        if dashboard.total_reasons > policy.maximum_reasons {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_reasons={}>{}",
                dashboard.total_reasons, policy.maximum_reasons
            ));
        }

        let (status, reasons) = if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            (AgentClosedLoopExecutionHealthStatus::Repair, repair_reasons)
        } else if !watch_reasons.is_empty() {
            (AgentClosedLoopExecutionHealthStatus::Watch, watch_reasons)
        } else {
            (AgentClosedLoopExecutionHealthStatus::Stable, Vec::new())
        };

        Self {
            status,
            reasons,
            dashboard,
        }
    }

    pub fn is_stable(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn allows_service_advance(&self) -> bool {
        self.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

