#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationDispatchPreflightHistoryGate;

impl AgentCollaborationDispatchPreflightHistoryGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        preflight: &AgentCollaborationDispatchPreflightRecord,
        history_record: &AgentCollaborationDispatchPreflightSummaryHistoryRecord,
    ) -> AgentCollaborationDispatchPreflightHistoryGateDecision {
        let preflight_summary = preflight.summary();
        let preflight_health = history_record.health.clone();
        let mut reasons = preflight.reasons.clone();
        extend_ordered_unique(
            &mut reasons,
            preflight_health
                .reasons
                .iter()
                .map(|reason| format!("collaboration_dispatch_preflight_history:{reason}"))
                .collect::<Vec<_>>(),
        );
        let requires_repair_first =
            preflight.requires_repair_first || preflight_health.requires_repair_first();
        let can_dispatch_queue = preflight.can_dispatch_queue
            && preflight_health.allows_service_advance()
            && !requires_repair_first;
        let can_open_side_effect_boundary = preflight.can_open_side_effect_boundary
            && preflight_health.allows_service_advance()
            && !requires_repair_first;
        let repair_tasks = collaboration_dispatch_preflight_history_gate_repair_tasks(
            requires_repair_first,
            &reasons,
        );
        let repair_queue =
            collaboration_dispatch_preflight_history_gate_repair_queue(preflight, &repair_tasks);
        let telemetry = collaboration_dispatch_preflight_history_gate_telemetry(
            preflight_health.status,
            can_dispatch_queue,
            can_open_side_effect_boundary,
            requires_repair_first,
            repair_tasks.len(),
            repair_queue.len(),
            reasons.len(),
            &preflight_summary,
        );

        AgentCollaborationDispatchPreflightHistoryGateDecision {
            preflight_summary,
            preflight_health,
            can_dispatch_queue,
            can_open_side_effect_boundary,
            requires_repair_first,
            repair_tasks,
            repair_queue,
            reasons,
            telemetry,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationDispatchPreflightSchedulerHandoff {
    pub requested_queue: AgentTaskQueue,
    pub effective_queue: AgentTaskQueue,
    pub can_dispatch_queue: bool,
    pub can_open_side_effect_boundary: bool,
    pub requires_repair_first: bool,
    pub repair_queue_tasks: usize,
    pub reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationDispatchPreflightSchedulerHandoff {
    pub fn from_gate_record(
        record: &AgentCollaborationDispatchPreflightHistoryGateRecord,
        requested_queue: AgentTaskQueue,
    ) -> Self {
        let repair_tasks = record.gate_decision.repair_queue.tasks();
        let effective_queue = if record.can_dispatch_queue() && !record.requires_repair_first() {
            requested_queue.clone()
        } else {
            requested_queue.clone().with_repair_first(&repair_tasks)
        };
        let repair_queue_tasks = record.gate_decision.repair_queue.len();
        let reasons = record.gate_decision.reasons.clone();
        let immediate_ready_tasks = effective_queue.immediate_ready_tasks().len();
        let telemetry = collaboration_dispatch_preflight_scheduler_handoff_telemetry(
            requested_queue.len(),
            effective_queue.len(),
            immediate_ready_tasks,
            record.can_dispatch_queue(),
            record.can_open_side_effect_boundary(),
            record.requires_repair_first(),
            repair_queue_tasks,
            reasons.len(),
        );

        Self {
            requested_queue,
            effective_queue,
            can_dispatch_queue: record.can_dispatch_queue(),
            can_open_side_effect_boundary: record.can_open_side_effect_boundary(),
            requires_repair_first: record.requires_repair_first(),
            repair_queue_tasks,
            reasons,
            telemetry,
        }
    }

    pub fn immediate_ready_task_ids(&self) -> Vec<String> {
        self.effective_queue
            .immediate_ready_tasks()
            .into_iter()
            .map(|task| task.id)
            .collect()
    }

    pub fn effective_queue_task_ids(&self) -> Vec<String> {
        self.effective_queue.task_ids()
    }

    pub fn requested_queue_task_ids(&self) -> Vec<String> {
        self.requested_queue.task_ids()
    }

    pub fn summary(&self) -> AgentCollaborationDispatchPreflightSchedulerHandoffSummary {
        AgentCollaborationDispatchPreflightSchedulerHandoffSummary::from_handoff(self)
    }
}

