impl AgentCollaborationDispatchPreflightSchedulerHandoffDashboard {
    pub fn from_summaries(
        summaries: &[AgentCollaborationDispatchPreflightSchedulerHandoffSummary],
    ) -> Self {
        let total_records = summaries.len();
        let dispatchable_records = summaries
            .iter()
            .filter(|summary| summary.can_dispatch_queue && !summary.requires_repair_first)
            .count();
        let side_effect_open_records = summaries
            .iter()
            .filter(|summary| {
                summary.can_open_side_effect_boundary && !summary.requires_repair_first
            })
            .count();
        let repair_first_records = summaries
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let substituted_queue_records = summaries
            .iter()
            .filter(|summary| {
                summary.requires_repair_first
                    || summary.effective_queue_tasks != summary.requested_queue_tasks
            })
            .count();
        let requested_queue_tasks = summaries
            .iter()
            .map(|summary| summary.requested_queue_tasks)
            .sum::<usize>();
        let effective_queue_tasks = summaries
            .iter()
            .map(|summary| summary.effective_queue_tasks)
            .sum::<usize>();
        let repair_queue_tasks = summaries
            .iter()
            .map(|summary| summary.repair_queue_tasks)
            .sum::<usize>();
        let reasons = summaries
            .iter()
            .map(|summary| summary.reasons)
            .sum::<usize>();
        let dispatch_rate = rate(dispatchable_records, total_records);
        let side_effect_open_rate = rate(side_effect_open_records, total_records);
        let repair_first_rate = rate(repair_first_records, total_records);
        let substituted_queue_rate = rate(substituted_queue_records, total_records);
        let telemetry = collaboration_dispatch_preflight_scheduler_handoff_dashboard_telemetry(
            total_records,
            dispatchable_records,
            side_effect_open_records,
            repair_first_records,
            substituted_queue_records,
            requested_queue_tasks,
            effective_queue_tasks,
            repair_queue_tasks,
            reasons,
            dispatch_rate,
            side_effect_open_rate,
            repair_first_rate,
            substituted_queue_rate,
        );

        Self {
            total_records,
            dispatchable_records,
            side_effect_open_records,
            repair_first_records,
            substituted_queue_records,
            requested_queue_tasks,
            effective_queue_tasks,
            repair_queue_tasks,
            reasons,
            dispatch_rate,
            side_effect_open_rate,
            repair_first_rate,
            substituted_queue_rate,
            telemetry,
        }
    }

    pub fn is_empty(&self) -> bool {
        self.total_records == 0
    }

    pub fn health(
        &self,
        policy: AgentCollaborationDispatchPreflightSchedulerHandoffHealthPolicy,
    ) -> AgentCollaborationDispatchPreflightSchedulerHandoffHealth {
        AgentCollaborationDispatchPreflightSchedulerHandoffHealth::from_dashboard(
            self.clone(),
            policy,
        )
    }
}

impl AgentCollaborationDispatchPreflightSchedulerHandoffHealth {
    pub fn from_dashboard(
        dashboard: AgentCollaborationDispatchPreflightSchedulerHandoffDashboard,
        policy: AgentCollaborationDispatchPreflightSchedulerHandoffHealthPolicy,
    ) -> Self {
        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();

        if dashboard.is_empty() {
            watch_reasons.push(
                "collaboration_dispatch_preflight_scheduler_handoff_history_empty".to_owned(),
            );
        } else {
            if dashboard.dispatch_rate < policy.minimum_dispatch_rate {
                watch_reasons.push(format!(
                    "collaboration_dispatch_preflight_scheduler_handoff_dispatch_rate={:.3}<{}",
                    dashboard.dispatch_rate, policy.minimum_dispatch_rate
                ));
            }
            if dashboard.side_effect_open_rate < policy.minimum_side_effect_open_rate {
                watch_reasons.push(format!(
                    "collaboration_dispatch_preflight_scheduler_handoff_side_effect_open_rate={:.3}<{}",
                    dashboard.side_effect_open_rate, policy.minimum_side_effect_open_rate
                ));
            }
        }

        if dashboard.repair_first_records > policy.maximum_repair_first_records {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_scheduler_handoff_repair_first_records={}>{}",
                dashboard.repair_first_records, policy.maximum_repair_first_records
            ));
        }

        if dashboard.substituted_queue_records > policy.maximum_substituted_queue_records {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_scheduler_handoff_substituted_queue_records={}>{}",
                dashboard.substituted_queue_records, policy.maximum_substituted_queue_records
            ));
        }

        if dashboard.repair_queue_tasks > policy.maximum_repair_queue_tasks {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_scheduler_handoff_repair_queue_tasks={}>{}",
                dashboard.repair_queue_tasks, policy.maximum_repair_queue_tasks
            ));
        }

        if dashboard.reasons > policy.maximum_reasons {
            repair_reasons.push(format!(
                "collaboration_dispatch_preflight_scheduler_handoff_reasons={}>{}",
                dashboard.reasons, policy.maximum_reasons
            ));
        }

        let (status, reasons) = if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            (AgentClosedLoopExecutionHealthStatus::Repair, repair_reasons)
        } else if !watch_reasons.is_empty() {
            (AgentClosedLoopExecutionHealthStatus::Watch, watch_reasons)
        } else {
            (AgentClosedLoopExecutionHealthStatus::Stable, Vec::new())
        };

        Self {
            status,
            reasons,
            dashboard,
        }
    }

    pub fn is_stable(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn allows_service_advance(&self) -> bool {
        self.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

