#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateDashboard {
    pub total_records: usize,
    pub dispatchable_records: usize,
    pub side_effect_open_records: usize,
    pub repair_first_records: usize,
    pub repair_task_count: usize,
    pub effective_queue_tasks: usize,
    pub reason_count: usize,
    pub latest_handoff_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub dispatchable_rate: f32,
    pub side_effect_open_rate: f32,
    pub repair_first_rate: f32,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateDashboard {
    pub fn from_summaries(
        summaries: &[AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateSummary],
    ) -> Self {
        let total_records = summaries.len();
        let dispatchable_records = summaries
            .iter()
            .filter(|summary| summary.can_dispatch_queue && !summary.requires_repair_first)
            .count();
        let side_effect_open_records = summaries
            .iter()
            .filter(|summary| {
                summary.can_open_side_effect_boundary && !summary.requires_repair_first
            })
            .count();
        let repair_first_records = summaries
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let repair_task_count = summaries
            .iter()
            .map(|summary| summary.repair_tasks)
            .sum::<usize>();
        let effective_queue_tasks = summaries
            .iter()
            .map(|summary| summary.effective_queue_tasks)
            .sum::<usize>();
        let reason_count = summaries
            .iter()
            .map(|summary| summary.reasons.len())
            .sum::<usize>();
        let latest_handoff_health_status = summaries
            .last()
            .map(|summary| summary.handoff_health_status);
        let dispatchable_rate = rate(dispatchable_records, total_records);
        let side_effect_open_rate = rate(side_effect_open_records, total_records);
        let repair_first_rate = rate(repair_first_records, total_records);
        let telemetry =
            collaboration_dispatch_preflight_scheduler_handoff_history_gate_dashboard_telemetry(
                total_records,
                dispatchable_records,
                side_effect_open_records,
                repair_first_records,
                repair_task_count,
                effective_queue_tasks,
                reason_count,
                dispatchable_rate,
                side_effect_open_rate,
                repair_first_rate,
            );

        Self {
            total_records,
            dispatchable_records,
            side_effect_open_records,
            repair_first_records,
            repair_task_count,
            effective_queue_tasks,
            reason_count,
            latest_handoff_health_status,
            dispatchable_rate,
            side_effect_open_rate,
            repair_first_rate,
            telemetry,
        }
    }

    pub fn is_empty(&self) -> bool {
        self.total_records == 0
    }

    pub fn health(
        &self,
        policy: AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateHealthPolicy,
    ) -> AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateHealth {
        AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateHealth::from_dashboard(
            self.clone(),
            policy,
        )
    }
}

