#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateTrendGate;

impl AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateTrendGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        gate_record: &AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateRecord,
        trend_record: &AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateSummaryHistoryRecord,
    ) -> AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateTrendGateDecision {
        let current_gate_summary = gate_record.summary();
        let trend_health = trend_record.health.clone();
        let mut reasons = gate_record.gate_decision.reasons.clone();
        extend_ordered_unique(
            &mut reasons,
            trend_health
                .reasons
                .iter()
                .map(|reason| {
                    format!(
                        "collaboration_dispatch_preflight_scheduler_handoff_history_gate_trend:{reason}"
                    )
                })
                .collect::<Vec<_>>(),
        );
        let requires_repair_first =
            gate_record.requires_repair_first() || trend_health.requires_repair_first();
        let can_dispatch_queue = gate_record.can_dispatch_queue()
            && trend_health.allows_service_advance()
            && !requires_repair_first;
        let can_open_side_effect_boundary = gate_record.can_open_side_effect_boundary()
            && trend_health.allows_service_advance()
            && !requires_repair_first;
        let repair_tasks =
            collaboration_dispatch_preflight_scheduler_handoff_history_gate_trend_gate_repair_tasks(
                requires_repair_first,
                &reasons,
            );
        let effective_queue =
            collaboration_dispatch_preflight_scheduler_handoff_history_gate_trend_gate_effective_queue(
                gate_record,
                requires_repair_first,
                &repair_tasks,
            );
        let telemetry =
            collaboration_dispatch_preflight_scheduler_handoff_history_gate_trend_gate_telemetry(
                trend_health.status,
                can_dispatch_queue,
                can_open_side_effect_boundary,
                requires_repair_first,
                repair_tasks.len(),
                effective_queue.len(),
                reasons.len(),
                &current_gate_summary,
            );

        AgentCollaborationDispatchPreflightSchedulerHandoffHistoryGateTrendGateDecision {
            current_gate_summary,
            trend_health,
            effective_queue,
            can_dispatch_queue,
            can_open_side_effect_boundary,
            requires_repair_first,
            repair_tasks,
            reasons,
            telemetry,
        }
    }
}

