#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationDispatchPreflight;

impl AgentCollaborationDispatchPreflight {
    pub fn new() -> Self {
        Self
    }

    #[allow(clippy::too_many_arguments)]
    pub fn record_and_gate(
        &self,
        plan: &AgentCollaborationPlan,
        plan_history: AgentCollaborationPlanSummaryHistory,
        plan_gate_policy: AgentCollaborationPlanGatePolicy,
        plan_health_policy: AgentCollaborationPlanHealthPolicy,
        budget_history: BudgetLedgerSummaryHistory,
        budget_health_policy: BudgetLedgerHealthPolicy,
        schedule_history: RecursiveAgentScheduleSummaryHistory,
        schedule_health_policy: RecursiveAgentScheduleHealthPolicy,
        max_parallel_tasks: usize,
    ) -> AgentCollaborationDispatchPreflightRecord {
        let plan_record = AgentCollaborationPlanSummaryHistoryRecorder::new()
            .record_plan_with_health_gate(plan_history, plan, plan_gate_policy, plan_health_policy);
        let budget_record = BudgetLedgerSummaryHistoryRecorder::new()
            .record_ledger_with_health_gate(
                budget_history,
                &plan.budget_ledger,
                budget_health_policy,
            );
        let schedule = RecursiveAgentScheduler::new(max_parallel_tasks).plan(plan.queue.tasks());
        let schedule_record = RecursiveAgentScheduleSummaryHistoryRecorder::new()
            .record_schedule_with_health_gate(schedule_history, &schedule, schedule_health_policy);

        collaboration_dispatch_preflight_from_records(plan_record, budget_record, schedule_record)
    }
}

fn collaboration_dispatch_preflight_from_records(
    plan_record: AgentCollaborationPlanHistoryGateRecord,
    budget_record: BudgetLedgerHistoryGateRecord,
    schedule_record: RecursiveAgentScheduleHistoryGateRecord,
) -> AgentCollaborationDispatchPreflightRecord {
    let requires_repair_first = plan_record.requires_repair_first()
        || budget_record.requires_repair_first()
        || schedule_record.requires_repair_first();
    let can_dispatch_queue = plan_record.can_dispatch_queue()
        && budget_record.can_dispatch_tasks()
        && schedule_record.gate_decision.can_dispatch_waves
        && !requires_repair_first;
    let can_open_side_effect_boundary = plan_record.can_open_side_effect_boundary()
        && budget_record.can_promote_side_effects()
        && schedule_record.gate_decision.can_dispatch_waves
        && !requires_repair_first;
    let reasons =
        collaboration_dispatch_preflight_reasons(&plan_record, &budget_record, &schedule_record);
    let repair_queue = collaboration_dispatch_preflight_repair_queue(
        &plan_record,
        &budget_record,
        &schedule_record,
    );
    let telemetry = collaboration_dispatch_preflight_telemetry(
        can_dispatch_queue,
        can_open_side_effect_boundary,
        requires_repair_first,
        repair_queue.len(),
        reasons.len(),
        &plan_record,
        &budget_record,
        &schedule_record,
    );

    AgentCollaborationDispatchPreflightRecord {
        plan_record,
        budget_record,
        schedule_record,
        can_dispatch_queue,
        can_open_side_effect_boundary,
        requires_repair_first,
        repair_queue,
        reasons,
        telemetry,
    }
}

#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationPlanner;

impl AgentCollaborationPlanner {
    pub fn new() -> Self {
        Self
    }

    pub fn plan(&self, windows: Vec<AgentWindowSpec>) -> AgentCollaborationPlan {
        let mut seen_windows = BTreeSet::new();
        let mut seen_budget_roles = BTreeSet::new();
        let mut queue = AgentTaskQueue::new();
        let mut budget_ledger = BudgetLedger::new();
        let mut active_windows = Vec::new();
        let mut duplicate_windows = Vec::new();
        let mut shared_budget_roles = Vec::new();
        let mut blocked_reasons = Vec::new();

        for window in windows {
            if !seen_windows.insert(window.window_id.clone()) {
                duplicate_windows.push(window.window_id.clone());
                blocked_reasons.push(format!("duplicate_window={}", window.window_id));
                continue;
            }
            if !seen_budget_roles.insert(window.role.clone()) {
                shared_budget_roles.push(window.role.as_str().to_owned());
                blocked_reasons.push(format!("shared_budget_role={}", window.role.as_str()));
                continue;
            }

            budget_ledger.set_budget(window.role.clone(), window.budget);
            active_windows.push(window.window_id.clone());
            queue.push(window.task());
        }

        let telemetry = collaboration_plan_telemetry(
            queue.len(),
            active_windows.len(),
            duplicate_windows.len(),
            shared_budget_roles.len(),
            blocked_reasons.len(),
        );

        AgentCollaborationPlan {
            queue,
            budget_ledger,
            active_windows,
            duplicate_windows,
            shared_budget_roles,
            blocked_reasons,
            telemetry,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationReview {
    pub summary: AgentCycleSummary,
    pub handoff: AgentCycleHandoff,
    pub adapter_boundary_summary: AgentAdapterBoundarySummary,
    pub adapter_boundary_blocked_reasons: Vec<String>,
    pub memory_gate: Option<SideEffectGate>,
    pub adaptive_state_gate: Option<SideEffectGate>,
    pub can_submit_memory: bool,
    pub can_write_adaptive_state: bool,
    pub blocked_reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationReview {
    pub fn from_report(report: &AgentCycleReport) -> Self {
        let summary = AgentCycleSummary::from_report(report);
        let handoff = AgentCycleHandoff::from_report(report);
        let adapter_boundary =
            AgentAdapterBoundarySnapshot::from_cycle_report(&AgentTaskQueue::new(), report);
        let adapter_boundary_summary = adapter_boundary.summary();
        let adapter_boundary_blocked_reasons = adapter_boundary.blocked_reasons.clone();
        let memory_gate = report
            .run_report
            .side_effects
            .iter()
            .find(|gate| gate.kind == SideEffectKind::MemoryNote)
            .cloned();
        let adaptive_state_gate = report
            .run_report
            .side_effects
            .iter()
            .find(|gate| gate.kind == SideEffectKind::AdaptiveStateWrite)
            .cloned();
        let can_submit_memory = adapter_boundary_summary.can_submit_memory_note
            && handoff.can_submit_memory()
            && memory_gate.as_ref().is_some_and(|gate| gate.allowed);
        let can_write_adaptive_state = adapter_boundary_summary.can_promote_adaptive_state
            && summary.ready_for_memory_promotion()
            && adaptive_state_gate
                .as_ref()
                .is_some_and(|gate| gate.allowed);
        let blocked_reasons = collaboration_review_blockers(
            &handoff,
            &adapter_boundary_blocked_reasons,
            memory_gate.as_ref(),
            adaptive_state_gate.as_ref(),
        );
        let telemetry = collaboration_review_telemetry(
            &summary,
            &adapter_boundary_summary,
            can_submit_memory,
            can_write_adaptive_state,
            blocked_reasons.len(),
        );

        Self {
            summary,
            handoff,
            adapter_boundary_summary,
            adapter_boundary_blocked_reasons,
            memory_gate,
            adaptive_state_gate,
            can_submit_memory,
            can_write_adaptive_state,
            blocked_reasons,
            telemetry,
        }
    }
}

