#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationBusinessLoopPlan {
    pub business_plan: AgentBusinessLoopPlan,
    pub collaboration_dashboard: AgentCollaborationDashboard,
    pub collaboration_health: AgentCollaborationHealth,
    pub effective_status: AgentCycleLedgerAdmissionStatus,
    pub adaptive_state_candidate: Option<AdaptiveStateCandidate>,
    pub repair_tasks: Vec<AgentTask>,
    pub blocked_reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationBusinessLoopPlan {
    pub fn can_promote_adaptive_state(&self) -> bool {
        self.effective_status == AgentCycleLedgerAdmissionStatus::Promote
            && self.adaptive_state_candidate.is_some()
            && self.collaboration_health.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn requires_repair_first(&self) -> bool {
        self.effective_status == AgentCycleLedgerAdmissionStatus::Repair
            || !self.repair_tasks.is_empty()
    }

    pub fn allows_service_advance(&self) -> bool {
        !self.requires_repair_first()
    }

    pub fn summary(&self) -> AgentCollaborationBusinessLoopSummary {
        AgentCollaborationBusinessLoopSummary::from_plan(self)
    }

    pub fn effective_business_plan(&self) -> AgentBusinessLoopPlan {
        let mut admission = self.business_plan.admission.clone();
        admission.status = self.effective_status;
        admission.reasons = self.blocked_reasons.clone();

        let mut next_queue = self.business_plan.next_queue.clone();
        for task in &self.repair_tasks {
            next_queue.push(task.clone());
        }

        AgentBusinessLoopPlan {
            admission,
            next_queue,
            adaptive_state_candidate: self.adaptive_state_candidate.clone(),
            telemetry: self.telemetry.clone(),
        }
    }

    pub fn close_service_execution(
        &self,
        run_id: impl AsRef<str>,
        receipts: Vec<AgentServiceCommandReceipt>,
    ) -> AgentCollaborationServiceExecutionReport {
        AgentCollaborationServiceExecutionCloser::new().close(run_id, self, receipts)
    }
}

