#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationBusinessLoopPlanner {
    business_controller: AgentBusinessLoopController,
}

impl AgentCollaborationBusinessLoopPlanner {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn plan(
        &self,
        ledger: &AgentCycleLedger,
        ledger_policy: AgentCycleLedgerPolicy,
        collaboration_history: &AgentCollaborationReviewHistory,
        collaboration_policy: AgentCollaborationHealthPolicy,
    ) -> AgentCollaborationBusinessLoopPlan {
        let business_plan = self.business_controller.plan(ledger, ledger_policy);
        let collaboration_dashboard = collaboration_history.dashboard();
        let collaboration_health = collaboration_dashboard.health(collaboration_policy);
        let effective_status =
            effective_business_status(business_plan.status(), collaboration_health.status);
        let adaptive_state_candidate =
            if effective_status == AgentCycleLedgerAdmissionStatus::Promote {
                business_plan.adaptive_state_candidate.clone()
            } else {
                None
            };
        let repair_tasks = collaboration_repair_tasks(&collaboration_health);
        let blocked_reasons = collaboration_business_loop_blockers(
            &business_plan,
            &collaboration_health,
            effective_status,
        );
        let telemetry = collaboration_business_loop_telemetry(
            &business_plan,
            &collaboration_health,
            effective_status,
            repair_tasks.len(),
            blocked_reasons.len(),
        );

        AgentCollaborationBusinessLoopPlan {
            business_plan,
            collaboration_dashboard,
            collaboration_health,
            effective_status,
            adaptive_state_candidate,
            repair_tasks,
            blocked_reasons,
            telemetry,
        }
    }
}

