#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationServiceExecutionDashboard {
    pub total_executions: usize,
    pub clean_executions: usize,
    pub dirty_executions: usize,
    pub adaptive_promotion_executions: usize,
    pub repair_mode_executions: usize,
    pub command_reason_count: usize,
    pub memory_promotion_command_reason_count: usize,
    pub memory_promotion_command_reason_executions: usize,
    pub tool_build_command_reason_count: usize,
    pub tool_build_command_reason_executions: usize,
    pub rust_validation_command_count: usize,
    pub rust_validation_command_executions: usize,
    pub blocked_executions: usize,
    pub queued_follow_up_executions: usize,
    pub total_next_queue_len: usize,
    pub clean_rate: f32,
    pub dirty_rate: f32,
    pub adaptive_promotion_rate: f32,
    pub repair_mode_rate: f32,
    pub blocked_rate: f32,
    pub queued_follow_up_rate: f32,
    pub latest_effective_status: Option<AgentCycleLedgerAdmissionStatus>,
    pub latest_collaboration_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub latest_clean: Option<bool>,
}

impl AgentCollaborationServiceExecutionDashboard {
    pub fn from_history(history: &AgentCollaborationServiceExecutionHistory) -> Self {
        let total_executions = history.summaries.len();
        let clean_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.clean)
            .count();
        let dirty_executions = total_executions.saturating_sub(clean_executions);
        let adaptive_promotion_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.can_promote_adaptive_state)
            .count();
        let repair_mode_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.repair_mode_requested)
            .count();
        let command_reason_count = history
            .summaries
            .iter()
            .map(|summary| summary.command_reason_count)
            .sum::<usize>();
        let memory_promotion_command_reason_count = history
            .summaries
            .iter()
            .map(|summary| summary.memory_promotion_command_reason_count)
            .sum::<usize>();
        let memory_promotion_command_reason_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.memory_promotion_command_reason_count > 0)
            .count();
        let tool_build_command_reason_count = history
            .summaries
            .iter()
            .map(|summary| summary.tool_build_command_reason_count)
            .sum::<usize>();
        let tool_build_command_reason_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.tool_build_command_reason_count > 0)
            .count();
        let rust_validation_command_count = history
            .summaries
            .iter()
            .map(|summary| summary.rust_validation_command_count)
            .sum::<usize>();
        let rust_validation_command_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.rust_validation_command_count > 0)
            .count();
        let blocked_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.blocked_reasons > 0)
            .count();
        let queued_follow_up_executions = history
            .summaries
            .iter()
            .filter(|summary| summary.next_queue_len > 0)
            .count();
        let total_next_queue_len = history
            .summaries
            .iter()
            .map(|summary| summary.next_queue_len)
            .sum();
        let latest = history.summaries.last();

        Self {
            total_executions,
            clean_executions,
            dirty_executions,
            adaptive_promotion_executions,
            repair_mode_executions,
            command_reason_count,
            memory_promotion_command_reason_count,
            memory_promotion_command_reason_executions,
            tool_build_command_reason_count,
            tool_build_command_reason_executions,
            rust_validation_command_count,
            rust_validation_command_executions,
            blocked_executions,
            queued_follow_up_executions,
            total_next_queue_len,
            clean_rate: rate(clean_executions, total_executions),
            dirty_rate: rate(dirty_executions, total_executions),
            adaptive_promotion_rate: rate(adaptive_promotion_executions, total_executions),
            repair_mode_rate: rate(repair_mode_executions, total_executions),
            blocked_rate: rate(blocked_executions, total_executions),
            queued_follow_up_rate: rate(queued_follow_up_executions, total_executions),
            latest_effective_status: latest.map(|summary| summary.effective_status),
            latest_collaboration_health_status: latest
                .map(|summary| summary.collaboration_health_status),
            latest_clean: latest.map(|summary| summary.clean),
        }
    }

    pub fn is_empty(&self) -> bool {
        self.total_executions == 0
    }

    pub fn health(
        &self,
        policy: AgentCollaborationServiceExecutionHealthPolicy,
    ) -> AgentCollaborationServiceExecutionHealth {
        AgentCollaborationServiceExecutionHealth::from_dashboard(self, policy)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
