#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionPlan {
    pub collaboration_plan: AgentCollaborationBusinessLoopPlan,
    pub service_execution_dashboard: AgentCollaborationServiceExecutionDashboard,
    pub service_execution_health: AgentCollaborationServiceExecutionHealth,
    pub final_status: AgentCycleLedgerAdmissionStatus,
    pub adaptive_state_candidate: Option<AdaptiveStateCandidate>,
    pub next_queue: AgentTaskQueue,
    pub repair_tasks: Vec<AgentTask>,
    pub blocked_reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationSelfEvolutionPlan {
    pub fn can_promote_adaptive_state(&self) -> bool {
        self.final_status == AgentCycleLedgerAdmissionStatus::Promote
            && self.adaptive_state_candidate.is_some()
            && self.service_execution_health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && self.collaboration_plan.can_promote_adaptive_state()
    }

    pub fn requires_repair_first(&self) -> bool {
        self.final_status == AgentCycleLedgerAdmissionStatus::Repair
            || !self.repair_tasks.is_empty()
            || self.collaboration_plan.requires_repair_first()
    }

    pub fn allows_service_advance(&self) -> bool {
        !self.requires_repair_first()
    }

    pub fn effective_business_plan(&self) -> AgentBusinessLoopPlan {
        let mut plan = self.collaboration_plan.effective_business_plan();
        plan.admission.status = self.final_status;
        plan.admission.reasons = self.blocked_reasons.clone();
        plan.adaptive_state_candidate = self.adaptive_state_candidate.clone();
        plan.next_queue = self.next_queue.clone();
        plan.telemetry = self.telemetry.clone();
        plan
    }

    pub fn summary(&self) -> AgentCollaborationSelfEvolutionSummary {
        AgentCollaborationSelfEvolutionSummary::from_plan(self)
    }
}

