#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionCloseDashboard {
    pub total_closes: usize,
    pub service_clean_closes: usize,
    pub service_dirty_closes: usize,
    pub promotable_closes: usize,
    pub repair_first_closes: usize,
    pub final_repair_closes: usize,
    pub blocked_closes: usize,
    pub queued_follow_up_closes: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_rust_validation_command_count: usize,
    pub service_execution_rust_validation_command_closes: usize,
    pub total_next_queue_len: usize,
    pub service_clean_rate: f32,
    pub service_dirty_rate: f32,
    pub promotion_rate: f32,
    pub repair_first_rate: f32,
    pub final_repair_rate: f32,
    pub blocked_rate: f32,
    pub queued_follow_up_rate: f32,
    pub latest_final_status: Option<AgentCycleLedgerAdmissionStatus>,
    pub latest_service_execution_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub latest_can_promote_adaptive_state: Option<bool>,
}

impl AgentCollaborationSelfEvolutionCloseDashboard {
    pub fn from_history(history: &AgentCollaborationSelfEvolutionCloseHistory) -> Self {
        let total_closes = history.summaries.len();
        let service_clean_closes = history
            .summaries
            .iter()
            .filter(|summary| summary.service_clean)
            .count();
        let service_dirty_closes = total_closes.saturating_sub(service_clean_closes);
        let promotable_closes = history
            .summaries
            .iter()
            .filter(|summary| summary.can_promote_adaptive_state)
            .count();
        let repair_first_closes = history
            .summaries
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let final_repair_closes = history
            .summaries
            .iter()
            .filter(|summary| summary.final_status == AgentCycleLedgerAdmissionStatus::Repair)
            .count();
        let blocked_closes = history
            .summaries
            .iter()
            .filter(|summary| summary.blocked_reasons > 0)
            .count();
        let queued_follow_up_closes = history
            .summaries
            .iter()
            .filter(|summary| summary.next_queue_len > 0)
            .count();
        let service_execution_command_reason_count = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum::<usize>();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum::<usize>();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries
            .iter()
            .filter(|summary| {
                summary.service_execution_memory_promotion_command_reason_executions > 0
            })
            .count();
        let service_execution_rust_validation_command_count = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_count)
            .sum::<usize>();
        let service_execution_rust_validation_command_closes = history
            .summaries
            .iter()
            .filter(|summary| summary.service_execution_rust_validation_command_executions > 0)
            .count();
        let total_next_queue_len = history
            .summaries
            .iter()
            .map(|summary| summary.next_queue_len)
            .sum();
        let latest = history.summaries.last();

        Self {
            total_closes,
            service_clean_closes,
            service_dirty_closes,
            promotable_closes,
            repair_first_closes,
            final_repair_closes,
            blocked_closes,
            queued_follow_up_closes,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_rust_validation_command_count,
            service_execution_rust_validation_command_closes,
            total_next_queue_len,
            service_clean_rate: rate(service_clean_closes, total_closes),
            service_dirty_rate: rate(service_dirty_closes, total_closes),
            promotion_rate: rate(promotable_closes, total_closes),
            repair_first_rate: rate(repair_first_closes, total_closes),
            final_repair_rate: rate(final_repair_closes, total_closes),
            blocked_rate: rate(blocked_closes, total_closes),
            queued_follow_up_rate: rate(queued_follow_up_closes, total_closes),
            latest_final_status: latest.map(|summary| summary.final_status),
            latest_service_execution_health_status: latest
                .map(|summary| summary.service_execution_health_status),
            latest_can_promote_adaptive_state: latest
                .map(|summary| summary.can_promote_adaptive_state),
        }
    }

    pub fn is_empty(&self) -> bool {
        self.total_closes == 0
    }

    pub fn health(
        &self,
        policy: AgentCollaborationSelfEvolutionCloseHealthPolicy,
    ) -> AgentCollaborationSelfEvolutionCloseHealth {
        AgentCollaborationSelfEvolutionCloseHealth::from_dashboard(self, policy)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSelfEvolutionCloseHealthPolicy {
    pub minimum_service_clean_rate: f32,
    pub minimum_promotion_rate: f32,
    pub maximum_service_dirty_rate: f32,
    pub maximum_repair_first_rate: f32,
    pub maximum_final_repair_rate: f32,
    pub maximum_blocked_rate: f32,
}

impl Default for AgentCollaborationSelfEvolutionCloseHealthPolicy {
    fn default() -> Self {
        Self {
            minimum_service_clean_rate: 0.67,
            minimum_promotion_rate: 0.50,
            maximum_service_dirty_rate: 0.0,
            maximum_repair_first_rate: 0.34,
            maximum_final_repair_rate: 0.0,
            maximum_blocked_rate: 0.34,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionCloseHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSelfEvolutionCloseHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationSelfEvolutionCloseDashboard,
        policy: AgentCollaborationSelfEvolutionCloseHealthPolicy,
    ) -> Self {
        if dashboard.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec!["no_collaboration_self_evolution_closes".to_owned()],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();

        if dashboard.service_dirty_rate > policy.maximum_service_dirty_rate {
            repair_reasons.push(format!(
                "self_evolution_close_service_dirty_rate={:.3}>{:.3}",
                dashboard.service_dirty_rate, policy.maximum_service_dirty_rate
            ));
        }
        if dashboard.final_repair_rate > policy.maximum_final_repair_rate {
            repair_reasons.push(format!(
                "self_evolution_close_final_repair_rate={:.3}>{:.3}",
                dashboard.final_repair_rate, policy.maximum_final_repair_rate
            ));
        }
        if dashboard.service_clean_rate < policy.minimum_service_clean_rate {
            watch_reasons.push(format!(
                "self_evolution_close_service_clean_rate={:.3}<{:.3}",
                dashboard.service_clean_rate, policy.minimum_service_clean_rate
            ));
        }
        if dashboard.promotion_rate < policy.minimum_promotion_rate {
            watch_reasons.push(format!(
                "self_evolution_close_promotion_rate={:.3}<{:.3}",
                dashboard.promotion_rate, policy.minimum_promotion_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            watch_reasons.push(format!(
                "self_evolution_close_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.blocked_rate > policy.maximum_blocked_rate {
            watch_reasons.push(format!(
                "self_evolution_close_blocked_rate={:.3}>{:.3}",
                dashboard.blocked_rate, policy.maximum_blocked_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }
}

