#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionControlDashboard {
    pub total_controls: usize,
    pub continue_controls: usize,
    pub observe_controls: usize,
    pub repair_controls: usize,
    pub idle_controls: usize,
    pub schedulable_controls: usize,
    pub adaptive_allowed_controls: usize,
    pub repair_first_controls: usize,
    pub total_next_queue_len: usize,
    pub schedule_rate: f32,
    pub adaptive_allowed_rate: f32,
    pub repair_first_rate: f32,
    pub observe_rate: f32,
    pub repair_rate: f32,
    pub idle_rate: f32,
    pub latest_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub latest_allows_adaptive_evolution: Option<bool>,
}

impl AgentCollaborationSelfEvolutionControlDashboard {
    pub fn from_history(history: &AgentCollaborationSelfEvolutionControlHistory) -> Self {
        let total_controls = history.summaries.len();
        let continue_controls = history
            .summaries
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Continue)
            .count();
        let observe_controls = history
            .summaries
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Observe)
            .count();
        let repair_controls = history
            .summaries
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Repair)
            .count();
        let idle_controls = history
            .summaries
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Idle)
            .count();
        let schedulable_controls = history
            .summaries
            .iter()
            .filter(|summary| summary.can_schedule)
            .count();
        let adaptive_allowed_controls = history
            .summaries
            .iter()
            .filter(|summary| summary.allows_adaptive_evolution)
            .count();
        let repair_first_controls = history
            .summaries
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let total_next_queue_len = history
            .summaries
            .iter()
            .map(|summary| summary.next_queue_len)
            .sum();
        let latest = history.summaries.last();

        Self {
            total_controls,
            continue_controls,
            observe_controls,
            repair_controls,
            idle_controls,
            schedulable_controls,
            adaptive_allowed_controls,
            repair_first_controls,
            total_next_queue_len,
            schedule_rate: rate(schedulable_controls, total_controls),
            adaptive_allowed_rate: rate(adaptive_allowed_controls, total_controls),
            repair_first_rate: rate(repair_first_controls, total_controls),
            observe_rate: rate(observe_controls, total_controls),
            repair_rate: rate(repair_controls, total_controls),
            idle_rate: rate(idle_controls, total_controls),
            latest_mode: latest.map(|summary| summary.mode),
            latest_health_status: latest.map(|summary| summary.health_status),
            latest_allows_adaptive_evolution: latest
                .map(|summary| summary.allows_adaptive_evolution),
        }
    }

    pub fn is_empty(&self) -> bool {
        self.total_controls == 0
    }

    pub fn health(
        &self,
        policy: AgentCollaborationSelfEvolutionControlHealthPolicy,
    ) -> AgentCollaborationSelfEvolutionControlHealth {
        AgentCollaborationSelfEvolutionControlHealth::from_dashboard(self, policy)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSelfEvolutionControlHealthPolicy {
    pub minimum_schedule_rate: f32,
    pub minimum_adaptive_allowed_rate: f32,
    pub maximum_observe_rate: f32,
    pub maximum_repair_rate: f32,
    pub maximum_idle_rate: f32,
    pub maximum_repair_first_rate: f32,
}

impl Default for AgentCollaborationSelfEvolutionControlHealthPolicy {
    fn default() -> Self {
        Self {
            minimum_schedule_rate: 0.67,
            minimum_adaptive_allowed_rate: 0.50,
            maximum_observe_rate: 0.67,
            maximum_repair_rate: 0.0,
            maximum_idle_rate: 0.67,
            maximum_repair_first_rate: 0.0,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionControlHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSelfEvolutionControlHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationSelfEvolutionControlDashboard,
        policy: AgentCollaborationSelfEvolutionControlHealthPolicy,
    ) -> Self {
        if dashboard.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec!["no_collaboration_self_evolution_controls".to_owned()],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();

        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "self_evolution_control_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "self_evolution_control_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.schedule_rate < policy.minimum_schedule_rate {
            watch_reasons.push(format!(
                "self_evolution_control_schedule_rate={:.3}<{:.3}",
                dashboard.schedule_rate, policy.minimum_schedule_rate
            ));
        }
        if dashboard.adaptive_allowed_rate < policy.minimum_adaptive_allowed_rate {
            watch_reasons.push(format!(
                "self_evolution_control_adaptive_allowed_rate={:.3}<{:.3}",
                dashboard.adaptive_allowed_rate, policy.minimum_adaptive_allowed_rate
            ));
        }
        if dashboard.observe_rate > policy.maximum_observe_rate {
            watch_reasons.push(format!(
                "self_evolution_control_observe_rate={:.3}>{:.3}",
                dashboard.observe_rate, policy.maximum_observe_rate
            ));
        }
        if dashboard.idle_rate > policy.maximum_idle_rate {
            watch_reasons.push(format!(
                "self_evolution_control_idle_rate={:.3}>{:.3}",
                dashboard.idle_rate, policy.maximum_idle_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }
}

