impl AgentCollaborationSelfEvolutionControlGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        record: &AgentCollaborationSelfEvolutionControlMonitorRecord,
    ) -> AgentCollaborationSelfEvolutionControlGateDecision {
        let requested_mode = record.control_plan.mode;
        let control_health = record.control_history_record.health.clone();
        let effective_mode = collaboration_self_evolution_control_gate_mode(
            requested_mode,
            control_health.status,
            record.control_plan.next_queue.is_empty(),
        );
        let reasons = collaboration_self_evolution_control_gate_reasons(
            &record.control_plan.reasons,
            &control_health,
        );
        let next_queue = record.control_plan.next_queue.clone();
        let telemetry = collaboration_self_evolution_control_gate_telemetry(
            requested_mode,
            effective_mode,
            &control_health,
            &next_queue,
            reasons.len(),
        );

        AgentCollaborationSelfEvolutionControlGateDecision {
            requested_mode,
            effective_mode,
            control_health,
            next_queue,
            reasons,
            telemetry,
        }
    }
}

