#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceCommandAdmission {
    pub effective_mode: AgentClosedLoopNextTurnMode,
    pub can_plan_service_commands: bool,
    pub allows_adaptive_evolution: bool,
    pub requires_repair_first: bool,
    pub reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationSelfEvolutionServiceCommandAdmission {
    pub fn from_handoff(record: &AgentCollaborationSelfEvolutionServiceHandoffRecord) -> Self {
        let can_plan_service_commands = record.can_schedule();
        let allows_adaptive_evolution = record.allows_adaptive_evolution();
        let requires_repair_first = record.requires_repair_first();
        let mut reasons = record.control_handoff_record.gate_decision.reasons.clone();
        if !can_plan_service_commands {
            reasons.push("self_evolution_service_handoff_not_schedulable".to_owned());
        }
        if requires_repair_first {
            reasons.push("self_evolution_service_handoff_repair_first".to_owned());
        }
        let telemetry = collaboration_self_evolution_service_command_admission_telemetry(
            record.effective_mode(),
            can_plan_service_commands,
            allows_adaptive_evolution,
            requires_repair_first,
            reasons.len(),
        );

        Self {
            effective_mode: record.effective_mode(),
            can_plan_service_commands,
            allows_adaptive_evolution,
            requires_repair_first,
            reasons,
            telemetry,
        }
    }
}

