#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionCloseAndAdmitDashboard {
    pub total_records: usize,
    pub clean_service_records: usize,
    pub command_plannable_records: usize,
    pub adaptive_allowed_records: usize,
    pub repair_first_records: usize,
    pub idle_records: usize,
    pub repair_records: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_rust_validation_command_count: usize,
    pub service_execution_rust_validation_command_closes: usize,
    pub clean_service_rate: f32,
    pub command_plan_rate: f32,
    pub adaptive_allowed_rate: f32,
    pub repair_first_rate: f32,
    pub idle_rate: f32,
    pub repair_rate: f32,
    pub latest_effective_mode: Option<AgentClosedLoopNextTurnMode>,
}

impl AgentCollaborationSelfEvolutionCloseAndAdmitDashboard {
    pub fn from_history(history: &AgentCollaborationSelfEvolutionCloseAndAdmitHistory) -> Self {
        let total_records = history.summaries.len();
        let clean_service_records = history
            .summaries
            .iter()
            .filter(|summary| summary.service_clean)
            .count();
        let command_plannable_records = history
            .summaries
            .iter()
            .filter(|summary| summary.can_plan_service_commands)
            .count();
        let adaptive_allowed_records = history
            .summaries
            .iter()
            .filter(|summary| summary.allows_adaptive_evolution)
            .count();
        let repair_first_records = history
            .summaries
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let idle_records = history
            .summaries
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Idle)
            .count();
        let repair_records = history
            .summaries
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Repair)
            .count();
        let service_execution_command_reason_count = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_closes)
            .sum();
        let service_execution_rust_validation_command_count = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_count)
            .sum();
        let service_execution_rust_validation_command_closes = history
            .summaries
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_closes)
            .sum();
        let latest = history.summaries.last();

        Self {
            total_records,
            clean_service_records,
            command_plannable_records,
            adaptive_allowed_records,
            repair_first_records,
            idle_records,
            repair_records,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_rust_validation_command_count,
            service_execution_rust_validation_command_closes,
            clean_service_rate: rate(clean_service_records, total_records),
            command_plan_rate: rate(command_plannable_records, total_records),
            adaptive_allowed_rate: rate(adaptive_allowed_records, total_records),
            repair_first_rate: rate(repair_first_records, total_records),
            idle_rate: rate(idle_records, total_records),
            repair_rate: rate(repair_records, total_records),
            latest_effective_mode: latest.map(|summary| summary.effective_mode),
        }
    }

    pub fn is_empty(&self) -> bool {
        self.total_records == 0
    }

    pub fn health(
        &self,
        policy: AgentCollaborationSelfEvolutionCloseAndAdmitHealthPolicy,
    ) -> AgentCollaborationSelfEvolutionCloseAndAdmitHealth {
        AgentCollaborationSelfEvolutionCloseAndAdmitHealth::from_dashboard(self, policy)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSelfEvolutionCloseAndAdmitHealthPolicy {
    pub minimum_command_plan_rate: f32,
    pub maximum_idle_rate: f32,
    pub maximum_repair_rate: f32,
    pub maximum_repair_first_rate: f32,
}

impl Default for AgentCollaborationSelfEvolutionCloseAndAdmitHealthPolicy {
    fn default() -> Self {
        Self {
            minimum_command_plan_rate: 0.0,
            maximum_idle_rate: 0.67,
            maximum_repair_rate: 0.0,
            maximum_repair_first_rate: 0.0,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionCloseAndAdmitHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSelfEvolutionCloseAndAdmitHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationSelfEvolutionCloseAndAdmitDashboard,
        policy: AgentCollaborationSelfEvolutionCloseAndAdmitHealthPolicy,
    ) -> Self {
        if dashboard.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec!["no_self_evolution_close_and_admit_records".to_owned()],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();

        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "self_evolution_close_and_admit_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "self_evolution_close_and_admit_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.command_plan_rate < policy.minimum_command_plan_rate {
            watch_reasons.push(format!(
                "self_evolution_close_and_admit_command_plan_rate={:.3}<{:.3}",
                dashboard.command_plan_rate, policy.minimum_command_plan_rate
            ));
        }
        if dashboard.idle_rate > policy.maximum_idle_rate {
            watch_reasons.push(format!(
                "self_evolution_close_and_admit_idle_rate={:.3}>{:.3}",
                dashboard.idle_rate, policy.maximum_idle_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }
}

