#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionCloseAndAdmitContinuationPlan {
    pub health: AgentCollaborationSelfEvolutionCloseAndAdmitHealth,
    pub mode: AgentClosedLoopNextTurnMode,
    pub can_plan_service_commands: bool,
    pub allows_adaptive_evolution: bool,
    pub requires_repair_first: bool,
    pub reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationSelfEvolutionCloseAndAdmitContinuationPlan {
    pub fn from_health(health: AgentCollaborationSelfEvolutionCloseAndAdmitHealth) -> Self {
        let mode = collaboration_self_evolution_close_and_admit_continuation_mode(&health);
        let can_plan_service_commands = mode.can_schedule();
        let allows_adaptive_evolution = mode.allows_adaptive_evolution()
            && health.status == AgentClosedLoopExecutionHealthStatus::Stable;
        let requires_repair_first = mode == AgentClosedLoopNextTurnMode::Repair;
        let reasons = health.reasons.clone();
        let telemetry = collaboration_self_evolution_close_and_admit_continuation_telemetry(
            &health,
            mode,
            can_plan_service_commands,
            allows_adaptive_evolution,
            requires_repair_first,
            reasons.len(),
        );

        Self {
            health,
            mode,
            can_plan_service_commands,
            allows_adaptive_evolution,
            requires_repair_first,
            reasons,
            telemetry,
        }
    }
}

