#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalPacket {
    pub monitor_record: AgentCollaborationSelfEvolutionCloseAndAdmitMonitorRecord,
    pub expected_command_plan: AgentServiceCommandPlan,
    pub command_count: usize,
    pub command_kinds: Vec<String>,
    pub can_dispatch_service_commands: bool,
    pub requires_adaptive_state_write: bool,
    pub can_write_adaptive_state: bool,
    pub repair_mode_requested: bool,
    pub requires_repair_first: bool,
    pub blocked_reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationSelfEvolutionServiceEvalPacket {
    pub fn from_monitor_record(
        record: &AgentCollaborationSelfEvolutionCloseAndAdmitMonitorRecord,
    ) -> Self {
        AgentCollaborationSelfEvolutionServiceEvalPacketPlanner::new().plan(record)
    }

    pub fn is_dispatchable(&self) -> bool {
        self.can_dispatch_service_commands
    }

    pub fn summary(&self) -> AgentCollaborationSelfEvolutionServiceEvalPacketSummary {
        AgentCollaborationSelfEvolutionServiceEvalPacketSummary::from_packet(self)
    }
}

#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationSelfEvolutionServiceEvalPacketPlanner {
    service_planner: AgentServiceCommandPlanner,
}

impl AgentCollaborationSelfEvolutionServiceEvalPacketPlanner {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn plan(
        &self,
        record: &AgentCollaborationSelfEvolutionCloseAndAdmitMonitorRecord,
    ) -> AgentCollaborationSelfEvolutionServiceEvalPacket {
        let close_record = record.close_and_admit_record.close_record();
        let effective_business_plan = close_record.effective_business_plan();
        let expected_command_plan = self.service_planner.plan(&effective_business_plan);
        let command_count = expected_command_plan.commands.len();
        let command_kinds = expected_command_plan
            .command_kinds()
            .into_iter()
            .map(str::to_owned)
            .collect::<Vec<_>>();
        let requires_adaptive_state_write = expected_command_plan.requires_adaptive_state_write();
        let repair_mode_requested = expected_command_plan.repair_mode_requested();
        let can_write_adaptive_state = record.allows_adaptive_evolution()
            && requires_adaptive_state_write
            && close_record.can_promote_adaptive_state();
        let can_dispatch_service_commands = record.can_plan_service_commands()
            && command_count > 0
            && (!requires_adaptive_state_write || can_write_adaptive_state)
            && (!record.requires_repair_first() || repair_mode_requested);
        let blocked_reasons = collaboration_self_evolution_service_eval_packet_blockers(
            record,
            command_count,
            requires_adaptive_state_write,
            can_write_adaptive_state,
            repair_mode_requested,
        );
        let telemetry = collaboration_self_evolution_service_eval_packet_telemetry(
            record,
            command_count,
            &command_kinds,
            can_dispatch_service_commands,
            requires_adaptive_state_write,
            can_write_adaptive_state,
            repair_mode_requested,
            record.requires_repair_first(),
            blocked_reasons.len(),
        );

        AgentCollaborationSelfEvolutionServiceEvalPacket {
            monitor_record: record.clone(),
            expected_command_plan,
            command_count,
            command_kinds,
            can_dispatch_service_commands,
            requires_adaptive_state_write,
            can_write_adaptive_state,
            repair_mode_requested,
            requires_repair_first: record.requires_repair_first(),
            blocked_reasons,
            telemetry,
        }
    }
}

