#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalPacketDashboard {
    pub total_packets: usize,
    pub dispatchable_packets: usize,
    pub dispatch_blocked_packets: usize,
    pub adaptive_write_requested_packets: usize,
    pub adaptive_write_admitted_packets: usize,
    pub repair_first_packets: usize,
    pub repair_first_ready_packets: usize,
    pub total_commands: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_rust_validation_command_count: usize,
    pub service_execution_rust_validation_command_closes: usize,
    pub latest_effective_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub latest_blocked_reasons: usize,
    pub dispatch_rate: f32,
    pub dispatch_blocked_rate: f32,
    pub adaptive_write_admission_rate: f32,
    pub unadmitted_adaptive_write_rate: f32,
    pub repair_first_ready_rate: f32,
}

impl AgentCollaborationSelfEvolutionServiceEvalPacketDashboard {
    pub fn from_history(history: &AgentCollaborationSelfEvolutionServiceEvalPacketHistory) -> Self {
        let total_packets = history.len();
        let dispatchable_packets = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_dispatch_service_commands)
            .count();
        let dispatch_blocked_packets = total_packets.saturating_sub(dispatchable_packets);
        let adaptive_write_requested_packets = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_adaptive_state_write)
            .count();
        let adaptive_write_admitted_packets = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_write_adaptive_state)
            .count();
        let repair_first_packets = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let repair_first_ready_packets = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_repair_first && summary.repair_first_ready)
            .count();
        let total_commands = history
            .summaries()
            .iter()
            .map(|summary| summary.command_count)
            .sum();
        let service_execution_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_closes)
            .sum();
        let service_execution_rust_validation_command_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_count)
            .sum();
        let service_execution_rust_validation_command_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_closes)
            .sum();
        let latest = history.summaries().last();
        let latest_effective_mode = latest.map(|summary| summary.effective_mode);
        let latest_health_status = latest.map(|summary| summary.close_and_admit_health_status);
        let latest_blocked_reasons = latest.map_or(0, |summary| summary.blocked_reasons);
        let dispatch_rate = rate(dispatchable_packets, total_packets);
        let dispatch_blocked_rate = rate(dispatch_blocked_packets, total_packets);
        let adaptive_write_admission_rate = rate(
            adaptive_write_admitted_packets,
            adaptive_write_requested_packets,
        );
        let unadmitted_adaptive_write_rate = rate(
            adaptive_write_requested_packets.saturating_sub(adaptive_write_admitted_packets),
            adaptive_write_requested_packets,
        );
        let repair_first_ready_rate = rate(repair_first_ready_packets, repair_first_packets);

        Self {
            total_packets,
            dispatchable_packets,
            dispatch_blocked_packets,
            adaptive_write_requested_packets,
            adaptive_write_admitted_packets,
            repair_first_packets,
            repair_first_ready_packets,
            total_commands,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_rust_validation_command_count,
            service_execution_rust_validation_command_closes,
            latest_effective_mode,
            latest_health_status,
            latest_blocked_reasons,
            dispatch_rate,
            dispatch_blocked_rate,
            adaptive_write_admission_rate,
            unadmitted_adaptive_write_rate,
            repair_first_ready_rate,
        }
    }

    pub fn health(
        &self,
        policy: AgentCollaborationSelfEvolutionServiceEvalPacketHealthPolicy,
    ) -> AgentCollaborationSelfEvolutionServiceEvalPacketHealth {
        AgentCollaborationSelfEvolutionServiceEvalPacketHealth::from_dashboard(self, policy)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalPacketHealthPolicy {
    pub minimum_dispatch_rate: f32,
    pub maximum_dispatch_blocked_rate: f32,
    pub maximum_unadmitted_adaptive_write_rate: f32,
}

impl Default for AgentCollaborationSelfEvolutionServiceEvalPacketHealthPolicy {
    fn default() -> Self {
        Self {
            minimum_dispatch_rate: 0.50,
            maximum_dispatch_blocked_rate: 0.50,
            maximum_unadmitted_adaptive_write_rate: 0.50,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalPacketHealth {
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSelfEvolutionServiceEvalPacketHealth {
    pub fn from_dashboard(
        dashboard: &AgentCollaborationSelfEvolutionServiceEvalPacketDashboard,
        policy: AgentCollaborationSelfEvolutionServiceEvalPacketHealthPolicy,
    ) -> Self {
        if dashboard.total_packets == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec!["self_evolution_service_eval_packet_history_empty".to_owned()],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.repair_first_packets > dashboard.repair_first_ready_packets {
            repair_reasons.push(format!(
                "self_evolution_service_eval_packet_repair_first_ready={:.3}<1.000",
                dashboard.repair_first_ready_rate
            ));
        }
        if dashboard.dispatch_rate < policy.minimum_dispatch_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_packet_dispatch_rate={:.3}<{:.3}",
                dashboard.dispatch_rate, policy.minimum_dispatch_rate
            ));
        }
        if dashboard.dispatch_blocked_rate > policy.maximum_dispatch_blocked_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_packet_dispatch_blocked_rate={:.3}>{:.3}",
                dashboard.dispatch_blocked_rate, policy.maximum_dispatch_blocked_rate
            ));
        }
        if dashboard.unadmitted_adaptive_write_rate > policy.maximum_unadmitted_adaptive_write_rate
        {
            watch_reasons.push(format!(
                "self_evolution_service_eval_packet_unadmitted_adaptive_write_rate={:.3}>{:.3}",
                dashboard.unadmitted_adaptive_write_rate,
                policy.maximum_unadmitted_adaptive_write_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }

    pub fn is_stable(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn allows_service_advance(&self) -> bool {
        self.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

