#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionPlanner;

impl AgentCollaborationSelfEvolutionServiceEvalReflectionPlanner {
    pub fn new() -> Self {
        Self
    }

    pub fn plan(
        &self,
        record: &AgentCollaborationSelfEvolutionServiceEvalPacketMonitorRecord,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionPacket {
        let health_status = record.health_status();
        let requires_reflection = health_status != AgentClosedLoopExecutionHealthStatus::Stable
            || !record.is_dispatchable()
            || record.history_record.dashboard.latest_blocked_reasons > 0;
        let can_promote_memory_note = !requires_reflection && record.is_dispatchable();
        let can_admit_adaptive_evolution =
            can_promote_memory_note && record.packet.can_write_adaptive_state;
        let reflection_focus = collaboration_self_evolution_service_eval_reflection_focus(record);
        let blocked_reasons = collaboration_self_evolution_service_eval_reflection_blockers(
            record,
            requires_reflection,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
        );
        let telemetry = collaboration_self_evolution_service_eval_reflection_packet_telemetry(
            record,
            health_status,
            requires_reflection,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            reflection_focus.len(),
            blocked_reasons.len(),
        );

        AgentCollaborationSelfEvolutionServiceEvalReflectionPacket {
            packet_monitor_record: record.clone(),
            health_status,
            requires_reflection,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            reflection_focus,
            blocked_reasons,
            telemetry,
        }
    }
}

