#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionContinuationPlan {
    pub health: AgentCollaborationSelfEvolutionServiceEvalReflectionHealth,
    pub mode: AgentClosedLoopNextTurnMode,
    pub requires_reflection: bool,
    pub can_promote_memory_note: bool,
    pub can_admit_adaptive_evolution: bool,
    pub requires_repair_first: bool,
    pub reasons: Vec<String>,
    pub telemetry: Vec<String>,
}

impl AgentCollaborationSelfEvolutionServiceEvalReflectionContinuationPlan {
    pub fn from_monitor_record(
        record: &AgentCollaborationSelfEvolutionServiceEvalReflectionMonitorRecord,
    ) -> Self {
        let health = record.history_record.health.clone();
        let mode = collaboration_self_evolution_service_eval_reflection_continuation_mode(
            &health,
            record.requires_reflection(),
        );
        let requires_repair_first = mode == AgentClosedLoopNextTurnMode::Repair;
        let can_promote_memory_note =
            mode == AgentClosedLoopNextTurnMode::Continue && record.can_promote_memory_note();
        let can_admit_adaptive_evolution = can_promote_memory_note
            && record.can_admit_adaptive_evolution()
            && health.status == AgentClosedLoopExecutionHealthStatus::Stable;
        let reasons = collaboration_self_evolution_service_eval_reflection_continuation_reasons(
            record, &health, mode,
        );
        let telemetry = collaboration_self_evolution_service_eval_reflection_continuation_telemetry(
            &health,
            mode,
            record.requires_reflection(),
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            reasons.len(),
        );

        Self {
            health,
            mode,
            requires_reflection: record.requires_reflection(),
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            reasons,
            telemetry,
        }
    }
}

