#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlPlanner;

impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlPlanner {
    pub fn new() -> Self {
        Self
    }

    pub fn plan(
        &self,
        record: &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationMonitorRecord,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlPlan {
        let requested_mode = record.effective_mode();
        let health = record.history_record.health.clone();
        let effective_mode =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_mode(
                requested_mode,
                health.status,
            );
        let requires_repair_first = effective_mode == AgentClosedLoopNextTurnMode::Repair;
        let can_dispatch_service_commands = effective_mode.can_schedule()
            && record.can_dispatch_service_commands()
            && (!requires_repair_first || record.requires_repair_first());
        let can_promote_memory_note = effective_mode == AgentClosedLoopNextTurnMode::Continue
            && health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && record.can_promote_memory_note();
        let can_admit_adaptive_evolution = can_promote_memory_note
            && record.can_admit_adaptive_evolution()
            && health.status == AgentClosedLoopExecutionHealthStatus::Stable;
        let reasons =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_reasons(
                record,
                &health,
                effective_mode,
            );
        let telemetry =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_telemetry(
                requested_mode,
                effective_mode,
                &health,
                can_dispatch_service_commands,
                can_promote_memory_note,
                can_admit_adaptive_evolution,
                requires_repair_first,
                reasons.len(),
            );

        AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlPlan {
            requested_mode,
            effective_mode,
            health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            service_execution_command_reason_count: record
                .history_record
                .dashboard
                .service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count: record
                .history_record
                .dashboard
                .service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes: record
                .history_record
                .dashboard
                .service_execution_memory_promotion_command_reason_closes,
            service_execution_rust_validation_command_count: record
                .history_record
                .dashboard
                .service_execution_rust_validation_command_count,
            service_execution_rust_validation_command_closes: record
                .history_record
                .dashboard
                .service_execution_rust_validation_command_closes,
            reasons,
            telemetry,
        }
    }
}

