#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionGate;

impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        record:
            &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionMonitorRecord,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionGateDecision
    {
        let requested_mode = record.admission.effective_mode;
        let admission_health = record.admission_history_record.health.clone();
        let effective_mode =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_gate_mode(
                requested_mode,
                admission_health.status,
            );
        let requires_repair_first = effective_mode == AgentClosedLoopNextTurnMode::Repair;
        let can_dispatch_service_commands = effective_mode.can_schedule()
            && record.can_dispatch_service_commands()
            && !requires_repair_first;
        let can_promote_memory_note = effective_mode == AgentClosedLoopNextTurnMode::Continue
            && admission_health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && record.can_promote_memory_note();
        let can_admit_adaptive_evolution = can_promote_memory_note
            && record.can_admit_adaptive_evolution()
            && admission_health.status == AgentClosedLoopExecutionHealthStatus::Stable;
        let reasons =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_gate_reasons(
                record,
                &admission_health,
                effective_mode,
            );
        let telemetry =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_gate_telemetry(
                requested_mode,
                effective_mode,
                &admission_health,
                can_dispatch_service_commands,
                can_promote_memory_note,
                can_admit_adaptive_evolution,
                requires_repair_first,
                reasons.len(),
            );

        AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionGateDecision {
            requested_mode,
            effective_mode,
            admission_health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            reasons,
            telemetry,
        }
    }
}

