#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffDashboard
{
    pub total_handoffs: usize,
    pub continue_handoffs: usize,
    pub observe_handoffs: usize,
    pub repair_handoffs: usize,
    pub dispatchable_handoffs: usize,
    pub memory_note_promotable_handoffs: usize,
    pub adaptive_evolution_admitted_handoffs: usize,
    pub repair_first_handoffs: usize,
    pub total_reasons: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_rust_validation_command_count: usize,
    pub service_execution_rust_validation_command_closes: usize,
    pub latest_requested_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_effective_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub continue_rate: f32,
    pub observe_rate: f32,
    pub repair_rate: f32,
    pub dispatch_rate: f32,
    pub memory_note_promotion_rate: f32,
    pub adaptive_evolution_admission_rate: f32,
    pub repair_first_rate: f32,
}

impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffDashboard {
    pub fn from_history(
        history:
            &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHistory,
    ) -> Self {
        let total_handoffs = history.len();
        let continue_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Continue)
            .count();
        let observe_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Observe)
            .count();
        let repair_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.effective_mode == AgentClosedLoopNextTurnMode::Repair)
            .count();
        let dispatchable_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_dispatch_service_commands)
            .count();
        let memory_note_promotable_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_promote_memory_note)
            .count();
        let adaptive_evolution_admitted_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_admit_adaptive_evolution)
            .count();
        let repair_first_handoffs = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let total_reasons = history
            .summaries()
            .iter()
            .map(|summary| summary.reasons)
            .sum();
        let service_execution_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_closes)
            .sum();
        let service_execution_rust_validation_command_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_count)
            .sum();
        let service_execution_rust_validation_command_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_closes)
            .sum();
        let latest = history.summaries().last();

        Self {
            total_handoffs,
            continue_handoffs,
            observe_handoffs,
            repair_handoffs,
            dispatchable_handoffs,
            memory_note_promotable_handoffs,
            adaptive_evolution_admitted_handoffs,
            repair_first_handoffs,
            total_reasons,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_rust_validation_command_count,
            service_execution_rust_validation_command_closes,
            latest_requested_mode: latest.map(|summary| summary.requested_mode),
            latest_effective_mode: latest.map(|summary| summary.effective_mode),
            latest_health_status: latest.map(|summary| summary.health_status),
            continue_rate: rate(continue_handoffs, total_handoffs),
            observe_rate: rate(observe_handoffs, total_handoffs),
            repair_rate: rate(repair_handoffs, total_handoffs),
            dispatch_rate: rate(dispatchable_handoffs, total_handoffs),
            memory_note_promotion_rate: rate(memory_note_promotable_handoffs, total_handoffs),
            adaptive_evolution_admission_rate: rate(
                adaptive_evolution_admitted_handoffs,
                total_handoffs,
            ),
            repair_first_rate: rate(repair_first_handoffs, total_handoffs),
        }
    }

    pub fn health(
        &self,
        policy:
            AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealthPolicy,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealth
    {
        AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealth::from_dashboard(
            self,
            policy,
        )
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealthPolicy
{
    pub minimum_continue_rate: f32,
    pub minimum_dispatch_rate: f32,
    pub minimum_memory_note_promotion_rate: f32,
    pub maximum_observe_rate: f32,
    pub maximum_repair_rate: f32,
    pub maximum_repair_first_rate: f32,
}

impl Default
    for AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealthPolicy
{
    fn default() -> Self {
        Self {
            minimum_continue_rate: 0.50,
            minimum_dispatch_rate: 0.25,
            minimum_memory_note_promotion_rate: 0.25,
            maximum_observe_rate: 0.67,
            maximum_repair_rate: 0.0,
            maximum_repair_first_rate: 0.0,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealth
{
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealth {
    pub fn from_dashboard(
        dashboard:
            &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffDashboard,
        policy:
            AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealthPolicy,
    ) -> Self {
        if dashboard.total_handoffs == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec![
                    "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_history_empty"
                        .to_owned(),
                ],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.continue_rate < policy.minimum_continue_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continue_rate={:.3}<{:.3}",
                dashboard.continue_rate, policy.minimum_continue_rate
            ));
        }
        if dashboard.dispatch_rate < policy.minimum_dispatch_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_dispatch_rate={:.3}<{:.3}",
                dashboard.dispatch_rate, policy.minimum_dispatch_rate
            ));
        }
        if dashboard.memory_note_promotion_rate < policy.minimum_memory_note_promotion_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_memory_note_promotion_rate={:.3}<{:.3}",
                dashboard.memory_note_promotion_rate,
                policy.minimum_memory_note_promotion_rate
            ));
        }
        if dashboard.observe_rate > policy.maximum_observe_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_observe_rate={:.3}>{:.3}",
                dashboard.observe_rate, policy.maximum_observe_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }

    pub fn is_stable(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn allows_service_advance(&self) -> bool {
        self.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

