#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationDashboard
{
    pub total_continuations: usize,
    pub continue_continuations: usize,
    pub observe_continuations: usize,
    pub repair_continuations: usize,
    pub dispatchable_continuations: usize,
    pub memory_note_promotable_continuations: usize,
    pub adaptive_evolution_admitted_continuations: usize,
    pub repair_first_continuations: usize,
    pub total_reasons: usize,
    pub service_execution_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_count: usize,
    pub service_execution_memory_promotion_command_reason_closes: usize,
    pub service_execution_rust_validation_command_count: usize,
    pub service_execution_rust_validation_command_closes: usize,
    pub latest_mode: Option<AgentClosedLoopNextTurnMode>,
    pub latest_health_status: Option<AgentClosedLoopExecutionHealthStatus>,
    pub continue_rate: f32,
    pub observe_rate: f32,
    pub repair_rate: f32,
    pub dispatch_rate: f32,
    pub memory_note_promotion_rate: f32,
    pub adaptive_evolution_admission_rate: f32,
    pub repair_first_rate: f32,
}

impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationDashboard {
    pub fn from_history(
        history:
            &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHistory,
    ) -> Self {
        let total_continuations = history.len();
        let continue_continuations = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Continue)
            .count();
        let observe_continuations = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Observe)
            .count();
        let repair_continuations = history
            .summaries()
            .iter()
            .filter(|summary| summary.mode == AgentClosedLoopNextTurnMode::Repair)
            .count();
        let dispatchable_continuations = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_dispatch_service_commands)
            .count();
        let memory_note_promotable_continuations = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_promote_memory_note)
            .count();
        let adaptive_evolution_admitted_continuations = history
            .summaries()
            .iter()
            .filter(|summary| summary.can_admit_adaptive_evolution)
            .count();
        let repair_first_continuations = history
            .summaries()
            .iter()
            .filter(|summary| summary.requires_repair_first)
            .count();
        let total_reasons = history
            .summaries()
            .iter()
            .map(|summary| summary.reasons)
            .sum();
        let service_execution_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_count)
            .sum();
        let service_execution_memory_promotion_command_reason_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_memory_promotion_command_reason_closes)
            .sum();
        let service_execution_rust_validation_command_count = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_count)
            .sum();
        let service_execution_rust_validation_command_closes = history
            .summaries()
            .iter()
            .map(|summary| summary.service_execution_rust_validation_command_closes)
            .sum();
        let latest = history.summaries().last();

        Self {
            total_continuations,
            continue_continuations,
            observe_continuations,
            repair_continuations,
            dispatchable_continuations,
            memory_note_promotable_continuations,
            adaptive_evolution_admitted_continuations,
            repair_first_continuations,
            total_reasons,
            service_execution_command_reason_count,
            service_execution_memory_promotion_command_reason_count,
            service_execution_memory_promotion_command_reason_closes,
            service_execution_rust_validation_command_count,
            service_execution_rust_validation_command_closes,
            latest_mode: latest.map(|summary| summary.mode),
            latest_health_status: latest.map(|summary| summary.health_status),
            continue_rate: rate(continue_continuations, total_continuations),
            observe_rate: rate(observe_continuations, total_continuations),
            repair_rate: rate(repair_continuations, total_continuations),
            dispatch_rate: rate(dispatchable_continuations, total_continuations),
            memory_note_promotion_rate: rate(
                memory_note_promotable_continuations,
                total_continuations,
            ),
            adaptive_evolution_admission_rate: rate(
                adaptive_evolution_admitted_continuations,
                total_continuations,
            ),
            repair_first_rate: rate(repair_first_continuations, total_continuations),
        }
    }

    pub fn health(
        &self,
        policy:
            AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealthPolicy,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealth
    {
        AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealth::from_dashboard(
            self,
            policy,
        )
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealthPolicy
{
    pub minimum_continue_rate: f32,
    pub minimum_dispatch_rate: f32,
    pub minimum_memory_note_promotion_rate: f32,
    pub maximum_observe_rate: f32,
    pub maximum_repair_rate: f32,
    pub maximum_repair_first_rate: f32,
}

impl Default
    for AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealthPolicy
{
    fn default() -> Self {
        Self {
            minimum_continue_rate: 0.50,
            minimum_dispatch_rate: 0.25,
            minimum_memory_note_promotion_rate: 0.25,
            maximum_observe_rate: 0.67,
            maximum_repair_rate: 0.0,
            maximum_repair_first_rate: 0.0,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealth
{
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealth {
    pub fn from_dashboard(
        dashboard:
            &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationDashboard,
        policy:
            AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHealthPolicy,
    ) -> Self {
        if dashboard.total_continuations == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec![
                    "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_history_empty"
                        .to_owned(),
                ],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.continue_rate < policy.minimum_continue_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_continue_rate={:.3}<{:.3}",
                dashboard.continue_rate, policy.minimum_continue_rate
            ));
        }
        if dashboard.dispatch_rate < policy.minimum_dispatch_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_dispatch_rate={:.3}<{:.3}",
                dashboard.dispatch_rate, policy.minimum_dispatch_rate
            ));
        }
        if dashboard.memory_note_promotion_rate < policy.minimum_memory_note_promotion_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_memory_note_promotion_rate={:.3}<{:.3}",
                dashboard.memory_note_promotion_rate,
                policy.minimum_memory_note_promotion_rate
            ));
        }
        if dashboard.observe_rate > policy.maximum_observe_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_observe_rate={:.3}>{:.3}",
                dashboard.observe_rate, policy.maximum_observe_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }

    pub fn is_stable(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn allows_service_advance(&self) -> bool {
        self.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

