impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationGate {
    pub fn new() -> Self {
        Self
    }

    pub fn gate(
        &self,
        record:
            &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationMonitorRecord,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationGateDecision
    {
        let requested_mode = record.mode();
        let continuation_health = record.continuation_history_record.health.clone();
        let effective_mode =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_gate_mode(
                requested_mode,
                continuation_health.status,
            );
        let requires_repair_first = effective_mode == AgentClosedLoopNextTurnMode::Repair;
        let can_dispatch_service_commands = effective_mode.can_schedule()
            && record.can_dispatch_service_commands()
            && !requires_repair_first;
        let can_promote_memory_note = effective_mode == AgentClosedLoopNextTurnMode::Continue
            && continuation_health.status == AgentClosedLoopExecutionHealthStatus::Stable
            && record.can_promote_memory_note();
        let can_admit_adaptive_evolution = can_promote_memory_note
            && record.can_admit_adaptive_evolution()
            && continuation_health.status == AgentClosedLoopExecutionHealthStatus::Stable;
        let reasons =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_gate_reasons(
                record,
                &continuation_health,
                effective_mode,
            );
        let telemetry =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_gate_telemetry(
                requested_mode,
                effective_mode,
                &continuation_health,
                can_dispatch_service_commands,
                can_promote_memory_note,
                can_admit_adaptive_evolution,
                requires_repair_first,
                reasons.len(),
            );

        AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationGateDecision {
            requested_mode,
            effective_mode,
            continuation_health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            reasons,
            telemetry,
        }
    }
}

