#[derive(Debug, Clone, PartialEq)]
pub struct AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHandoffContinuationHandoffHealth
{
    pub status: AgentClosedLoopExecutionHealthStatus,
    pub reasons: Vec<String>,
}

impl AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHandoffContinuationHandoffHealth {
    pub fn from_dashboard(
        dashboard:
            &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHandoffContinuationHandoffDashboard,
        policy:
            AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHandoffContinuationHandoffHealthPolicy,
    ) -> Self {
        if dashboard.total_handoffs == 0 {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: vec![
                    "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_handoff_history_empty"
                        .to_owned(),
                ],
            };
        }

        let mut repair_reasons = Vec::new();
        let mut watch_reasons = Vec::new();
        if dashboard.repair_rate > policy.maximum_repair_rate {
            repair_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_handoff_repair_rate={:.3}>{:.3}",
                dashboard.repair_rate, policy.maximum_repair_rate
            ));
        }
        if dashboard.repair_first_rate > policy.maximum_repair_first_rate {
            repair_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_handoff_repair_first_rate={:.3}>{:.3}",
                dashboard.repair_first_rate, policy.maximum_repair_first_rate
            ));
        }
        if dashboard.continue_rate < policy.minimum_continue_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_handoff_continue_rate={:.3}<{:.3}",
                dashboard.continue_rate, policy.minimum_continue_rate
            ));
        }
        if dashboard.dispatch_rate < policy.minimum_dispatch_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_handoff_dispatch_rate={:.3}<{:.3}",
                dashboard.dispatch_rate, policy.minimum_dispatch_rate
            ));
        }
        if dashboard.memory_note_promotion_rate < policy.minimum_memory_note_promotion_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_handoff_memory_note_promotion_rate={:.3}<{:.3}",
                dashboard.memory_note_promotion_rate,
                policy.minimum_memory_note_promotion_rate
            ));
        }
        if dashboard.observe_rate > policy.maximum_observe_rate {
            watch_reasons.push(format!(
                "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_handoff_observe_rate={:.3}>{:.3}",
                dashboard.observe_rate, policy.maximum_observe_rate
            ));
        }

        if !repair_reasons.is_empty() {
            repair_reasons.extend(watch_reasons);
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Repair,
                reasons: repair_reasons,
            };
        }
        if !watch_reasons.is_empty() {
            return Self {
                status: AgentClosedLoopExecutionHealthStatus::Watch,
                reasons: watch_reasons,
            };
        }

        Self {
            status: AgentClosedLoopExecutionHealthStatus::Stable,
            reasons: Vec::new(),
        }
    }

    pub fn is_stable(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Stable
    }

    pub fn allows_service_advance(&self) -> bool {
        self.status != AgentClosedLoopExecutionHealthStatus::Repair
    }

    pub fn requires_repair_first(&self) -> bool {
        self.status == AgentClosedLoopExecutionHealthStatus::Repair
    }
}

