#[derive(Debug, Clone, Default)]
pub struct AgentCollaborationSelfEvolutionCloser {
    service_execution_closer: AgentCollaborationServiceExecutionCloser,
    service_history_recorder: AgentCollaborationServiceExecutionHistoryRecorder,
    self_evolution_planner: AgentCollaborationSelfEvolutionPlanner,
}

impl AgentCollaborationSelfEvolutionCloser {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn close(
        &self,
        run_id: impl AsRef<str>,
        collaboration_plan: &AgentCollaborationBusinessLoopPlan,
        service_execution_history: AgentCollaborationServiceExecutionHistory,
        service_execution_policy: AgentCollaborationServiceExecutionHealthPolicy,
        receipts: Vec<AgentServiceCommandReceipt>,
    ) -> AgentCollaborationSelfEvolutionCloseRecord {
        let service_execution_report =
            self.service_execution_closer
                .close(run_id, collaboration_plan, receipts);
        let service_execution_history_record = self.service_history_recorder.record_report(
            service_execution_history,
            &service_execution_report,
            service_execution_policy,
        );
        let mut self_evolution_plan = self.self_evolution_planner.plan(
            collaboration_plan,
            &service_execution_history_record.history,
            service_execution_policy,
        );
        let service_feedback_repair_tasks = service_execution_report
            .service_report
            .feedback
            .repair_tasks
            .clone();

        merge_service_execution_next_queue(&mut self_evolution_plan, &service_execution_report);
        let telemetry = collaboration_self_evolution_close_telemetry(
            &service_execution_report,
            &service_execution_history_record,
            &self_evolution_plan,
            service_feedback_repair_tasks.len(),
        );

        AgentCollaborationSelfEvolutionCloseRecord {
            service_execution_report,
            service_execution_history_record,
            self_evolution_plan,
            service_feedback_repair_tasks,
            telemetry,
        }
    }
}

