fn collaboration_dispatch_preflight_reasons(
    plan_record: &AgentCollaborationPlanHistoryGateRecord,
    budget_record: &BudgetLedgerHistoryGateRecord,
    schedule_record: &RecursiveAgentScheduleHistoryGateRecord,
) -> Vec<String> {
    let mut reasons = Vec::new();
    extend_ordered_unique(
        &mut reasons,
        plan_record
            .gate_decision
            .reasons
            .iter()
            .map(|reason| format!("plan:{reason}"))
            .collect::<Vec<_>>(),
    );
    extend_ordered_unique(
        &mut reasons,
        budget_record
            .gate_decision
            .reasons
            .iter()
            .map(|reason| format!("budget:{reason}"))
            .collect::<Vec<_>>(),
    );
    extend_ordered_unique(
        &mut reasons,
        schedule_record
            .gate_decision
            .reasons
            .iter()
            .map(|reason| format!("schedule:{reason}"))
            .collect::<Vec<_>>(),
    );
    reasons
}

fn collaboration_dispatch_preflight_repair_queue(
    plan_record: &AgentCollaborationPlanHistoryGateRecord,
    budget_record: &BudgetLedgerHistoryGateRecord,
    schedule_record: &RecursiveAgentScheduleHistoryGateRecord,
) -> AgentTaskQueue {
    let mut repair_tasks = Vec::new();
    repair_tasks.extend(plan_record.gate_decision.repair_tasks.iter().cloned());
    repair_tasks.extend(budget_record.gate_decision.repair_tasks.iter().cloned());
    repair_tasks.extend(schedule_record.gate_decision.repair_tasks.iter().cloned());
    AgentTaskQueue::from_tasks(repair_tasks)
}

