fn collaboration_self_evolution_status(
    collaboration_status: AgentCycleLedgerAdmissionStatus,
    service_execution_status: AgentClosedLoopExecutionHealthStatus,
) -> AgentCycleLedgerAdmissionStatus {
    match service_execution_status {
        AgentClosedLoopExecutionHealthStatus::Repair => AgentCycleLedgerAdmissionStatus::Repair,
        AgentClosedLoopExecutionHealthStatus::Watch => AgentCycleLedgerAdmissionStatus::Hold,
        AgentClosedLoopExecutionHealthStatus::Stable => collaboration_status,
    }
}

fn collaboration_service_execution_repair_tasks(
    health: &AgentCollaborationServiceExecutionHealth,
) -> Vec<AgentTask> {
    if health.status != AgentClosedLoopExecutionHealthStatus::Repair {
        return Vec::new();
    }

    health
        .reasons
        .iter()
        .enumerate()
        .map(|(index, reason)| {
            AgentTask::new(
                format!("collaboration-service-execution-repair-{index}"),
                AgentRole::Reviewer,
                format!("repair collaboration service execution health: {reason}"),
                AgentBudget::new(16, 1, 1),
            )
            .with_lane("collaboration-service-execution-repair")
            .with_priority(1)
        })
        .collect()
}

fn collaboration_self_evolution_blockers(
    collaboration_plan: &AgentCollaborationBusinessLoopPlan,
    service_execution_health: &AgentCollaborationServiceExecutionHealth,
    final_status: AgentCycleLedgerAdmissionStatus,
) -> Vec<String> {
    let mut blocked_reasons = collaboration_plan.blocked_reasons.clone();

    if service_execution_health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        blocked_reasons.push(format!(
            "service_execution_health={}",
            service_execution_health.status.as_str()
        ));
    }
    blocked_reasons.extend(
        service_execution_health
            .reasons
            .iter()
            .map(|reason| format!("service_execution={reason}")),
    );
    if final_status != collaboration_plan.effective_status {
        blocked_reasons.push(format!("final_status={}", final_status.as_str()));
    }

    blocked_reasons
}

