fn merge_service_execution_next_queue(
    plan: &mut AgentCollaborationSelfEvolutionPlan,
    service_execution_report: &AgentCollaborationServiceExecutionReport,
) {
    for task in service_execution_report.next_queue().tasks() {
        plan.next_queue.push(task);
    }

    for reason in &service_execution_report
        .service_report
        .turnover
        .blocked_reasons
    {
        plan.blocked_reasons
            .push(format!("current_service_execution={reason}"));
    }

    plan.telemetry.push(format!(
        "agent_collaboration_self_evolution_plan_merged_service_next_queue={}",
        service_execution_report.next_queue().len()
    ));
    plan.telemetry.push(format!(
        "agent_collaboration_self_evolution_plan_current_service_blockers={}",
        service_execution_report
            .service_report
            .turnover
            .blocked_reasons
            .len()
    ));
}

