fn collaboration_self_evolution_control_mode(
    health: &AgentCollaborationSelfEvolutionCloseHealth,
    next_queue: &AgentTaskQueue,
) -> AgentClosedLoopNextTurnMode {
    if next_queue.is_empty() {
        return AgentClosedLoopNextTurnMode::Idle;
    }

    match health.status {
        AgentClosedLoopExecutionHealthStatus::Stable => AgentClosedLoopNextTurnMode::Continue,
        AgentClosedLoopExecutionHealthStatus::Watch => AgentClosedLoopNextTurnMode::Observe,
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn collaboration_self_evolution_control_reasons(
    health: &AgentCollaborationSelfEvolutionCloseHealth,
    next_queue: &AgentTaskQueue,
) -> Vec<String> {
    let mut reasons = health.reasons.clone();
    if next_queue.is_empty() {
        reasons.push("next_queue_empty".to_owned());
    }
    reasons
}

