fn collaboration_self_evolution_control_gate_mode(
    requested_mode: AgentClosedLoopNextTurnMode,
    control_health_status: AgentClosedLoopExecutionHealthStatus,
    next_queue_empty: bool,
) -> AgentClosedLoopNextTurnMode {
    if next_queue_empty {
        return AgentClosedLoopNextTurnMode::Idle;
    }

    match control_health_status {
        AgentClosedLoopExecutionHealthStatus::Stable => requested_mode,
        AgentClosedLoopExecutionHealthStatus::Watch => match requested_mode {
            AgentClosedLoopNextTurnMode::Continue => AgentClosedLoopNextTurnMode::Observe,
            mode => mode,
        },
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn collaboration_self_evolution_control_gate_reasons(
    plan_reasons: &[String],
    control_health: &AgentCollaborationSelfEvolutionControlHealth,
) -> Vec<String> {
    let mut reasons = plan_reasons.to_vec();
    if control_health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "self_evolution_control_history_status={}",
            control_health.status.as_str()
        ));
    }
    reasons.extend(
        control_health
            .reasons
            .iter()
            .map(|reason| format!("self_evolution_control_history_reason={reason}")),
    );
    reasons
}

