fn collaboration_self_evolution_service_eval_packet_blockers(
    record: &AgentCollaborationSelfEvolutionCloseAndAdmitMonitorRecord,
    command_count: usize,
    requires_adaptive_state_write: bool,
    can_write_adaptive_state: bool,
    repair_mode_requested: bool,
) -> Vec<String> {
    let mut reasons = record.continuation_plan.reasons.clone();
    if command_count == 0 {
        reasons.push("self_evolution_service_eval_command_plan_empty".to_owned());
    }
    if !record.can_plan_service_commands() {
        reasons.push("self_evolution_service_eval_not_schedulable".to_owned());
    }
    if requires_adaptive_state_write && !can_write_adaptive_state {
        reasons.push("self_evolution_service_eval_adaptive_state_write_not_admitted".to_owned());
    }
    if record.requires_repair_first() && !repair_mode_requested {
        reasons.push("self_evolution_service_eval_repair_first_without_repair_command".to_owned());
    }
    reasons
}

