fn collaboration_self_evolution_service_eval_reflection_focus(
    record: &AgentCollaborationSelfEvolutionServiceEvalPacketMonitorRecord,
) -> Vec<String> {
    let mut focus = record.history_record.health.reasons.clone();
    focus.extend(record.packet.blocked_reasons.clone());
    if !record.is_dispatchable() {
        focus.push("self_evolution_service_eval_reflection_dispatch_blocked".to_owned());
    }
    if record.packet.requires_adaptive_state_write && !record.packet.can_write_adaptive_state {
        focus.push("self_evolution_service_eval_reflection_adaptive_write_blocked".to_owned());
    }
    if record.packet.requires_repair_first && !record.packet.repair_mode_requested {
        focus.push("self_evolution_service_eval_reflection_repair_command_missing".to_owned());
    }
    dedup_stable(focus)
}

fn collaboration_self_evolution_service_eval_reflection_blockers(
    record: &AgentCollaborationSelfEvolutionServiceEvalPacketMonitorRecord,
    requires_reflection: bool,
    can_promote_memory_note: bool,
    can_admit_adaptive_evolution: bool,
) -> Vec<String> {
    let mut blockers = Vec::new();
    if requires_reflection {
        blockers.push("self_evolution_service_eval_reflection_required".to_owned());
    }
    if !can_promote_memory_note {
        blockers.push("self_evolution_service_eval_memory_note_not_promotable".to_owned());
    }
    if record.packet.requires_adaptive_state_write && !can_admit_adaptive_evolution {
        blockers.push("self_evolution_service_eval_adaptive_evolution_not_admitted".to_owned());
    }
    blockers
}

