fn collaboration_self_evolution_service_eval_reflection_continuation_mode(
    health: &AgentCollaborationSelfEvolutionServiceEvalReflectionHealth,
    requires_reflection: bool,
) -> AgentClosedLoopNextTurnMode {
    match health.status {
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
        AgentClosedLoopExecutionHealthStatus::Watch => AgentClosedLoopNextTurnMode::Observe,
        AgentClosedLoopExecutionHealthStatus::Stable if requires_reflection => {
            AgentClosedLoopNextTurnMode::Observe
        }
        AgentClosedLoopExecutionHealthStatus::Stable => AgentClosedLoopNextTurnMode::Continue,
    }
}

fn collaboration_self_evolution_service_eval_reflection_continuation_reasons(
    record: &AgentCollaborationSelfEvolutionServiceEvalReflectionMonitorRecord,
    health: &AgentCollaborationSelfEvolutionServiceEvalReflectionHealth,
    mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = health.reasons.clone();
    reasons.extend(record.reflection_packet.blocked_reasons.clone());
    if record.requires_reflection() {
        reasons.push(
            "self_evolution_service_eval_reflection_continuation_reflection_required".to_owned(),
        );
    }
    if mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push("self_evolution_service_eval_reflection_continuation_observe".to_owned());
    }
    if mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push("self_evolution_service_eval_reflection_continuation_repair_first".to_owned());
    }
    dedup_stable(reasons)
}

