fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_mode(
    requested_mode: AgentClosedLoopNextTurnMode,
    health_status: AgentClosedLoopExecutionHealthStatus,
) -> AgentClosedLoopNextTurnMode {
    match health_status {
        AgentClosedLoopExecutionHealthStatus::Stable => requested_mode,
        AgentClosedLoopExecutionHealthStatus::Watch => match requested_mode {
            AgentClosedLoopNextTurnMode::Repair => AgentClosedLoopNextTurnMode::Repair,
            _ => AgentClosedLoopNextTurnMode::Observe,
        },
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_reasons(
    record: &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationMonitorRecord,
    health: &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationHealth,
    effective_mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = record
        .close_continuation_record
        .continuation_plan
        .reasons
        .clone();
    if health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "self_evolution_service_eval_reflection_close_continuation_control_health={}",
            health.status.as_str()
        ));
    }
    reasons.extend(health.reasons.iter().map(|reason| {
        format!(
            "self_evolution_service_eval_reflection_close_continuation_control_health_reason={reason}"
        )
    }));
    if effective_mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_observe".to_owned(),
        );
    }
    if effective_mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_repair_first"
                .to_owned(),
        );
    }
    dedup_stable(reasons)
}

