fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_reasons(
    record:
        &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlHandoffRecord,
    can_dispatch_service_commands: bool,
    can_promote_memory_note: bool,
    can_admit_adaptive_evolution: bool,
    requires_repair_first: bool,
) -> Vec<String> {
    let mut reasons = record.gate_decision.reasons.clone();
    if !can_dispatch_service_commands {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_dispatch_blocked"
                .to_owned(),
        );
    }
    if !can_promote_memory_note {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_memory_note_blocked"
                .to_owned(),
        );
    }
    if !can_admit_adaptive_evolution {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_adaptive_evolution_blocked"
                .to_owned(),
        );
    }
    if requires_repair_first {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_repair_first"
                .to_owned(),
        );
    }
    dedup_stable(reasons)
}

