fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_gate_mode(
    requested_mode: AgentClosedLoopNextTurnMode,
    admission_health_status: AgentClosedLoopExecutionHealthStatus,
) -> AgentClosedLoopNextTurnMode {
    match admission_health_status {
        AgentClosedLoopExecutionHealthStatus::Stable => requested_mode,
        AgentClosedLoopExecutionHealthStatus::Watch => match requested_mode {
            AgentClosedLoopNextTurnMode::Repair => AgentClosedLoopNextTurnMode::Repair,
            _ => AgentClosedLoopNextTurnMode::Observe,
        },
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_gate_reasons(
    record:
        &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionMonitorRecord,
    admission_health:
        &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHealth,
    effective_mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = record.admission.reasons.clone();
    if admission_health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_gate_health={}",
            admission_health.status.as_str()
        ));
    }
    reasons.extend(admission_health.reasons.iter().map(|reason| {
        format!(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_gate_health_reason={reason}"
        )
    }));
    if effective_mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_gate_observe"
                .to_owned(),
        );
    }
    if effective_mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_gate_repair_first"
                .to_owned(),
        );
    }
    dedup_stable(reasons)
}

