fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_mode(
    requested_mode: AgentClosedLoopNextTurnMode,
    handoff_health_status: AgentClosedLoopExecutionHealthStatus,
) -> AgentClosedLoopNextTurnMode {
    match handoff_health_status {
        AgentClosedLoopExecutionHealthStatus::Stable => requested_mode,
        AgentClosedLoopExecutionHealthStatus::Watch => match requested_mode {
            AgentClosedLoopNextTurnMode::Repair => AgentClosedLoopNextTurnMode::Repair,
            _ => AgentClosedLoopNextTurnMode::Observe,
        },
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_reasons(
    record:
        &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffMonitorRecord,
    handoff_health:
        &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffHealth,
    mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = record.handoff_record.gate_decision.reasons.clone();
    if handoff_health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_health={}",
            handoff_health.status.as_str()
        ));
    }
    reasons.extend(handoff_health.reasons.iter().map(|reason| {
        format!(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_health_reason={reason}"
        )
    }));
    if mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_observe"
                .to_owned(),
        );
    }
    if mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_repair_first"
                .to_owned(),
        );
    }
    dedup_stable(reasons)
}

