fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_gate_mode(
    requested_mode: AgentClosedLoopNextTurnMode,
    continuation_health_status: AgentClosedLoopExecutionHealthStatus,
) -> AgentClosedLoopNextTurnMode {
    match continuation_health_status {
        AgentClosedLoopExecutionHealthStatus::Stable => requested_mode,
        AgentClosedLoopExecutionHealthStatus::Watch => match requested_mode {
            AgentClosedLoopNextTurnMode::Repair => AgentClosedLoopNextTurnMode::Repair,
            _ => AgentClosedLoopNextTurnMode::Observe,
        },
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn collaboration_self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_gate_reasons(
    record:
        &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHandoffContinuationMonitorRecord,
    continuation_health:
        &AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlAdmissionHandoffContinuationHandoffContinuationHealth,
    effective_mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = record.continuation_record.continuation.reasons.clone();
    if continuation_health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_gate_health={}",
            continuation_health.status.as_str()
        ));
    }
    reasons.extend(continuation_health.reasons.iter().map(|reason| {
        format!(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_gate_health_reason={reason}"
        )
    }));
    if effective_mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_gate_observe"
                .to_owned(),
        );
    }
    if effective_mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push(
            "self_evolution_service_eval_reflection_close_continuation_control_admission_handoff_continuation_handoff_continuation_gate_repair_first"
                .to_owned(),
        );
    }
    dedup_stable(reasons)
}

