fn side_effect_boundary_gate(
    kind: SideEffectKind,
    allowed: bool,
    label: &str,
    reasons: &[String],
) -> SideEffectGate {
    if allowed {
        SideEffectGate::allow(kind, format!("{label}_admitted"))
    } else {
        let reason = reasons
            .first()
            .cloned()
            .unwrap_or_else(|| "not_admitted".to_owned());
        SideEffectGate::block(kind, format!("{label}_blocked:{reason}"))
    }
}

fn evolution_admission_handoff_boundary_mode(
    record: &EvolutionAdmissionHandoffTrendContinuationHistoryGateHistoryRecord,
) -> AgentClosedLoopNextTurnMode {
    match record.health.status {
        EvolutionAdmissionHealthStatus::Stable if record.is_effectively_admitted() => {
            AgentClosedLoopNextTurnMode::Continue
        }
        EvolutionAdmissionHealthStatus::Stable | EvolutionAdmissionHealthStatus::Watch => {
            AgentClosedLoopNextTurnMode::Observe
        }
        EvolutionAdmissionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn evolution_admission_handoff_boundary_health_status(
    record: &EvolutionAdmissionHandoffTrendContinuationHistoryGateHistoryRecord,
) -> AgentClosedLoopExecutionHealthStatus {
    match record.health.status {
        EvolutionAdmissionHealthStatus::Stable => AgentClosedLoopExecutionHealthStatus::Stable,
        EvolutionAdmissionHealthStatus::Watch => AgentClosedLoopExecutionHealthStatus::Watch,
        EvolutionAdmissionHealthStatus::Repair => AgentClosedLoopExecutionHealthStatus::Repair,
    }
}

fn evolution_admission_handoff_boundary_reasons(
    record: &EvolutionAdmissionHandoffTrendContinuationHistoryGateHistoryRecord,
) -> Vec<String> {
    let mut reasons = Vec::new();
    reasons.extend(
        record
            .health
            .reasons
            .iter()
            .map(|reason| format!("evolution_admission_handoff_history_health_reason={reason}")),
    );

    if !record.is_effectively_admitted() {
        reasons.push("evolution_admission_handoff_history_not_effectively_admitted".to_owned());
    }
    if record.requires_repair_first() {
        reasons.push("evolution_admission_handoff_history_repair_first".to_owned());
    }
    if record.blocked_reason_count() > 0 {
        reasons.push(format!(
            "evolution_admission_handoff_history_blocked_reasons={}",
            record.blocked_reason_count()
        ));
    }
    reasons.extend(
        record
            .repair_task_ids()
            .iter()
            .map(|task_id| format!("evolution_admission_handoff_history_repair_task={task_id}")),
    );

    dedup_stable(reasons)
}

