fn side_effect_boundary_gate_mode(
    requested_mode: AgentClosedLoopNextTurnMode,
    health_status: AgentClosedLoopExecutionHealthStatus,
) -> AgentClosedLoopNextTurnMode {
    match health_status {
        AgentClosedLoopExecutionHealthStatus::Stable => requested_mode,
        AgentClosedLoopExecutionHealthStatus::Watch => match requested_mode {
            AgentClosedLoopNextTurnMode::Repair => AgentClosedLoopNextTurnMode::Repair,
            _ => AgentClosedLoopNextTurnMode::Observe,
        },
        AgentClosedLoopExecutionHealthStatus::Repair => AgentClosedLoopNextTurnMode::Repair,
    }
}

fn side_effect_boundary_gate_reasons(
    boundary: &AgentCollaborationSideEffectBoundary,
    health: &AgentCollaborationSideEffectBoundaryHealth,
    effective_mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = boundary.reasons.clone();
    if health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "collaboration_side_effect_boundary_gate_health={}",
            health.status.as_str()
        ));
    }
    reasons.extend(
        health.reasons.iter().map(|reason| {
            format!("collaboration_side_effect_boundary_gate_health_reason={reason}")
        }),
    );
    if effective_mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push("collaboration_side_effect_boundary_gate_observe".to_owned());
    }
    if effective_mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push("collaboration_side_effect_boundary_gate_repair_first".to_owned());
    }
    dedup_stable(reasons)
}

