fn side_effect_boundary_handoff_monitor_gate_reasons(
    monitor: &AgentCollaborationSideEffectBoundaryHandoffMonitorRecord,
    health: &AgentCollaborationSideEffectBoundaryHandoffMonitorHealth,
    effective_mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = monitor.handoff.gate_decision.reasons.clone();
    if health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "collaboration_side_effect_boundary_handoff_monitor_gate_health={}",
            health.status.as_str()
        ));
    }
    reasons.extend(health.reasons.iter().map(|reason| {
        format!("collaboration_side_effect_boundary_handoff_monitor_gate_health_reason={reason}")
    }));
    if effective_mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push("collaboration_side_effect_boundary_handoff_monitor_gate_observe".to_owned());
    }
    if effective_mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push(
            "collaboration_side_effect_boundary_handoff_monitor_gate_repair_first".to_owned(),
        );
    }
    dedup_stable(reasons)
}

