fn adapter_side_effect_admission_gate_reasons(
    admission: &AgentCollaborationAdapterSideEffectAdmission,
    health: &AgentCollaborationAdapterSideEffectAdmissionHealth,
    effective_mode: AgentClosedLoopNextTurnMode,
) -> Vec<String> {
    let mut reasons = admission.reasons.clone();
    if health.status != AgentClosedLoopExecutionHealthStatus::Stable {
        reasons.push(format!(
            "collaboration_adapter_side_effect_admission_gate_health={}",
            health.status.as_str()
        ));
    }
    reasons.extend(health.reasons.iter().map(|reason| {
        format!("collaboration_adapter_side_effect_admission_gate_health_reason={reason}")
    }));
    if effective_mode == AgentClosedLoopNextTurnMode::Observe {
        reasons.push("collaboration_adapter_side_effect_admission_gate_observe".to_owned());
    }
    if effective_mode == AgentClosedLoopNextTurnMode::Repair {
        reasons.push("collaboration_adapter_side_effect_admission_gate_repair_first".to_owned());
    }
    dedup_stable(reasons)
}

