fn collaboration_window_ownership_repair_tasks(
    requires_repair_first: bool,
    reasons: &[String],
) -> Vec<AgentTask> {
    if !requires_repair_first {
        return Vec::new();
    }

    reasons
        .iter()
        .enumerate()
        .map(|(index, reason)| {
            AgentTask::new(
                format!("collaboration-ownership-repair-{index}"),
                AgentRole::Planner,
                format!("repair collaboration ownership boundary: {reason}"),
                AgentBudget::new(16, 1, 1),
            )
            .with_lane("collaboration-ownership-repair")
            .with_priority(1)
        })
        .collect()
}

fn collaboration_ownership_preflight_gate_repair_tasks(
    ownership_blocks: bool,
    ownership_record: &AgentWindowOwnershipReviewSummaryHistoryRecord,
) -> Vec<AgentTask> {
    if !ownership_blocks {
        return Vec::new();
    }

    let repair_ids = &ownership_record.appended_summary.repair_task_ids;
    if !repair_ids.is_empty() {
        return repair_ids
            .iter()
            .map(|repair_id| {
                AgentTask::new(
                    repair_id.clone(),
                    AgentRole::Planner,
                    "repair collaboration ownership boundary before dispatch preflight",
                    AgentBudget::new(16, 1, 1),
                )
                .with_lane("collaboration-ownership-repair")
                .with_priority(1)
            })
            .collect();
    }

    ownership_record
        .health
        .reasons
        .iter()
        .enumerate()
        .map(|(index, reason)| {
            AgentTask::new(
                format!("collaboration-ownership-preflight-repair-{index}"),
                AgentRole::Planner,
                format!("repair collaboration ownership preflight gate: {reason}"),
                AgentBudget::new(16, 1, 1),
            )
            .with_lane("collaboration-ownership-repair")
            .with_priority(1)
        })
        .collect()
}

