fn clean_room_assignment_reason_codes(
    worker_status: AgentWindowContextStatus,
    replacement_plan: &AgentWindowContextCleanRoomReplacementPlan,
    candidate_task_ids_empty: bool,
    rejected_candidate_tasks: usize,
    side_effect_boundary_preserved: bool,
    assignment_allowed: bool,
) -> Vec<String> {
    let mut reason_codes = vec![worker_status.reason_code().to_owned()];
    reason_codes.extend(replacement_plan.replacement_prompt.reason_codes.clone());
    if !worker_status.accepts_clean_room_replacement() {
        reason_codes.push("clean_room_assignment_target_not_replacement".to_owned());
    }
    if worker_status.blocks_original_assignment() {
        reason_codes.push("original_window_follow_up_blocked".to_owned());
    }
    if !replacement_plan.clean_room_replacement_plan_required {
        reason_codes.push("clean_room_replacement_plan_not_required".to_owned());
    }
    if !replacement_plan.clean_room_replacement_available {
        reason_codes.push("clean_room_replacement_unavailable".to_owned());
    }
    if !replacement_plan.replacement_prompt_ready {
        reason_codes.push("clean_room_replacement_prompt_not_ready".to_owned());
    }
    if candidate_task_ids_empty {
        reason_codes.push("candidate_clean_room_task_ids_empty".to_owned());
    }
    if rejected_candidate_tasks > 0 {
        reason_codes.push("candidate_clean_room_task_ids_outside_replacement_plan".to_owned());
    }
    if !side_effect_boundary_preserved {
        reason_codes.push("clean_room_replacement_side_effect_boundary_open".to_owned());
    }
    if assignment_allowed {
        reason_codes.push("clean_room_assignment_allowed".to_owned());
    } else {
        reason_codes.push("clean_room_assignment_blocked".to_owned());
    }
    dedup_stable(reason_codes)
}

