fn collaboration_ownership_preflight_gate_history_record_telemetry(
    dashboard: &AgentCollaborationOwnershipPreflightGateDashboard,
    health: &AgentCollaborationOwnershipPreflightGateHealth,
) -> Vec<String> {
    let mut telemetry = vec![
        "agent_collaboration_ownership_preflight_gate_history_record=true".to_owned(),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_status={}",
            execution_health_status_name(health.status)
        ),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_records={}",
            dashboard.total_records
        ),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_dispatch_rate={:.3}",
            dashboard.dispatch_rate
        ),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_side_effect_open_rate={:.3}",
            dashboard.side_effect_open_rate
        ),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_memory_note_open_rate={:.3}",
            dashboard.memory_note_open_rate
        ),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_next_task_open_rate={:.3}",
            dashboard.next_task_open_rate
        ),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_repair_first_records={}",
            dashboard.repair_first_records
        ),
        format!(
            "agent_collaboration_ownership_preflight_gate_history_record_repair_queue_tasks={}",
            dashboard.total_repair_queue_tasks
        ),
    ];
    telemetry.extend(health.reasons.iter().map(|reason| {
        format!("agent_collaboration_ownership_preflight_gate_history_record_reason={reason}")
    }));
    telemetry
}

#[allow(clippy::too_many_arguments)]
fn collaboration_window_ownership_review_telemetry(
    windows: usize,
    changed_paths: usize,
    conflicting_paths: usize,
    out_of_bounds_writes: usize,
    can_write: bool,
    requires_repair_first: bool,
    repair_tasks: usize,
    reasons: usize,
) -> Vec<String> {
    vec![
        "agent_collaboration_window_ownership_review=true".to_owned(),
        format!("agent_collaboration_window_ownership_review_windows={windows}"),
        format!("agent_collaboration_window_ownership_review_changed_paths={changed_paths}"),
        format!(
            "agent_collaboration_window_ownership_review_conflicting_paths={conflicting_paths}"
        ),
        format!(
            "agent_collaboration_window_ownership_review_out_of_bounds_writes={out_of_bounds_writes}"
        ),
        format!("agent_collaboration_window_ownership_review_can_write={can_write}"),
        format!(
            "agent_collaboration_window_ownership_review_requires_repair_first={requires_repair_first}"
        ),
        format!("agent_collaboration_window_ownership_review_repair_tasks={repair_tasks}"),
        format!("agent_collaboration_window_ownership_review_reasons={reasons}"),
    ]
}

fn rate(count: usize, total: usize) -> f32 {
    if total == 0 {
        0.0
    } else {
        count as f32 / total as f32
    }
}

fn execution_health_status_name(status: AgentClosedLoopExecutionHealthStatus) -> &'static str {
    match status {
        AgentClosedLoopExecutionHealthStatus::Stable => "stable",
        AgentClosedLoopExecutionHealthStatus::Watch => "watch",
        AgentClosedLoopExecutionHealthStatus::Repair => "repair",
    }
}

