    fn evolution_admission_handoff_summary_for_boundary(
        health: EvolutionAdmissionHealthStatus,
        effective_admitted: bool,
        requires_repair_first: bool,
    ) -> EvolutionAdmissionHandoffTrendContinuationHistoryGateSummary {
        let repair_task_ids = if requires_repair_first {
            vec!["evolution-repair".to_owned()]
        } else {
            Vec::new()
        };
        let blocked_reasons = usize::from(requires_repair_first);

        EvolutionAdmissionHandoffTrendContinuationHistoryGateSummary {
            continuation_health_status: health,
            effective_admitted,
            can_promote_ready_proposals: effective_admitted && !requires_repair_first,
            can_promote_evolution_signals: effective_admitted && !requires_repair_first,
            can_reinforce_process: effective_admitted && !requires_repair_first,
            can_promote_adaptive_state: effective_admitted && !requires_repair_first,
            requires_repair_first,
            repair_tasks: repair_task_ids.len(),
            next_queue_tasks: 1,
            blocked_reasons,
            records: 1,
            repair_task_ids,
            next_queue_task_ids: vec!["business-task".to_owned()],
            telemetry: Vec::new(),
        }
    }

    fn evolution_admission_handoff_boundary_from_summary(
        summary: EvolutionAdmissionHandoffTrendContinuationHistoryGateSummary,
        policy: EvolutionAdmissionHandoffTrendContinuationHistoryGateHealthPolicy,
    ) -> AgentCollaborationSideEffectBoundary {
        let record = evolution_admission_handoff_history_from_summary(summary, policy);

        AgentCollaborationSideEffectBoundary::from_evolution_admission_handoff_history(&record)
    }

    #[test]
    fn window_ownership_review_allows_isolated_changed_paths() {
        let review = AgentWindowOwnershipReviewer::new().review(vec![
            AgentWindowOwnership::new("window-1")
                .owns_path("crates/norion-agent/src")
                .changed_path("crates/norion-agent/src/collaboration.rs"),
            AgentWindowOwnership::new("window-2")
                .owns_path("docs/architecture")
                .changed_path("docs/architecture/norion-agent.md"),
        ]);

        assert_eq!(review.windows, 2);
        assert_eq!(review.changed_paths, 2);
        assert!(review.conflicting_paths.is_empty());
        assert!(review.out_of_bounds_writes.is_empty());
        assert!(review.can_write);
        assert!(!review.requires_repair_first);
        assert!(review.repair_tasks.is_empty());
        assert!(review.reasons.is_empty());
        assert!(
            review.telemetry.iter().any(|line| {
                line == "agent_collaboration_window_ownership_review_can_write=true"
            })
        );
    }

    #[test]
    fn window_ownership_review_repairs_shared_or_out_of_bounds_files_before_writes() {
        let review = AgentWindowOwnershipReviewer::new().review(vec![
            AgentWindowOwnership::new("window-2")
                .owns_path("docs/architecture")
                .changed_path("docs\\architecture\\norion-agent.md")
                .changed_path("crates/norion-agent/src/collaboration.rs"),
            AgentWindowOwnership::new("window-1")
                .owns_path("crates/norion-agent/src")
                .changed_path("crates/norion-agent/src/collaboration.rs"),
        ]);

        assert_eq!(review.windows, 2);
        assert_eq!(review.changed_paths, 2);
        assert!(!review.can_write);
        assert!(review.requires_repair_first);
        assert_eq!(
            review.conflicting_paths,
            vec![AgentWindowOwnershipConflict {
                path: "crates/norion-agent/src/collaboration.rs".to_owned(),
                window_ids: vec!["window-1".to_owned(), "window-2".to_owned()],
            }]
        );
        assert_eq!(
            review.out_of_bounds_writes,
            vec![AgentWindowOutOfBoundsWrite {
                window_id: "window-2".to_owned(),
                path: "crates/norion-agent/src/collaboration.rs".to_owned(),
            }]
        );
        assert_eq!(
            review.reasons,
            vec![
                "ownership_conflict path=crates/norion-agent/src/collaboration.rs windows=window-1,window-2",
                "ownership_out_of_bounds window=window-2 path=crates/norion-agent/src/collaboration.rs",
            ]
        );
        assert_eq!(
            review.repair_task_ids(),
            vec![
                "collaboration-ownership-repair-0".to_owned(),
                "collaboration-ownership-repair-1".to_owned()
            ]
        );
        assert!(review.repair_tasks.iter().all(|task| {
            task.role == AgentRole::Planner && task.lane == "collaboration-ownership-repair"
        }));
        assert!(review.telemetry.iter().any(|line| {
            line == "agent_collaboration_window_ownership_review_requires_repair_first=true"
        }));
    }

    #[test]
    fn window_ownership_review_summary_history_records_clean_contract() {
        let review = AgentWindowOwnershipReviewer::new().review(vec![
            AgentWindowOwnership::new("window-1")
                .owns_path("crates/norion-agent/src")
                .changed_path("crates/norion-agent/src/collaboration.rs"),
            AgentWindowOwnership::new("window-2")
                .owns_path("docs/architecture")
                .changed_path("docs/architecture/norion-agent-workflow.md"),
        ]);

        let record = AgentWindowOwnershipReviewSummaryHistoryRecorder::new()
            .record_review_with_health(
                AgentWindowOwnershipReviewSummaryHistory::new(),
                &review,
                AgentWindowOwnershipReviewHealthPolicy::default(),
            );

        assert_eq!(record.records(), 1);
        assert_eq!(record.appended_summary.windows, 2);
        assert_eq!(record.appended_summary.changed_paths, 2);
        assert_eq!(record.appended_summary.conflicting_paths, 0);
        assert!(record.appended_summary.can_write);
        assert!(!record.appended_summary.requires_repair_first);
        assert!(record.appended_summary.repair_task_ids.is_empty());
        assert_eq!(
            record.health.status,
            AgentWindowOwnershipReviewHealthStatus::Stable
        );
        assert!(record.health.is_stable());
        assert!(record.allows_service_advance());
        assert!(!record.requires_repair_first());
        assert_eq!(record.dashboard.write_allowed_rate, 1.0);
        assert_eq!(record.dashboard.repair_first_rate, 0.0);
        assert!(
            record.telemetry.iter().any(|line| {
                line == "agent_window_ownership_review_history_record_status=stable"
            })
        );
    }

    #[test]
    fn window_ownership_review_summary_history_repairs_dirty_contract() {
        let clean = AgentWindowOwnershipReviewer::new()
            .review(vec![
                AgentWindowOwnership::new("window-1")
                    .owns_path("crates/norion-agent/src")
                    .changed_path("crates/norion-agent/src/lib.rs"),
            ])
            .summary();
        let dirty_review = AgentWindowOwnershipReviewer::new().review(vec![
            AgentWindowOwnership::new("window-2")
                .owns_path("docs/architecture")
                .changed_path("crates/norion-agent/src/collaboration.rs"),
            AgentWindowOwnership::new("window-1")
                .owns_path("crates/norion-agent/src")
                .changed_path("crates\\norion-agent\\src\\collaboration.rs"),
        ]);
        let history = AgentWindowOwnershipReviewSummaryHistory::from_summaries(vec![clean]);

        let record = AgentWindowOwnershipReviewSummaryHistoryRecorder::new()
            .record_review_with_health(
                history,
                &dirty_review,
                AgentWindowOwnershipReviewHealthPolicy::default(),
            );

        assert_eq!(record.records(), 2);
        assert_eq!(record.appended_summary.conflicting_paths, 1);
        assert_eq!(record.appended_summary.out_of_bounds_writes, 1);
        assert_eq!(
            record.appended_summary.repair_task_ids,
            vec![
                "collaboration-ownership-repair-0".to_owned(),
                "collaboration-ownership-repair-1".to_owned()
            ]
        );
        assert_eq!(record.dashboard.repair_first_reviews, 1);
        assert_eq!(record.dashboard.conflicting_paths, 1);
        assert_eq!(record.dashboard.out_of_bounds_writes, 1);
        assert_eq!(record.dashboard.repair_tasks, 2);
        assert_eq!(
            record.health.status,
            AgentWindowOwnershipReviewHealthStatus::Repair
        );
        assert!(!record.allows_service_advance());
        assert!(record.requires_repair_first());
        assert_eq!(
            record.health.reasons,
            vec![
                "window_ownership_review_repair_first_reviews=1>0".to_owned(),
                "window_ownership_review_conflicting_paths=1>0".to_owned(),
                "window_ownership_review_out_of_bounds_writes=1>0".to_owned(),
            ]
        );
        assert!(
            record.telemetry.iter().any(|line| {
                line == "agent_window_ownership_review_history_record_status=repair"
            })
        );
    }

