    #[test]
    fn collaboration_window_budget_exhaustion_rejects_only_depleted_window() {
        let plan = AgentCollaborationPlanner::new().plan(vec![
            AgentWindowSpec::new(
                "window-1",
                AgentRole::Coder,
                "implement the isolated change",
                AgentBudget::new(8, 1, 1),
            ),
            AgentWindowSpec::new(
                "window-2",
                AgentRole::Reviewer,
                "review without budget",
                AgentBudget::zero(),
            ),
            AgentWindowSpec::new(
                "window-3",
                AgentRole::Tester,
                "verify the crate",
                AgentBudget::new(6, 1, 1),
            ),
        ]);
        let gate = plan.gate(
            AgentCollaborationPlanGatePolicy::expected_windows(3).allow_zero_budget_windows(),
        );

        assert!(gate.can_dispatch_queue);
        assert!(gate.can_open_side_effect_boundary);
        assert_eq!(gate.summary.zero_budget_windows, 1);
        assert!(gate.reasons.is_empty());

        let dispatch = DispatchPlanner::new(plan.budget_ledger.clone())
            .plan_with_policy(plan.queue.tasks(), &BudgetPolicy::strict());
        let assigned_ids = dispatch
            .assignments
            .iter()
            .map(|assignment| assignment.task_id.as_str())
            .collect::<Vec<_>>();
        let rejected_ids = dispatch
            .rejections
            .iter()
            .map(|rejection| rejection.task_id.as_str())
            .collect::<Vec<_>>();

        assert_eq!(assigned_ids, vec!["window-1", "window-3"]);
        assert_eq!(rejected_ids, vec!["window-2"]);
        assert_eq!(dispatch.rejections[0].role, AgentRole::Reviewer);
        assert!(
            dispatch.rejections[0]
                .reason
                .contains("zero budget task rejected for role reviewer")
        );
        assert_eq!(
            dispatch.remaining.get(&AgentRole::Coder).copied(),
            Some(AgentBudget::zero())
        );
        assert_eq!(
            dispatch.remaining.get(&AgentRole::Tester).copied(),
            Some(AgentBudget::zero())
        );
        assert_eq!(
            dispatch.remaining.get(&AgentRole::Reviewer).copied(),
            Some(AgentBudget::zero())
        );
    }

