    #[test]
    fn collaboration_clean_room_readiness_summary_isolates_polluted_window_handoff() {
        let conflicted_path = "crates/norion-agent/src/collaboration.rs";
        let plan = AgentCollaborationPlanner::new().plan(six_windows());
        let business_task_ids = plan.queue.task_ids();
        let preflight = AgentCollaborationDispatchPreflight::new().record_and_gate(
            &plan,
            AgentCollaborationPlanSummaryHistory::new(),
            AgentCollaborationPlanGatePolicy::six_window_strict(),
            AgentCollaborationPlanHealthPolicy::default(),
            BudgetLedgerSummaryHistory::new(),
            BudgetLedgerHealthPolicy::default(),
            RecursiveAgentScheduleSummaryHistory::new(),
            RecursiveAgentScheduleHealthPolicy::default(),
            3,
        );
        let ownership_review = AgentWindowOwnershipReviewer::new().review(vec![
            AgentWindowOwnership::new("window-1")
                .owns_path("crates/norion-agent/src")
                .changed_path(conflicted_path),
            AgentWindowOwnership::new("window-2")
                .owns_path("docs/architecture")
                .changed_path(conflicted_path),
        ]);
        let ownership_record = AgentWindowOwnershipReviewSummaryHistoryRecorder::new()
            .record_review_with_health(
                AgentWindowOwnershipReviewSummaryHistory::new(),
                &ownership_review,
                AgentWindowOwnershipReviewHealthPolicy::default(),
            );
        let gate =
            AgentCollaborationOwnershipPreflightGate::new().gate(preflight, ownership_record);

        let summary = gate.clean_room_readiness_summary(&plan.queue);

        assert!(summary.clean_room_report_only);
        assert!(!summary.side_effects_allowed);
        assert!(summary.polluted_window_isolated);
        assert!(summary.business_tasks_preserved);
        assert!(summary.requires_repair_first);
        assert!(!summary.dispatch_allowed_by_gate);
        assert!(summary.can_assign_repair_window_tasks);
        assert!(!summary.can_assign_business_window_tasks);
        assert_eq!(summary.business_task_ids, business_task_ids);
        assert_eq!(summary.requested_business_tasks, 6);
        assert_eq!(summary.preserved_business_tasks, 6);
        assert_eq!(
            summary.repair_task_ids,
            vec![
                "collaboration-ownership-repair-0".to_owned(),
                "collaboration-ownership-repair-1".to_owned()
            ]
        );
        assert_eq!(summary.immediate_ready_task_ids, summary.repair_task_ids);
        assert_eq!(
            summary.effective_queue_tasks,
            summary.requested_business_tasks + summary.repair_queue_tasks
        );
        assert!(summary.evidence_items >= summary.reason_codes.len());
        assert!(
            summary
                .reason_codes
                .iter()
                .any(|code| { code == "ownership:window_ownership_review_conflicting_paths" })
        );
        assert!(
            summary
                .reason_codes
                .iter()
                .any(|code| { code == "ownership:window_ownership_review_out_of_bounds_writes" })
        );
        assert!(
            summary
                .reason_codes
                .iter()
                .all(|code| { !code.contains(conflicted_path) && !code.contains("window-1") })
        );
        assert!(summary.telemetry.iter().any(|line| {
            line == "agent_collaboration_clean_room_readiness_summary_side_effects_allowed=false"
        }));
    }

