    #[test]
    fn window_context_reallocation_fields_polluted_stale_paused_replacement_statuses() {
        let plan = AgentCollaborationPlanner::new().plan(six_windows());
        let requested_task_ids = plan.queue.task_ids();
        let observations = vec![
            AgentWindowContextObservation::new(AgentWindowContextStatus::Polluted)
                .with_business_task_id(requested_task_ids[0].clone())
                .with_evidence_result_id("handoff-summary:agent-r20")
                .with_reason_code(
                    "polluted_context window=old-thread path=crates/norion-agent/src/collaboration.rs",
                ),
            AgentWindowContextObservation::new(AgentWindowContextStatus::Stale)
                .with_evidence_result_id("validation:946-passed")
                .with_reason_code("stale_context=round-312"),
            AgentWindowContextObservation::new(AgentWindowContextStatus::Paused)
                .with_reason_code("paused_by_main_window thread=archived"),
            AgentWindowContextObservation::new(AgentWindowContextStatus::CleanRoomReplacement)
                .with_reason_code("replacement_window=clean-room-r21"),
        ];

        let summary =
            AgentWindowContextReallocationSummary::from_observations(&observations, &plan.queue);

        assert!(summary.report_only);
        assert!(!summary.side_effects_allowed);
        assert_eq!(summary.clean_windows, 0);
        assert_eq!(summary.polluted_windows, 1);
        assert_eq!(summary.stale_windows, 1);
        assert_eq!(summary.paused_windows, 1);
        assert_eq!(summary.clean_room_replacements, 1);
        assert!(summary.blocked_original_assignment);
        assert!(summary.can_assign_clean_room_replacement);
        assert!(summary.business_tasks_preserved);
        assert!(summary.evidence_backed_results_preserved);
        assert_eq!(summary.requested_business_tasks, 6);
        assert_eq!(summary.narrow_replacement_task_ids, requested_task_ids);
        assert_eq!(summary.narrow_replacement_tasks, 6);
        assert_eq!(
            summary.evidence_result_ids,
            vec![
                "handoff-summary:agent-r20".to_owned(),
                "validation:946-passed".to_owned()
            ]
        );
        assert!(
            summary
                .reason_codes
                .contains(&"window_context_polluted".to_owned())
        );
        assert!(
            summary
                .reason_codes
                .contains(&"window_context_stale".to_owned())
        );
        assert!(
            summary
                .reason_codes
                .contains(&"window_context_paused".to_owned())
        );
        assert!(
            summary
                .reason_codes
                .contains(&"window_context_clean_room_replacement".to_owned())
        );
        assert!(
            summary
                .reason_codes
                .contains(&"polluted_context".to_owned())
        );
        assert!(summary.reason_codes.contains(&"stale_context".to_owned()));
        assert!(
            summary
                .reason_codes
                .contains(&"paused_by_main_window".to_owned())
        );
        assert!(
            summary
                .reason_codes
                .contains(&"replacement_window".to_owned())
        );
        assert!(summary.reason_codes.iter().all(|code| {
            !code.contains("old-thread")
                && !code.contains("crates/norion-agent")
                && !code.contains("round-312")
        }));
        assert!(summary.telemetry.iter().any(|line| {
            line == "agent_window_context_reallocation_summary_side_effects_allowed=false"
        }));
        assert!(summary.telemetry.iter().any(|line| {
            line == "agent_window_context_reallocation_summary_assign_clean_room_replacement=true"
        }));
    }

