    #[test]
    fn window_context_reallocation_policy_routes_blocked_windows_to_clean_room_plan_only() {
        let plan = AgentCollaborationPlanner::new().plan(six_windows());
        let requested_task_ids = plan.queue.task_ids();
        let observations = vec![
            AgentWindowContextObservation::new(AgentWindowContextStatus::Polluted)
                .with_evidence_result_id("handoff-summary:r23-agent")
                .with_reason_code(
                    "polluted_context old_thread=019-old path=crates/norion-agent/src/collaboration.rs payload=raw-history",
                ),
            AgentWindowContextObservation::new(AgentWindowContextStatus::Paused)
                .with_reason_code("paused_by_main_window payload=old-window-chat"),
        ];
        let summary =
            AgentWindowContextReallocationSummary::from_observations(&observations, &plan.queue);

        let replacement_plan =
            AgentWindowContextReallocationPolicy::strict_clean_room().plan(&summary);

        assert!(replacement_plan.report_only);
        assert!(replacement_plan.pure_data_only);
        assert!(!replacement_plan.side_effects_allowed);
        assert!(!replacement_plan.starts_thread);
        assert!(!replacement_plan.sends_message);
        assert!(!replacement_plan.reads_old_window_payload);
        assert!(replacement_plan.clean_room_replacement_plan_required);
        assert!(!replacement_plan.clean_room_replacement_available);
        assert!(!replacement_plan.original_window_follow_up_assignment_allowed);
        assert!(replacement_plan.replacement_prompt_ready);
        assert!(replacement_plan.follow_up_tasks_only_in_replacement_prompt);
        assert_eq!(
            replacement_plan.replacement_prompt.task_ids,
            requested_task_ids
        );
        assert_eq!(
            replacement_plan.replacement_prompt.evidence_result_ids,
            vec!["handoff-summary:r23-agent".to_owned()]
        );
        assert_eq!(
            replacement_plan.replacement_prompt.reason_codes,
            vec![
                "window_context_polluted".to_owned(),
                "polluted_context".to_owned(),
                "window_context_paused".to_owned(),
                "paused_by_main_window".to_owned(),
            ]
        );

        let prompt_payload = format!("{:?}", replacement_plan.replacement_prompt);
        assert!(!prompt_payload.contains("019-old"));
        assert!(!prompt_payload.contains("crates/norion-agent"));
        assert!(!prompt_payload.contains("raw-history"));
        assert!(!prompt_payload.contains("old-window-chat"));
        assert!(replacement_plan.telemetry.iter().any(|line| {
            line == "agent_window_context_clean_room_replacement_plan_required=true"
        }));
        assert!(replacement_plan.telemetry.iter().any(|line| {
            line == "agent_window_context_clean_room_replacement_plan_sends_message=false"
        }));
    }

