    #[test]
    fn clean_room_assignment_report_allows_only_sanitized_candidate_prompt_payload() {
        let plan = AgentCollaborationPlanner::new().plan(six_windows());
        let requested_task_ids = plan.queue.task_ids();
        let observations = vec![
            AgentWindowContextObservation::new(AgentWindowContextStatus::Polluted)
                .with_evidence_result_id("handoff-summary:r24-agent")
                .with_reason_code(
                    "polluted_context old_thread=019-old path=crates/norion-agent/src/collaboration.rs payload=raw-history",
                ),
            AgentWindowContextObservation::new(AgentWindowContextStatus::CleanRoomReplacement)
                .with_reason_code("replacement_window=clean-room-r24"),
        ];
        let summary =
            AgentWindowContextReallocationSummary::from_observations(&observations, &plan.queue);
        let replacement_plan =
            AgentWindowContextReallocationPolicy::strict_clean_room().plan(&summary);

        let assignment = AgentWindowContextCleanRoomAssignmentReport::decide(
            AgentWindowContextStatus::CleanRoomReplacement,
            &replacement_plan,
            vec![
                requested_task_ids[0].clone(),
                requested_task_ids[2].clone(),
                requested_task_ids[0].clone(),
            ],
        );

        assert_eq!(
            assignment.decision,
            AgentWindowContextCleanRoomAssignmentDecision::Allowed
        );
        assert!(assignment.decision.is_allowed());
        assert!(assignment.report_only);
        assert!(assignment.pure_data_only);
        assert!(!assignment.side_effects_allowed);
        assert!(!assignment.starts_thread);
        assert!(!assignment.sends_message);
        assert!(!assignment.reads_old_window_payload);
        assert!(assignment.assignment_allowed);
        assert!(!assignment.assignment_blocked);
        assert!(!assignment.assigns_original_window_follow_up);
        assert!(assignment.assigns_clean_room_replacement);
        assert_eq!(
            assignment.accepted_candidate_task_ids,
            vec![requested_task_ids[0].clone(), requested_task_ids[2].clone()]
        );
        assert_eq!(assignment.rejected_candidate_tasks, 0);
        assert_eq!(
            assignment.sanitized_prompt_payload.task_ids,
            assignment.accepted_candidate_task_ids
        );
        assert_eq!(
            assignment.evidence_result_ids,
            vec!["handoff-summary:r24-agent".to_owned()]
        );
        assert!(
            assignment
                .reason_codes
                .contains(&"clean_room_assignment_allowed".to_owned())
        );
        let payload = format!("{:?}", assignment.sanitized_prompt_payload);
        assert!(!payload.contains("019-old"));
        assert!(!payload.contains("crates/norion-agent"));
        assert!(!payload.contains("raw-history"));
        assert!(assignment.telemetry.iter().any(|line| {
            line == "agent_window_context_clean_room_assignment_report_decision=allowed"
        }));
        assert!(assignment.telemetry.iter().any(|line| {
            line == "agent_window_context_clean_room_assignment_report_sends_message=false"
        }));
    }

    #[test]
    fn clean_room_assignment_report_blocks_polluted_stale_paused_original_follow_up() {
        let plan = AgentCollaborationPlanner::new().plan(six_windows());
        let requested_task_ids = plan.queue.task_ids();
        let observations = vec![
            AgentWindowContextObservation::new(AgentWindowContextStatus::Polluted)
                .with_evidence_result_id("handoff-summary:r24-agent")
                .with_reason_code("polluted_context old_thread=019-old payload=raw-history"),
            AgentWindowContextObservation::new(AgentWindowContextStatus::Stale)
                .with_reason_code("stale_context=round-320"),
            AgentWindowContextObservation::new(AgentWindowContextStatus::Paused)
                .with_reason_code("paused_by_main_window payload=old-window-chat"),
            AgentWindowContextObservation::new(AgentWindowContextStatus::CleanRoomReplacement)
                .with_reason_code("replacement_window=clean-room-r24"),
        ];
        let summary =
            AgentWindowContextReallocationSummary::from_observations(&observations, &plan.queue);
        let replacement_plan =
            AgentWindowContextReallocationPolicy::strict_clean_room().plan(&summary);

        for status in [
            AgentWindowContextStatus::Polluted,
            AgentWindowContextStatus::Stale,
            AgentWindowContextStatus::Paused,
        ] {
            let assignment = AgentWindowContextCleanRoomAssignmentReport::decide(
                status,
                &replacement_plan,
                vec![requested_task_ids[0].clone()],
            );

            assert_eq!(
                assignment.decision,
                AgentWindowContextCleanRoomAssignmentDecision::Blocked
            );
            assert!(!assignment.decision.is_allowed());
            assert!(!assignment.assignment_allowed);
            assert!(assignment.assignment_blocked);
            assert!(!assignment.assigns_original_window_follow_up);
            assert!(!assignment.assigns_clean_room_replacement);
            assert!(assignment.sanitized_prompt_payload.task_ids.is_empty());
            assert!(
                assignment
                    .reason_codes
                    .contains(&status.reason_code().to_owned())
            );
            assert!(
                assignment
                    .reason_codes
                    .contains(&"original_window_follow_up_blocked".to_owned())
            );
            assert!(
                assignment
                    .reason_codes
                    .contains(&"clean_room_assignment_target_not_replacement".to_owned())
            );
            let payload = format!("{:?}", assignment.sanitized_prompt_payload);
            assert!(!payload.contains("019-old"));
            assert!(!payload.contains("round-320"));
            assert!(!payload.contains("old-window-chat"));
            assert!(assignment.telemetry.iter().any(|line| {
                line == "agent_window_context_clean_room_assignment_report_decision=blocked"
            }));
        }
    }

    #[test]
    fn clean_room_assignment_report_blocks_candidate_tasks_outside_replacement_plan() {
        let plan = AgentCollaborationPlanner::new().plan(six_windows());
        let requested_task_ids = plan.queue.task_ids();
        let observations = vec![
            AgentWindowContextObservation::new(AgentWindowContextStatus::Polluted)
                .with_evidence_result_id("handoff-summary:r24-agent"),
            AgentWindowContextObservation::new(AgentWindowContextStatus::CleanRoomReplacement),
        ];
        let summary =
            AgentWindowContextReallocationSummary::from_observations(&observations, &plan.queue);
        let replacement_plan =
            AgentWindowContextReallocationPolicy::strict_clean_room().plan(&summary);

        let assignment = AgentWindowContextCleanRoomAssignmentReport::decide(
            AgentWindowContextStatus::CleanRoomReplacement,
            &replacement_plan,
            vec![
                requested_task_ids[0].clone(),
                "old_thread=019-old path=crates/norion-agent/src/collaboration.rs".to_owned(),
            ],
        );

        assert_eq!(
            assignment.decision,
            AgentWindowContextCleanRoomAssignmentDecision::Blocked
        );
        assert!(!assignment.assignment_allowed);
        assert!(assignment.assignment_blocked);
        assert_eq!(
            assignment.accepted_candidate_task_ids,
            vec![requested_task_ids[0].clone()]
        );
        assert_eq!(assignment.rejected_candidate_tasks, 1);
        assert!(assignment.sanitized_prompt_payload.task_ids.is_empty());
        assert!(
            assignment
                .reason_codes
                .contains(&"candidate_clean_room_task_ids_outside_replacement_plan".to_owned())
        );
        let payload = format!("{:?}", assignment.sanitized_prompt_payload);
        assert!(!payload.contains("019-old"));
        assert!(!payload.contains("crates/norion-agent"));
        assert!(assignment.telemetry.iter().any(|line| {
            line == "agent_window_context_clean_room_assignment_report_rejected_candidate_tasks=1"
        }));
    }

    #[test]
    fn clean_room_reassignment_report_replaces_polluted_stale_paused_and_discards_payloads() {
        let workers = vec![
            AgentWindowContextReassignmentWorker::new(
                "old-polluted-window",
                AgentWindowContextReassignmentWorkerStatus::Polluted,
            )
            .with_task_id("agent-r25-a")
            .with_evidence_result_id("evidence:r24-assignment")
            .with_discarded_payload_ref("payload=raw-old-thread-body")
            .with_reason_code("polluted_context old_thread=019-old body=chat transcript"),
            AgentWindowContextReassignmentWorker::new(
                "old-stale-window",
                AgentWindowContextReassignmentWorkerStatus::Stale,
            )
            .with_task_id("agent-r25-b")
            .with_evidence_result_id("evidence:validation-953")
            .with_discarded_payload_ref("thread_body=stale-chat")
            .with_reason_code("stale_context round=322"),
            AgentWindowContextReassignmentWorker::new(
                "old-paused-window",
                AgentWindowContextReassignmentWorkerStatus::Paused,
            )
            .with_task_id("agent-r25-b")
            .with_discarded_payload_ref("paused_payload=operator-transcript")
            .with_reason_code("paused_by_main_window payload=old-window-chat"),
            AgentWindowContextReassignmentWorker::new(
                "old-completed-window",
                AgentWindowContextReassignmentWorkerStatus::Completed,
            )
            .with_task_id("completed-task")
            .with_evidence_result_id("evidence:completed-handoff")
            .with_discarded_payload_ref("completion_payload=old-complete-body"),
        ];

        let report = AgentWindowContextCleanRoomReassignmentReport::from_workers(
            &workers,
            vec![
                "agent-r25-a",
                "agent-r25-b",
                "completed-task",
                "old_thread=019-old path=crates/norion-agent/src/collaboration.rs",
            ],
        );

        assert!(report.report_only);
        assert!(report.pure_data_only);
        assert!(!report.side_effects_allowed);
        assert!(!report.starts_thread);
        assert!(!report.sends_message);
        assert!(!report.reads_old_window_payload);
        assert!(!report.carries_old_thread_body);
        assert!(!report.assigns_original_window_follow_up);
        assert_eq!(report.total_workers, 4);
        assert_eq!(
            report.old_windows_deactivated,
            vec![
                "old-polluted-window".to_owned(),
                "old-stale-window".to_owned(),
                "old-paused-window".to_owned(),
                "old-completed-window".to_owned(),
            ]
        );
        assert_eq!(
            report.clean_room_replacement_worker_ids,
            vec![
                "old-polluted-window".to_owned(),
                "old-stale-window".to_owned(),
                "old-paused-window".to_owned(),
            ]
        );
        assert_eq!(
            report.completed_worker_ids,
            vec!["old-completed-window".to_owned()]
        );
        assert_eq!(
            report.sanitized_candidate_task_ids,
            vec![
                "agent-r25-a".to_owned(),
                "agent-r25-b".to_owned(),
                "completed-task".to_owned(),
            ]
        );
        assert_eq!(report.rejected_candidate_tasks, 1);
        assert_eq!(
            report.clean_room_replacement_task_ids,
            vec!["agent-r25-a".to_owned(), "agent-r25-b".to_owned()]
        );
        assert_eq!(
            report.inherited_evidence_result_ids,
            vec![
                "evidence:r24-assignment".to_owned(),
                "evidence:validation-953".to_owned(),
                "evidence:completed-handoff".to_owned(),
            ]
        );
        assert_eq!(
            report.discarded_payload_refs,
            vec![
                "payload".to_owned(),
                "thread_body".to_owned(),
                "paused_payload".to_owned(),
                "completion_payload".to_owned(),
                "candidate_clean_room_task_payload".to_owned(),
            ]
        );
        assert!(
            report
                .reason_codes
                .contains(&"clean_room_replacement_required".to_owned())
        );
        assert!(
            report
                .reason_codes
                .contains(&"candidate_clean_room_task_payload_discarded".to_owned())
        );
        assert!(
            report
                .reason_codes
                .contains(&"completed_worker_evidence_inherited".to_owned())
        );
        let payload = format!("{report:?}");
        assert!(!payload.contains("019-old"));
        assert!(!payload.contains("raw-old-thread-body"));
        assert!(!payload.contains("chat transcript"));
        assert!(!payload.contains("crates/norion-agent"));
        assert!(!payload.contains("old-window-chat"));
        assert!(report.telemetry.iter().any(|line| {
            line == "agent_window_context_clean_room_reassignment_report_sends_message=false"
        }));
        assert!(report.telemetry.iter().any(|line| {
            line == "agent_window_context_clean_room_reassignment_report_assigns_original_follow_up=false"
        }));
    }

