    #[test]
    fn helper_role_repair_routing_discards_dirty_ids_without_raw_payload() {
        let evidence = vec![
            AgentHelperRoleEvidence::new(
                "summary evidence old_thread=019-old context=raw-context",
                "summary-helper raw-dialog=old-window-chat",
                AgentHelperRole::Summary,
            )
            .with_helper_stage_contract_complete(false)
            .with_reason_code("paused_by_main_window body=old-window-chat raw_context=dialog")
            .with_discarded_payload_ref("payload=raw-old-thread-body old_thread=019-old"),
        ];

        let report = AgentHelperRoleRepairRoutingReport::from_evidence_with_task_prefix(
            &evidence,
            "unsafe prefix payload=old-window-chat raw-dialog=history",
        );

        assert_eq!(
            report.repair_task_ids(),
            vec!["helper-role-repair-summary-0".to_owned()]
        );
        assert!(report.inherited_evidence_result_ids.is_empty());
        assert_eq!(
            report.discarded_payload_refs,
            vec![
                "helper_role_evidence_id".to_owned(),
                "helper_role_helper_id".to_owned(),
                "payload".to_owned(),
            ]
        );
        assert!(
            report
                .reason_codes
                .contains(&"helper_role_repair_task_prefix_sanitized".to_owned())
        );
        assert!(
            report.repair_tasks[0]
                .objective
                .contains("evidence_id=sanitized-evidence")
        );
        assert!(
            report.repair_tasks[0]
                .objective
                .contains("helper_id=sanitized-helper")
        );
        assert_eq!(report.repair_tasks[0].role, AgentRole::Aggregator);
        assert_eq!(report.repair_tasks[0].lane, "summary-repair");

        let payload = format!("{report:?}");
        assert!(!payload.contains("019-old"));
        assert!(!payload.contains("raw-context"));
        assert!(!payload.contains("raw-dialog"));
        assert!(!payload.contains("raw-history"));
        assert!(!payload.contains("old-window-chat"));
        assert!(!payload.contains("raw-old-thread-body"));
    }

    #[test]
    fn helper_role_repair_routing_observes_complete_helpers_without_dispatch() {
        let evidence = vec![
            AgentHelperRoleEvidence::new(
                "summary-evidence-clean",
                "summary-helper-clean",
                AgentHelperRole::Summary,
            ),
            AgentHelperRoleEvidence::new(
                "test-gate-evidence-clean",
                "test-gate-helper-clean",
                AgentHelperRole::TestGate,
            ),
        ];

        let report = AgentHelperRoleRepairRoutingReport::from_evidence(&evidence);

        assert_eq!(
            report.decision,
            AgentHelperRoleRepairRoutingDecision::Observe
        );
        assert!(!report.requires_repair_first);
        assert!(report.repair_tasks.is_empty());
        assert!(report.routed_helper_roles.is_empty());
        assert!(report.inherited_evidence_result_ids.is_empty());
        assert!(!report.side_effect_dispatch_allowed);
        assert!(!report.allows_side_effect_dispatch());
        assert_eq!(report.complete_helper_evidence, 2);
        assert_eq!(report.incomplete_helper_evidence, 0);
        assert!(
            report
                .reason_codes
                .contains(&"summary_helper_evidence_complete".to_owned())
        );
        assert!(
            report
                .reason_codes
                .contains(&"test_gate_helper_evidence_complete".to_owned())
        );
        assert!(
            report
                .reason_codes
                .contains(&"summary_completed_evidence_not_promoted".to_owned())
        );
        assert!(
            report
                .reason_codes
                .contains(&"test_gate_completed_evidence_not_promoted".to_owned())
        );
        assert!(report.telemetry.iter().any(|line| {
            line == "agent_helper_role_repair_routing_report_side_effect_dispatch_allowed=false"
        }));
    }

    #[test]
    fn self_improve_proposal_promotion_gate_observes_when_clean_room_assignment_is_not_ready() {
        let candidate = AgentTask::new(
            "r26-observe-only",
            AgentRole::Tester,
            "wait for clean room assignment evidence",
            AgentBudget::new(8, 1, 1),
        );
        let assignment_state = AgentSelfImproveProposalCleanRoomAssignmentState {
            assignment_allowed: false,
            side_effects_allowed: false,
            starts_thread: false,
            sends_message: false,
            reads_old_window_payload: false,
            assigns_original_window_follow_up: false,
            evidence_result_ids: Vec::new(),
            reason_codes: vec!["clean_room_assignment_blocked".to_owned()],
        };
        let artifact = AgentSelfImproveProposalArtifact::new("proposal:r26-observe")
            .with_evidence_result_id("evidence:proposal-artifact");
        let validation = vec![AgentSelfImproveProposalValidationEvidence::passed(
            "evidence:validation-passed",
        )];

        let gate = AgentSelfImproveProposalPromotionGate::decide(
            &artifact,
            &candidate,
            &validation,
            &assignment_state,
        );

        assert_eq!(
            gate.decision,
            AgentSelfImproveProposalPromotionDecision::Observe
        );
        assert!(!gate.can_promote_to_task_queue);
        assert_eq!(gate.required_role, AgentRole::Reflector);
        assert!(gate.candidate_queue.is_empty());
        assert!(!gate.side_effect_dispatch_allowed);
        assert!(
            gate.reason_codes
                .contains(&"proposal_observe_only".to_owned())
        );
    }

    #[test]
    fn collaboration_ownership_preflight_gate_schedules_ownership_repair_before_preflight_repair() {
        let dirty_plan = AgentCollaborationPlanner::new().plan(vec![AgentWindowSpec::new(
            "window-1",
            AgentRole::Planner,
            "unbudgeted planning lane",
            AgentBudget::zero(),
        )]);
        let dirty_summary =
            dirty_plan.summary(AgentCollaborationPlanGatePolicy::expected_windows(1));
        let plan = AgentCollaborationPlanner::new().plan(six_windows());
        let preflight = AgentCollaborationDispatchPreflight::new().record_and_gate(
            &plan,
            AgentCollaborationPlanSummaryHistory::from_summaries(vec![dirty_summary]),
            AgentCollaborationPlanGatePolicy::six_window_strict(),
            AgentCollaborationPlanHealthPolicy::default(),
            BudgetLedgerSummaryHistory::new(),
            BudgetLedgerHealthPolicy::default(),
            RecursiveAgentScheduleSummaryHistory::new(),
            RecursiveAgentScheduleHealthPolicy::default(),
            3,
        );
        let ownership_review = AgentWindowOwnershipReviewer::new().review(vec![
            AgentWindowOwnership::new("window-1")
                .owns_path("crates/norion-agent/src")
                .changed_path("crates/norion-agent/src/collaboration.rs"),
            AgentWindowOwnership::new("window-2")
                .owns_path("docs/architecture")
                .changed_path("crates/norion-agent/src/collaboration.rs"),
        ]);
        let ownership_record = AgentWindowOwnershipReviewSummaryHistoryRecorder::new()
            .record_review_with_health(
                AgentWindowOwnershipReviewSummaryHistory::new(),
                &ownership_review,
                AgentWindowOwnershipReviewHealthPolicy::default(),
            );

        let gate =
            AgentCollaborationOwnershipPreflightGate::new().gate(preflight, ownership_record);
        let mut repair_queue = gate.repair_queue.clone();
        let first_wave = repair_queue.drain_ready(&BTreeSet::new());
        let completed_ownership = first_wave
            .iter()
            .map(|task| task.id.clone())
            .collect::<BTreeSet<_>>();
        let second_wave = repair_queue.drain_ready(&completed_ownership);

        assert_eq!(
            first_wave
                .iter()
                .map(|task| task.id.as_str())
                .collect::<Vec<_>>(),
            vec![
                "collaboration-ownership-repair-0",
                "collaboration-ownership-repair-1"
            ]
        );
        assert_eq!(
            second_wave
                .iter()
                .map(|task| task.id.as_str())
                .collect::<Vec<_>>(),
            vec!["collaboration-plan-repair-0", "collaboration-plan-repair-1"]
        );
        assert!(repair_queue.is_empty());
        assert!(gate.requires_repair_first);
    }

