    #[test]
    fn collaboration_review_allows_clean_memory_and_adaptive_state_handoff() {
        let window_plan = AgentCollaborationPlanner::new().plan(six_windows());
        let completed = BTreeSet::new();
        let dispatch = AgentCycleOrchestrator::new().plan_next_wave(
            window_plan.queue,
            &completed,
            window_plan.budget_ledger,
            &BudgetPolicy::strict(),
            3,
        );
        let tasks_by_id = dispatch
            .assigned_tasks
            .iter()
            .map(|task| (task.id.clone(), task.clone()))
            .collect::<std::collections::BTreeMap<_, _>>();
        let results = ["window-1", "window-2", "window-3"]
            .into_iter()
            .map(|task_id| {
                let task = tasks_by_id.get(task_id).unwrap();
                AgentResult::accepted(
                    task,
                    format!("{task_id} complete"),
                    vec![AgentMessage::new(
                        format!("{task_id}-status"),
                        task.role.clone(),
                        AgentMessageKind::Status,
                        "collaboration",
                        format!("{task_id} complete"),
                    )],
                    task.required_budget,
                )
            })
            .collect::<Vec<_>>();
        let mut reflection = ReflectionLoop::new();
        reflection
            .submit(ReflectionStage::Draft, "observed clean collaboration wave")
            .unwrap();
        reflection
            .submit(ReflectionStage::Critique, "confirm budgets stay isolated")
            .unwrap();
        reflection
            .submit(ReflectionStage::Revision, "keep windows budget isolated")
            .unwrap();
        reflection
            .submit(
                ReflectionStage::MemoryNote,
                "six-window collaboration completed a clean first wave",
            )
            .unwrap();

        let report = AgentCycleOrchestrator::new().close_wave(
            dispatch.dispatch,
            results,
            AgentCycleEvidence {
                quality: 0.94,
                validation_passed: true,
                runtime_response_ok: true,
                reflection: Some(reflection),
                ..AgentCycleEvidence::default()
            },
        );
        let review = AgentCollaborationReview::from_report(&report);

        assert!(review.can_submit_memory);
        assert!(review.can_write_adaptive_state);
        assert!(review.blocked_reasons.is_empty());
        assert_eq!(review.summary.assigned_tasks, 3);
        assert_eq!(review.summary.unresolved_conflicts, 0);
        assert_eq!(review.handoff.memory_notes.len(), 1);
        assert!(
            review
                .telemetry
                .iter()
                .any(|line| line == "agent_collaboration_review_memory_allowed=true")
        );
    }

    #[test]
    fn collaboration_review_blocks_memory_and_adaptive_state_on_conflict() {
        let task = AgentWindowSpec::new(
            "window-1",
            AgentRole::Planner,
            "surface risk",
            AgentBudget::new(10, 1, 1),
        )
        .task();
        let mut planner = DispatchPlanner::new(
            BudgetLedger::new().with_budget(AgentRole::Planner, AgentBudget::new(10, 1, 1)),
        );
        let dispatch = planner.plan_with_policy(vec![task.clone()], &BudgetPolicy::strict());
        let result = AgentResult::accepted(
            &task,
            "conflicting gate",
            vec![
                AgentMessage::new(
                    "gate-allow",
                    AgentRole::Planner,
                    AgentMessageKind::Gate,
                    "memory",
                    "allow memory promotion",
                ),
                AgentMessage::new(
                    "gate-block",
                    AgentRole::Reviewer,
                    AgentMessageKind::Gate,
                    "memory",
                    "block memory promotion",
                ),
            ],
            task.required_budget,
        );
        let report = AgentCycleOrchestrator::new().close_wave(
            dispatch,
            vec![result],
            AgentCycleEvidence {
                quality: 0.90,
                validation_passed: true,
                runtime_response_ok: true,
                ..AgentCycleEvidence::default()
            },
        );

        let review = AgentCollaborationReview::from_report(&report);

        assert!(!review.can_submit_memory);
        assert!(!review.can_write_adaptive_state);
        assert!(review.summary.unresolved_conflicts > 0);
        assert!(
            review
                .blocked_reasons
                .iter()
                .any(|reason| reason.starts_with("unresolved_conflicts="))
        );
        assert!(
            review
                .blocked_reasons
                .iter()
                .any(|reason| reason.starts_with("memory_gate=blocked by"))
        );
    }

    #[test]
    fn collaboration_review_inherits_closed_run_ledger_admission_from_cycle_report() {
        let task = AgentWindowSpec::new(
            "window-1",
            AgentRole::Reviewer,
            "review oversized request",
            AgentBudget::new(8, 1, 1),
        )
        .task();
        let mut planner = DispatchPlanner::new(
            BudgetLedger::new().with_budget(AgentRole::Reviewer, AgentBudget::new(4, 1, 1)),
        );
        let dispatch = planner.plan_with_policy(vec![task], &BudgetPolicy::strict());
        let report = AgentCycleOrchestrator::new().close_wave(
            dispatch,
            Vec::new(),
            AgentCycleEvidence {
                quality: 0.95,
                validation_passed: true,
                runtime_response_ok: true,
                ..AgentCycleEvidence::default()
            },
        );

        let review = AgentCollaborationReview::from_report(&report);

        assert!(report.run_ledger_admission.requires_repair_first);
        assert_eq!(
            review.adapter_boundary_summary.status,
            crate::adapter::AgentAdapterBoundaryStatus::Repair
        );
        assert!(review.adapter_boundary_summary.requires_repair_first);
        assert!(!review.can_submit_memory);
        assert!(!review.can_write_adaptive_state);
        assert!(
            review
                .adapter_boundary_blocked_reasons
                .iter()
                .any(|reason| reason.starts_with(
                    "norion_core:run_ledger_admission:dispatch_rejection task=window-1 role=reviewer"
                ))
        );
        assert!(
            review
                .blocked_reasons
                .iter()
                .any(|reason| reason.starts_with(
                    "norion_core:run_ledger_admission:dispatch_rejection task=window-1 role=reviewer"
                ))
        );
        assert!(
            review.telemetry.iter().any(|line| {
                line == "agent_collaboration_review_adapter_boundary_status=Repair"
            })
        );
    }

