    #[test]
    fn collaboration_business_loop_repairs_before_promotion_on_conflict_trend() {
        let ledger = clean_ledger();
        let mut collaboration_history = AgentCollaborationReviewHistory::new();
        collaboration_history.push(synthetic_review(
            false,
            false,
            1,
            0,
            vec!["unresolved_conflicts=1".to_owned()],
        ));

        let plan = AgentCollaborationBusinessLoopPlanner::new().plan(
            &ledger,
            AgentCycleLedgerPolicy::default(),
            &collaboration_history,
            AgentCollaborationHealthPolicy::default(),
        );

        assert_eq!(
            plan.business_plan.status(),
            AgentCycleLedgerAdmissionStatus::Promote
        );
        assert_eq!(
            plan.effective_status,
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert_eq!(
            plan.collaboration_health.status,
            AgentClosedLoopExecutionHealthStatus::Repair
        );
        assert!(!plan.can_promote_adaptive_state());
        assert!(plan.requires_repair_first());
        assert!(!plan.allows_service_advance());
        assert!(plan.adaptive_state_candidate.is_none());
        assert!(!plan.repair_tasks.is_empty());
        assert_eq!(plan.repair_tasks[0].lane, "collaboration-repair");
        assert!(plan.telemetry.iter().any(|line| {
            line == "agent_collaboration_business_loop_plan_effective_status=repair"
        }));
        let summary = plan.summary();

        assert_eq!(
            summary.business_status,
            AgentCycleLedgerAdmissionStatus::Promote
        );
        assert_eq!(
            summary.collaboration_health_status,
            AgentClosedLoopExecutionHealthStatus::Repair
        );
        assert_eq!(
            summary.effective_status,
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert!(!summary.can_promote_adaptive_state);
        assert!(summary.requires_repair_first);
        assert!(!summary.has_adaptive_state_candidate);
        assert_eq!(summary.repair_tasks, plan.repair_tasks.len());
        let effective_business_plan = plan.effective_business_plan();
        let service_plan = AgentServiceCommandPlanner::new().plan(&effective_business_plan);

        assert_eq!(
            effective_business_plan.status(),
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert_eq!(
            effective_business_plan.next_queue.task_ids(),
            plan.repair_tasks
                .iter()
                .map(|task| task.id.clone())
                .collect::<Vec<_>>()
        );
        assert!(!service_plan.requires_adaptive_state_write());
        assert!(service_plan.repair_mode_requested());
        assert!(service_plan.command_kinds().contains(&"enqueue_tasks"));
        let receipts = service_plan
            .commands
            .iter()
            .map(|command| AgentServiceCommandReceipt::applied(command, "ok"))
            .collect::<Vec<_>>();
        let execution_report = plan.close_service_execution("run-collab-repair", receipts);

        assert!(execution_report.is_clean());
        assert!(!execution_report.can_promote_adaptive_state());
        assert!(execution_report.next_queue().len() >= plan.repair_tasks.len());
        assert!(
            execution_report
                .command_kinds()
                .contains(&"open_repair_mode")
        );
        assert!(execution_report.command_kinds().contains(&"enqueue_tasks"));
        let execution_summary = execution_report.summary();

        assert_eq!(
            execution_summary.effective_status,
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert_eq!(
            execution_summary.collaboration_health_status,
            AgentClosedLoopExecutionHealthStatus::Repair
        );
        assert!(execution_summary.clean);
        assert!(!execution_summary.requires_adaptive_state_write);
        assert!(!execution_summary.can_promote_adaptive_state);
        assert!(execution_summary.repair_mode_requested);
        assert!(
            execution_summary
                .command_kinds
                .contains(&"open_repair_mode".to_owned())
        );
        assert!(
            execution_summary
                .command_kinds
                .contains(&"enqueue_tasks".to_owned())
        );
    }

