    #[test]
    fn collaboration_self_evolution_repairs_dirty_service_history_before_promotion() {
        let collaboration_plan = clean_collaboration_business_loop_plan();
        let service_history = dirty_service_execution_history(&collaboration_plan);

        let plan = AgentCollaborationSelfEvolutionPlanner::new().plan(
            &collaboration_plan,
            &service_history,
            AgentCollaborationServiceExecutionHealthPolicy::default(),
        );

        assert_eq!(
            collaboration_plan.effective_status,
            AgentCycleLedgerAdmissionStatus::Promote
        );
        assert_eq!(plan.final_status, AgentCycleLedgerAdmissionStatus::Repair);
        assert_eq!(
            plan.service_execution_health.status,
            AgentClosedLoopExecutionHealthStatus::Repair
        );
        assert!(!plan.can_promote_adaptive_state());
        assert!(plan.requires_repair_first());
        assert!(plan.adaptive_state_candidate.is_none());
        assert!(!plan.repair_tasks.is_empty());
        assert_eq!(
            plan.repair_tasks[0].lane,
            "collaboration-service-execution-repair"
        );
        assert_eq!(
            plan.next_queue.task_ids(),
            plan.repair_tasks
                .iter()
                .map(|task| task.id.clone())
                .collect::<Vec<_>>()
        );
        assert!(
            plan.blocked_reasons
                .iter()
                .any(|reason| reason == "service_execution_health=repair")
        );
        let effective_business_plan = plan.effective_business_plan();

        assert_eq!(
            effective_business_plan.status(),
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert!(effective_business_plan.adaptive_state_candidate.is_none());
        assert_eq!(
            effective_business_plan.next_queue.task_ids(),
            plan.next_queue.task_ids()
        );
    }

    #[test]
