    #[test]
    fn collaboration_self_evolution_closer_merges_current_service_and_trend_repairs() {
        let collaboration_plan = clean_collaboration_business_loop_plan();
        let effective_business_plan = collaboration_plan.effective_business_plan();
        let command_plan = AgentServiceCommandPlanner::new().plan(&effective_business_plan);
        let receipts = vec![AgentServiceCommandReceipt::failed(
            &command_plan.commands[0],
            "adaptive state writer offline",
        )];

        let record = AgentCollaborationSelfEvolutionCloser::new().close(
            "run-collab-self-evolution-close-dirty",
            &collaboration_plan,
            AgentCollaborationServiceExecutionHistory::new(),
            AgentCollaborationServiceExecutionHealthPolicy::default(),
            receipts,
        );
        let next_tasks = record.next_queue().tasks();
        let lanes = next_tasks
            .iter()
            .map(|task| task.lane.as_str())
            .collect::<Vec<_>>();

        assert!(!record.service_execution_report.is_clean());
        assert_eq!(
            record.self_evolution_plan.final_status,
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert_eq!(
            record.self_evolution_plan.service_execution_health.status,
            AgentClosedLoopExecutionHealthStatus::Repair
        );
        assert!(!record.can_promote_adaptive_state());
        assert!(record.requires_repair_first());
        assert!(!record.allows_service_advance());
        assert!(!record.service_feedback_repair_tasks.is_empty());
        assert!(
            lanes
                .iter()
                .any(|lane| *lane == "collaboration-service-execution-repair")
        );
        assert!(lanes.iter().any(|lane| *lane == "service-feedback"));
        assert!(
            record
                .self_evolution_plan
                .blocked_reasons
                .iter()
                .any(|reason| reason.starts_with("current_service_execution="))
        );
        let effective_business_plan = record.effective_business_plan();

        assert_eq!(
            effective_business_plan.status(),
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert_eq!(
            effective_business_plan.next_queue.task_ids(),
            record.next_queue().task_ids()
        );
        let summary = record.summary();

        assert!(!summary.service_clean);
        assert_eq!(
            summary.service_execution_health_status,
            AgentClosedLoopExecutionHealthStatus::Repair
        );
        assert_eq!(
            summary.final_status,
            AgentCycleLedgerAdmissionStatus::Repair
        );
        assert!(summary.requires_repair_first);
        assert!(summary.service_feedback_repair_tasks > 0);
        assert!(summary.self_evolution_repair_tasks > 0);
    }

