    #[allow(clippy::too_many_arguments)]
    fn close_continuation_control_plan(
        requested_mode: AgentClosedLoopNextTurnMode,
        effective_mode: AgentClosedLoopNextTurnMode,
        health_status: AgentClosedLoopExecutionHealthStatus,
        can_dispatch_service_commands: bool,
        can_promote_memory_note: bool,
        can_admit_adaptive_evolution: bool,
        requires_repair_first: bool,
        reasons: Vec<String>,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlPlan {
        let health = AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationHealth {
            status: health_status,
            reasons: Vec::new(),
        };
        let telemetry =
            collaboration_self_evolution_service_eval_reflection_close_continuation_control_telemetry(
                requested_mode,
                effective_mode,
                &health,
                can_dispatch_service_commands,
                can_promote_memory_note,
                can_admit_adaptive_evolution,
                requires_repair_first,
                reasons.len(),
            );

        AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationControlPlan {
            requested_mode,
            effective_mode,
            health,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            service_execution_command_reason_count: 0,
            service_execution_memory_promotion_command_reason_count: 0,
            service_execution_memory_promotion_command_reason_closes: 0,
            service_execution_rust_validation_command_count: 0,
            service_execution_rust_validation_command_closes: 0,
            reasons,
            telemetry,
        }
    }

    fn close_continuation_summary(
        mode: AgentClosedLoopNextTurnMode,
        can_dispatch_service_commands: bool,
        can_promote_memory_note: bool,
        can_admit_adaptive_evolution: bool,
        requires_repair_first: bool,
        blocked_reasons: usize,
    ) -> AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationSummary {
        AgentCollaborationSelfEvolutionServiceEvalReflectionCloseContinuationSummary {
            close_and_admit_health_status: if requires_repair_first {
                AgentClosedLoopExecutionHealthStatus::Repair
            } else {
                AgentClosedLoopExecutionHealthStatus::Stable
            },
            packet_health_status: if requires_repair_first {
                AgentClosedLoopExecutionHealthStatus::Repair
            } else {
                AgentClosedLoopExecutionHealthStatus::Stable
            },
            reflection_health_status: if requires_repair_first {
                AgentClosedLoopExecutionHealthStatus::Repair
            } else {
                AgentClosedLoopExecutionHealthStatus::Stable
            },
            mode,
            can_dispatch_service_commands,
            can_promote_memory_note,
            can_admit_adaptive_evolution,
            requires_repair_first,
            close_and_admit_records: 1,
            packet_records: 1,
            reflection_records: 1,
            blocked_reasons,
            service_execution_command_reason_count: 0,
            service_execution_memory_promotion_command_reason_count: 0,
            service_execution_memory_promotion_command_reason_closes: 0,
            service_execution_rust_validation_command_count: 0,
            service_execution_rust_validation_command_closes: 0,
            telemetry: Vec::new(),
        }
    }

    fn synthetic_review(
        can_submit_memory: bool,
        can_write_adaptive_state: bool,
        unresolved_conflicts: usize,
        budget_overspends: usize,
        blocked_reasons: Vec<String>,
    ) -> AgentCollaborationReview {
        let adapter_boundary_status = if blocked_reasons.is_empty() {
            crate::adapter::AgentAdapterBoundaryStatus::Stable
        } else {
            crate::adapter::AgentAdapterBoundaryStatus::Repair
        };
        AgentCollaborationReview {
            summary: AgentCycleSummary {
                assigned_tasks: 1,
                rejected_tasks: 0,
                unique_messages: 1,
                duplicate_groups: 0,
                unresolved_conflicts,
                blocked_side_effects: blocked_reasons.len(),
                budget_overspends,
                execution_failures: 0,
                reward_total: if blocked_reasons.is_empty() {
                    0.92
                } else {
                    0.20
                },
                reward_action: if blocked_reasons.is_empty() {
                    RewardAction::Reinforce
                } else {
                    RewardAction::Penalize
                },
                evolution_signals: if blocked_reasons.is_empty() { 1 } else { 0 },
                follow_up_tasks: if blocked_reasons.is_empty() { 1 } else { 2 },
                memory_promotions: if can_submit_memory { 1 } else { 0 },
                tool_build_reports: 0,
                tool_build_missing_requests: 0,
                tool_build_unexpected_receipts: 0,
                tool_build_duplicate_receipts: 0,
                tool_build_held_receipts: 0,
                tool_build_rejected_receipts: 0,
            },
            handoff: AgentCycleHandoff {
                memory_notes: Vec::new(),
                follow_up_tasks: Vec::new(),
                blocked_reasons: blocked_reasons.clone(),
            },
            adapter_boundary_summary: AgentAdapterBoundarySummary {
                status: adapter_boundary_status,
                owners: 1,
                stable_owners: usize::from(blocked_reasons.is_empty()),
                watch_owners: 0,
                repair_owners: usize::from(!blocked_reasons.is_empty()),
                next_queue_tasks: 0,
                blocked_reasons: blocked_reasons.len(),
                can_dispatch_core: blocked_reasons.is_empty(),
                can_submit_memory_note: can_submit_memory,
                can_promote_adaptive_state: can_write_adaptive_state,
                can_execute_service_commands: blocked_reasons.is_empty(),
                requires_repair_first: !blocked_reasons.is_empty(),
                service_execution_command_reason_count: 0,
                service_execution_memory_promotion_command_reason_count: 0,
                service_execution_memory_promotion_command_reason_closes: 0,
                service_execution_tool_build_command_reason_count: 0,
                telemetry: Vec::new(),
            },
            adapter_boundary_blocked_reasons: blocked_reasons.clone(),
            memory_gate: Some(if can_submit_memory {
                SideEffectGate::allow(SideEffectKind::MemoryNote, "clean")
            } else {
                SideEffectGate::block(SideEffectKind::MemoryNote, "blocked by review")
            }),
            adaptive_state_gate: Some(if can_write_adaptive_state {
                SideEffectGate::allow(SideEffectKind::AdaptiveStateWrite, "clean")
            } else {
                SideEffectGate::block(SideEffectKind::AdaptiveStateWrite, "blocked by review")
            }),
            can_submit_memory,
            can_write_adaptive_state,
            blocked_reasons,
            telemetry: Vec::new(),
        }
    }

    fn clean_collaboration_business_loop_plan() -> AgentCollaborationBusinessLoopPlan {
        let ledger = clean_ledger();
        let mut collaboration_history = AgentCollaborationReviewHistory::new();
        collaboration_history.push(synthetic_review(true, true, 0, 0, Vec::new()));

        AgentCollaborationBusinessLoopPlanner::new().plan(
            &ledger,
            AgentCycleLedgerPolicy::default(),
            &collaboration_history,
            AgentCollaborationHealthPolicy::default(),
        )
    }

    fn clean_service_execution_history(
        collaboration_plan: &AgentCollaborationBusinessLoopPlan,
    ) -> AgentCollaborationServiceExecutionHistory {
        let effective_business_plan = collaboration_plan.effective_business_plan();
        let command_plan = AgentServiceCommandPlanner::new().plan(&effective_business_plan);
        let receipts = command_plan
            .commands
            .iter()
            .map(|command| AgentServiceCommandReceipt::applied(command, "ok"))
            .collect::<Vec<_>>();
        let report =
            collaboration_plan.close_service_execution("run-collab-self-evolution-clean", receipts);

        AgentCollaborationServiceExecutionHistoryRecorder::new()
            .record_report(
                AgentCollaborationServiceExecutionHistory::new(),
                &report,
                AgentCollaborationServiceExecutionHealthPolicy::default(),
            )
            .history
    }

    fn self_evolution_control_queue() -> AgentTaskQueue {
        AgentTaskQueue::from_tasks(vec![
            AgentTask::new(
                "self-evolution-next",
                AgentRole::Planner,
                "continue self-evolution loop",
                AgentBudget::new(8, 1, 1),
            )
            .with_lane("self-evolution")
            .with_priority(5),
        ])
    }

    fn clean_self_evolution_close_record() -> AgentCollaborationSelfEvolutionCloseRecord {
        let collaboration_plan = clean_collaboration_business_loop_plan();
        let effective_business_plan = collaboration_plan.effective_business_plan();
        let command_plan = AgentServiceCommandPlanner::new().plan(&effective_business_plan);
        let receipts = command_plan
            .commands
            .iter()
            .map(|command| AgentServiceCommandReceipt::applied(command, "ok"))
            .collect::<Vec<_>>();

        AgentCollaborationSelfEvolutionCloser::new().close(
            "run-collab-self-evolution-history-clean",
            &collaboration_plan,
            AgentCollaborationServiceExecutionHistory::new(),
            AgentCollaborationServiceExecutionHealthPolicy::default(),
            receipts,
        )
    }

    fn dirty_self_evolution_close_record() -> AgentCollaborationSelfEvolutionCloseRecord {
        let collaboration_plan = clean_collaboration_business_loop_plan();
        let effective_business_plan = collaboration_plan.effective_business_plan();
        let command_plan = AgentServiceCommandPlanner::new().plan(&effective_business_plan);
        let receipts = vec![AgentServiceCommandReceipt::failed(
            &command_plan.commands[0],
            "adaptive state writer offline",
        )];

        AgentCollaborationSelfEvolutionCloser::new().close(
            "run-collab-self-evolution-history-dirty",
            &collaboration_plan,
            AgentCollaborationServiceExecutionHistory::new(),
            AgentCollaborationServiceExecutionHealthPolicy::default(),
            receipts,
        )
    }

    fn dirty_service_execution_history(
        collaboration_plan: &AgentCollaborationBusinessLoopPlan,
    ) -> AgentCollaborationServiceExecutionHistory {
        let effective_business_plan = collaboration_plan.effective_business_plan();
        let command_plan = AgentServiceCommandPlanner::new().plan(&effective_business_plan);
        let receipts = vec![AgentServiceCommandReceipt::failed(
            &command_plan.commands[0],
            "adaptive state writer offline",
        )];
        let report =
            collaboration_plan.close_service_execution("run-collab-self-evolution-dirty", receipts);

        AgentCollaborationServiceExecutionHistoryRecorder::new()
            .record_report(
                AgentCollaborationServiceExecutionHistory::new(),
                &report,
                AgentCollaborationServiceExecutionHealthPolicy::default(),
            )
            .history
    }

    fn clean_close_and_admit_monitor_record_for_tests()
    -> AgentCollaborationSelfEvolutionCloseAndAdmitMonitorRecord {
        let collaboration_plan = clean_collaboration_business_loop_plan();
        let command_plan =
            AgentServiceCommandPlanner::new().plan(&collaboration_plan.effective_business_plan());
        let receipts = command_plan
            .commands
            .iter()
            .map(|command| AgentServiceCommandReceipt::applied(command, "ok"))
            .collect::<Vec<_>>();

        AgentCollaborationSelfEvolutionCloseAndAdmitMonitor::new().close_record_and_plan(
            "run-collab-clean-monitor-helper",
            &collaboration_plan,
            AgentCollaborationServiceExecutionHistory::new(),
            AgentCollaborationServiceExecutionHealthPolicy::default(),
            receipts,
            AgentCollaborationSelfEvolutionCloseHistory::new(),
            AgentCollaborationSelfEvolutionCloseHealthPolicy::default(),
            AgentCollaborationSelfEvolutionControlHistory::new(),
            AgentCollaborationSelfEvolutionControlHealthPolicy::default(),
            AgentCollaborationSelfEvolutionCloseAndAdmitHistory::new(),
            AgentCollaborationSelfEvolutionCloseAndAdmitHealthPolicy::default(),
        )
    }

    fn clean_reflection_packet_monitor_record_for_tests()
    -> AgentCollaborationSelfEvolutionServiceEvalPacketMonitorRecord {
        let summary = AgentCollaborationSelfEvolutionServiceEvalPacketSummary {
            effective_mode: AgentClosedLoopNextTurnMode::Continue,
            close_and_admit_health_status: AgentClosedLoopExecutionHealthStatus::Stable,
            command_count: 1,
            command_kinds: vec!["emit_telemetry".to_owned()],
            can_dispatch_service_commands: true,
            requires_adaptive_state_write: false,
            can_write_adaptive_state: false,
            repair_mode_requested: false,
            requires_repair_first: false,
            repair_first_ready: true,
            blocked_reasons: 0,
            service_execution_command_reason_count: 0,
            service_execution_memory_promotion_command_reason_count: 0,
            service_execution_memory_promotion_command_reason_closes: 0,
            service_execution_rust_validation_command_count: 0,
            service_execution_rust_validation_command_closes: 0,
            telemetry: Vec::new(),
        };
        let history_record = AgentCollaborationSelfEvolutionServiceEvalPacketHistoryRecorder::new()
            .record(
                AgentCollaborationSelfEvolutionServiceEvalPacketHistory::new(),
                summary.clone(),
                AgentCollaborationSelfEvolutionServiceEvalPacketHealthPolicy::default(),
            );
        let packet = AgentCollaborationSelfEvolutionServiceEvalPacket {
            monitor_record: clean_close_and_admit_monitor_record_for_tests(),
            expected_command_plan: AgentServiceCommandPlan {
                commands: Vec::new(),
            },
            command_count: summary.command_count,
            command_kinds: summary.command_kinds,
            can_dispatch_service_commands: summary.can_dispatch_service_commands,
            requires_adaptive_state_write: summary.requires_adaptive_state_write,
            can_write_adaptive_state: summary.can_write_adaptive_state,
            repair_mode_requested: summary.repair_mode_requested,
            requires_repair_first: summary.requires_repair_first,
            blocked_reasons: Vec::new(),
            telemetry: Vec::new(),
        };

        AgentCollaborationSelfEvolutionServiceEvalPacketMonitorRecord {
            packet,
            history_record,
            telemetry: Vec::new(),
        }
    }

    fn clean_ledger() -> AgentCycleLedger {
        AgentCycleLedger::from_entries(vec![
            accepted_entry("run-1", 0.86),
            accepted_entry("run-2", 0.88),
        ])
    }

    fn accepted_entry(run_id: &str, reward_total: f32) -> AgentCycleLedgerEntry {
        AgentCycleLedgerEntry::new(
            AgentCycleLedgerRecord::new(
                run_id,
                synthetic_summary(reward_total),
                AgentReportEvidence::new(true, true)
                    .with_validation_ref("eval:validation:pass")
                    .with_runtime_ref("service:runtime:ok"),
                Some(MemorySubmissionReport {
                    submitted: vec![MemoryNote::new("agent_cycle", "remember clean loop")],
                    failures: Vec::new(),
                    blocked_reasons: Vec::new(),
                    note_quality: None,
                }),
            ),
            AgentReportGateDecision {
                accepted: true,
                reasons: Vec::new(),
                follow_up_tasks: Vec::new(),
            },
            AgentLoopbackPlan {
                promote_adaptive_state: true,
                enqueue_tasks: Vec::new(),
                blocked_reasons: Vec::new(),
            },
        )
    }

    fn synthetic_summary(reward_total: f32) -> AgentCycleSummary {
        AgentCycleSummary {
            assigned_tasks: 1,
            rejected_tasks: 0,
            unique_messages: 1,
            duplicate_groups: 0,
            unresolved_conflicts: 0,
            blocked_side_effects: 0,
            budget_overspends: 0,
            execution_failures: 0,
            reward_total,
            reward_action: RewardAction::Reinforce,
            evolution_signals: 1,
            follow_up_tasks: 0,
            memory_promotions: 1,
            tool_build_reports: 0,
            tool_build_missing_requests: 0,
            tool_build_unexpected_receipts: 0,
            tool_build_duplicate_receipts: 0,
            tool_build_held_receipts: 0,
            tool_build_rejected_receipts: 0,
        }
    }
